        app.Decommission(Clock(Now.AddDays(2)));

        var ex = Assert.ThrowsExactly<InvalidLifecycleTransitionException>(
            () => app.AssignTeam(Guid.NewGuid()));
        Assert.AreEqual(Lifecycle.Decommissioned, ex.CurrentLifecycle);
    }
}

