using Kartova.Catalog.Application;

namespace Kartova.Catalog.Tests;

[TestClass]
public class DerivedDependenciesTests
{
    private static readonly Guid S = Guid.Parse("11111111-1111-1111-1111-111111111111");
    private static readonly Guid T = Guid.Parse("22222222-2222-2222-2222-222222222222");
    private static readonly Guid U = Guid.Parse("33333333-3333-3333-3333-333333333333");
    private static readonly Guid App = Guid.Parse("44444444-4444-4444-4444-444444444444");
    private static readonly Guid App2 = Guid.Parse("55555555-5555-5555-5555-555555555555");
    private static readonly Guid Api1 = Guid.Parse("66666666-6666-6666-6666-666666666666");
    private static readonly Guid Api2 = Guid.Parse("77777777-7777-7777-7777-777777777777");

    private static readonly IReadOnlySet<(Guid, Guid)> NoExplicit = new HashSet<(Guid, Guid)>();

    private static IReadOnlyList<DerivedDependencies.Edge> Compute(
        (Guid, Guid)[] consumes = null!, (Guid, Guid)[] serviceProvides = null!,
        (Guid, Guid)[] instanceOf = null!, (Guid, Guid)[] appProvides = null!,
        IReadOnlySet<(Guid, Guid)> explicitDeps = null!) =>
        DerivedDependencies.Compute(
            consumes ?? [], serviceProvides ?? [], instanceOf ?? [], appProvides ?? [], explicitDeps ?? NoExplicit);

    [TestMethod]
    public void direct_provide_path_yields_edge_with_null_via_app()
    {
        // S consumes Api1; T provides Api1 directly → S depends-on T, viaApp null.
        var edges = Compute(consumes: [(S, Api1)], serviceProvides: [(T, Api1)]);
        var e = edges.Single();
        Assert.AreEqual(S, e.SourceServiceId);
        Assert.AreEqual(T, e.TargetServiceId);
        var p = e.Paths.Single();
        Assert.AreEqual(Api1, p.ApiId);
        Assert.IsNull(p.ViaAppId);
    }

    [TestMethod]
    public void via_app_path_yields_edge_with_via_app_populated()
    {
        // S consumes Api1; T instance-of App; App provides Api1 → viaApp = App.
        var edges = Compute(consumes: [(S, Api1)], instanceOf: [(T, App)], appProvides: [(App, Api1)]);
        var p = edges.Single().Paths.Single();
        Assert.AreEqual(Api1, p.ApiId);
        Assert.AreEqual(App, p.ViaAppId);
    }

    [TestMethod]
    public void same_api_direct_and_via_app_dedupes_to_two_distinct_paths()
    {
        // T both provides Api1 directly AND via App. Distinct paths (null via + App via), one edge.
        var edges = Compute(
            consumes: [(S, Api1)], serviceProvides: [(T, Api1)],
            instanceOf: [(T, App)], appProvides: [(App, Api1)]);
        var e = edges.Single();
        Assert.AreEqual(2, e.Paths.Count);
        Assert.IsTrue(e.Paths.Any(p => p.ViaAppId is null));
        Assert.IsTrue(e.Paths.Any(p => p.ViaAppId == App));
    }

    [TestMethod]
    public void multiple_apis_collapse_to_one_edge_with_multiple_paths()
    {
        // S consumes Api1 and Api2; T provides both → one edge, two paths.
        var edges = Compute(consumes: [(S, Api1), (S, Api2)], serviceProvides: [(T, Api1), (T, Api2)]);
        var e = edges.Single();
        Assert.AreEqual(2, e.Paths.Count);
        CollectionAssert.AreEquivalent(new[] { Api1, Api2 }, e.Paths.Select(p => p.ApiId).ToArray());
    }

    [TestMethod]
    public void explicit_depends_on_suppresses_derived_edge_for_that_pair()
    {
        var edges = Compute(
            consumes: [(S, Api1)], serviceProvides: [(T, Api1)],
            explicitDeps: new HashSet<(Guid, Guid)> { (S, T) });
        Assert.AreEqual(0, edges.Count);
    }

    [TestMethod]
    public void self_dependency_is_never_emitted()
    {
        // S consumes Api1 and S also provides Api1 → no S→S edge.
        var edges = Compute(consumes: [(S, Api1)], serviceProvides: [(S, Api1)]);
        Assert.AreEqual(0, edges.Count);
    }

    [TestMethod]
    public void consumer_without_matching_provider_yields_nothing()
    {
        var edges = Compute(consumes: [(S, Api1)], serviceProvides: [(T, Api2)]);
        Assert.AreEqual(0, edges.Count);
    }

    [TestMethod]
    public void two_consumers_of_same_provider_yield_two_edges()
    {
        // S and U both consume Api1 that T provides → S→T and U→T.
        var edges = Compute(consumes: [(S, Api1), (U, Api1)], serviceProvides: [(T, Api1)]);
        Assert.AreEqual(2, edges.Count);
        Assert.IsTrue(edges.Any(e => e.SourceServiceId == S && e.TargetServiceId == T));
        Assert.IsTrue(edges.Any(e => e.SourceServiceId == U && e.TargetServiceId == T));
    }

    [TestMethod]
    public void empty_inputs_yield_empty()
    {
        Assert.AreEqual(0, Compute().Count);
    }

    [TestMethod]
    public void paths_are_deterministically_ordered()
    {
        // Two apps expose the same API for T; order must be stable (by apiId, then viaAppId).
        var edges = Compute(
            consumes: [(S, Api1)], instanceOf: [(T, App2), (T, App)], appProvides: [(App, Api1), (App2, Api1)]);
        var vias = edges.Single().Paths.Select(p => p.ViaAppId).ToList();
        var sorted = vias.OrderBy(v => v).ToList();
        CollectionAssert.AreEqual(sorted, vias);
    }

    [TestMethod]
    public void duplicate_raw_tuples_dedupe_to_one_path()
    {
        // S consumes Api1 twice (duplicate raw edges); T provides Api1 → one edge with a single deduped path.
        var edges = Compute(consumes: [(S, Api1), (S, Api1)], serviceProvides: [(T, Api1)]);
        Assert.AreEqual(1, edges.Single().Paths.Count);
    }

    [TestMethod]
    public void edges_are_ordered_by_source_then_target()
    {
        // U and S both consume Api1 that T provides. Returned edges must already be sorted by (source, target).
        var edges = Compute(consumes: [(U, Api1), (S, Api1)], serviceProvides: [(T, Api1)]);
        var expected = edges.OrderBy(e => e.SourceServiceId).ThenBy(e => e.TargetServiceId).ToList();
        CollectionAssert.AreEqual(expected, edges.ToList());
    }
}

using Kartova.Catalog.Infrastructure;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.InMemory.Infrastructure.Internal;
using Microsoft.EntityFrameworkCore.Metadata;
using Microsoft.EntityFrameworkCore.Metadata.Conventions;

// NOTE: `Kartova.Catalog.Application` namespace wins simple-name lookup over
// `Kartova.Catalog.Domain.Application`, so we alias the domain type explicitly.
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Pins the EF Core model shape produced by <see cref="EfApplicationConfiguration"/>.
/// These tests introspect the compiled EF model via an InMemory context so that
/// removing or reordering any Fluent API call in the configuration class causes an
/// immediate failure — without requiring a live database.
/// </summary>
[TestClass]
public class EfApplicationConfigurationTests
{
    /// <summary>
    /// Returns a mutable (non-frozen) <see cref="IConventionEntityType"/> built by
    /// applying <see cref="EfApplicationConfiguration"/> to a fresh <see cref="ModelBuilder"/>.
    /// Using the mutable model (before <c>FinalizeModel()</c> is called) allows us to
    /// cast keys/properties to <see cref="IConventionKey"/> and read
    /// <see cref="ConfigurationSource"/>.
    /// </summary>
    private static IConventionEntityType BuildConventionModel()
    {
        // Build a convention set using the InMemory provider's static helper.
        var conventionSet = InMemoryConventionSetBuilder.Build();
        var modelBuilder = new ModelBuilder(conventionSet);

        // Apply only the configuration under test.
        new EfApplicationConfiguration().Configure(modelBuilder.Entity<DomainApplication>());

        return (IConventionEntityType)modelBuilder.Model
            .FindEntityType(typeof(DomainApplication))!;
    }

    private static IEntityType GetEntityType()
    {
        // Arrange — build an in-memory context to obtain the compiled model.
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase("EfApplicationConfigurationTests_" + Guid.NewGuid())
            .Options;

        using var ctx = new CatalogDbContext(options);

        return ctx.Model.FindEntityType(typeof(DomainApplication))
            ?? throw new InvalidOperationException("Application entity type not found in model.");
    }

    // -----------------------------------------------------------------------
    // Mutant-killing assertion — Statement mutator on `EfApplicationConfiguration.HasKey(IdFieldName)`.
    // -----------------------------------------------------------------------

    [TestMethod]
    public void Configure_marks_Id_as_primary_key()
    {
        // Arrange — use the mutable convention model so we can read ConfigurationSource.
        var entity = BuildConventionModel();

        // Act
        var pk = entity.FindPrimaryKey();

        // Assert
        // The PK is mapped via the private backing field _id (plain Guid).
        // Using a backing field instead of the ApplicationId-typed property allows
        // EF Core to translate ORDER BY / WHERE on the id column without going
        // through the value converter (which EF cannot push down to SQL).
        Assert.IsNotNull(pk, "a primary key must be configured");
        Assert.AreEqual(
            1,
            pk!.Properties.Count(p => p.Name == "_id"),
            "_id backing field must be the sole primary key property");

        // The strongest kill: explicit HasKey → ConfigurationSource.Explicit.
        Assert.AreEqual(
            ConfigurationSource.Explicit,
            pk.GetConfigurationSource(),
            "the PK must be configured via explicit HasKey on the _id field");
    }

    // -----------------------------------------------------------------------
    // Complementary assertions — kill neighbouring Statement mutations
    // -----------------------------------------------------------------------

    [TestMethod]
    public void Configure_maps_to_catalog_applications_table()
    {
        // Arrange / Act
        var entity = GetEntityType();

        // Assert
        Assert.AreEqual("catalog_applications", entity.GetTableName());
    }

    [TestMethod]
    public void Configure_value_generation_never_on_Id()
    {
        // Arrange / Act — the PK is now the _id backing field (plain Guid)
        var idProp = GetEntityType().FindProperty("_id")!;

        // Assert
        Assert.AreEqual(
            ValueGenerated.Never,
            idProp.ValueGenerated,
            "ApplicationId values are assigned by the domain, not the database");
    }

    [TestMethod]
    public void Configure_Id_column_name_is_id()
    {
        // Arrange / Act — the PK is now the _id backing field (plain Guid)
        var idProp = GetEntityType().FindProperty("_id")!;

        // Assert
        Assert.AreEqual("id", idProp.GetColumnName());
    }

    [TestMethod]
    public void Configure_pins_required_columns_and_max_lengths()
    {
        // Arrange
        var entity = GetEntityType();

        // Act / Assert — DisplayName
        var displayName = entity.FindProperty("DisplayName")!;
        Assert.IsFalse(displayName.IsNullable, "DisplayName is required");
        Assert.AreEqual(128, displayName.GetMaxLength(), "DisplayName max length is 128");
        Assert.AreEqual("display_name", displayName.GetColumnName());

        // Description
        var description = entity.FindProperty("Description")!;
        Assert.IsFalse(description.IsNullable, "Description is required");
        Assert.AreEqual("description", description.GetColumnName());

        // CreatedByUserId (ADR-0103: renamed from OwnerUserId)
        var createdByUserId = entity.FindProperty("CreatedByUserId")!;
        Assert.IsFalse(createdByUserId.IsNullable, "CreatedByUserId is required");
        Assert.AreEqual("created_by_user_id", createdByUserId.GetColumnName());

        // TeamId (ADR-0103: now the required owner — non-nullable)
        var teamId = entity.FindProperty("TeamId")!;
        Assert.IsFalse(teamId.IsNullable, "TeamId is required (the owning team)");
        Assert.AreEqual("team_id", teamId.GetColumnName());

        // TenantId
        var tenantId = entity.FindProperty("TenantId")!;
        Assert.IsFalse(tenantId.IsNullable, "TenantId is required");
        Assert.AreEqual("tenant_id", tenantId.GetColumnName());

        // CreatedAt
        var createdAt = entity.FindProperty("CreatedAt")!;
        Assert.IsFalse(createdAt.IsNullable, "CreatedAt is required");
        Assert.AreEqual("created_at", createdAt.GetColumnName());
    }

    [TestMethod]
    public void Configure_ignores_domain_typed_Id_property()
    {
        // Arrange — use the convention model so we can read IgnoredMembers (which is
        // erased once the model is finalized).
        var conventionEntity = BuildConventionModel();

        // Act
        var ignoredMembers = conventionEntity.GetIgnoredMembers();
        var finalEntity = GetEntityType();
        var idProperty = finalEntity.FindProperty(nameof(DomainApplication.Id));
        var mappedNames = finalEntity.GetProperties().Select(p => p.Name).ToList();

        // Assert
        // Primary kill: explicit Ignore registers the member name in IgnoredMembers.
        Assert.IsTrue(
            ignoredMembers.Contains(nameof(DomainApplication.Id)),
            "Configure must explicitly Ignore the domain-typed Id getter so future EF " +
            "convention changes (complex/owned-type auto-mapping) cannot silently map it");

        // Secondary kill: the finalized model must not surface Id as a mapped property —
        // only the shadow _id backing field should appear.
        Assert.IsNull(idProperty, "the domain-typed Id getter must not be mapped");
        Assert.IsFalse(mappedNames.Contains(nameof(DomainApplication.Id)));
        Assert.IsTrue(mappedNames.Contains("_id"), "the backing field _id must be mapped instead");
    }

    [TestMethod]
    public void Configure_indexes_tenant_id_with_named_index()
    {
        // Arrange / Act
        var entity = GetEntityType();

        // Assert
        // Specifically the single-column TenantId index (multiple composite indexes
        // also start with TenantId — e.g. ix_catalog_applications_tenant_id_display_name).
        var index = entity.GetIndexes()
            .SingleOrDefault(i => i.Properties.Count == 1 && i.Properties[0].Name == "TenantId");

        Assert.IsNotNull(index, "TenantId must have a dedicated single-column index");
        Assert.AreEqual("ix_catalog_applications_tenant_id", index!.GetDatabaseName());
    }

    [TestMethod]
    public void Configure_indexes_tenant_id_and_display_name_with_named_composite_index()
    {
        // ADR-0095: composite (tenant_id, display_name) supports ORDER BY display_name
        // keyset pagination scoped per tenant without an extra sort step.
        var entity = GetEntityType();

        var index = entity.GetIndexes()
            .SingleOrDefault(i =>
                i.Properties.Count == 2 &&
                i.Properties[0].Name == "TenantId" &&
                i.Properties[1].Name == "DisplayName");

        Assert.IsNotNull(index, "composite (TenantId, DisplayName) index must exist for displayName sort");
        Assert.AreEqual("ix_catalog_applications_tenant_id_display_name", index!.GetDatabaseName());
    }
}

using Kartova.Catalog.Application;
using Kartova.Catalog.Infrastructure;
using Kartova.SharedKernel;
using Kartova.SharedKernel.Identity;
using Kartova.SharedKernel.Multitenancy;
using Microsoft.EntityFrameworkCore;
using NSubstitute;

// NOTE: Alias needed — the enclosing `Kartova.Catalog` namespace contains a sibling child
// namespace `Kartova.Catalog.Application` which wins simple-name lookup for `Application`.
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Unit-tier tests for the CreatedBy-enrichment branch of <see cref="GetApplicationByIdHandler"/>
/// (slice 9 / E1 — ADR-0098, renamed slice 10 / ADR-0103). The detail endpoint uses
/// single-shot <c>IUserDirectory.GetAsync</c> rather than the list endpoint's batched
/// <c>GetManyAsync</c>, so the two paths have separate unit coverage. The
/// not-found branch is covered transitively by the existing integration tests
/// and the InMemory provider here is enough to seed/load a single row.
/// </summary>
[TestClass]
public sealed class GetApplicationByIdHandlerOwnerEnrichmentTests
{
    private static readonly TenantId Tenant = new(Guid.Parse("aaaaaaaa-2222-0000-0000-000000000001"));
    private static readonly Guid Team = Guid.Parse("cccccccc-2222-0000-0000-000000000001");
    private static readonly DateTimeOffset BaseTime =
        new(2026, 5, 27, 12, 0, 0, TimeSpan.Zero);

    private static async Task<(CatalogDbContext Db, Guid AppId, Guid CreatorId)> SeedSingleAppAsync()
    {
        var creatorId = Guid.NewGuid();
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;

        Guid appId;
        await using (var seed = new CatalogDbContext(options))
        {
            var app = DomainApplication.Create(
                displayName: "App For Detail Lookup",
                description: "created-by enrichment unit test",
                createdByUserId: creatorId,
                teamId: Team,
                tenantId: Tenant,
                clock: TestClocks.At(BaseTime));
            seed.Applications.Add(app);
            await seed.SaveChangesAsync();
            appId = app.Id.Value;
        }

        return (new CatalogDbContext(options), appId, creatorId);
    }

    [TestMethod]
    public async Task Handle_populates_CreatedBy_when_directory_returns_matching_user()
    {
        var (db, appId, creatorId) = await SeedSingleAppAsync();
        await using var _ = db;

        var directory = Substitute.For<IUserDirectory>();
        var displayInfo = new UserDisplayInfo(creatorId, "Bob Bridger", "bob@orga.kartova.local");
        directory.GetAsync(creatorId, Arg.Any<CancellationToken>()).Returns(displayInfo);

        var handler = new GetApplicationByIdHandler(directory);
        var resp = await handler.Handle(new GetApplicationByIdQuery(appId), db, CancellationToken.None);

        Assert.IsNotNull(resp);
        Assert.IsNotNull(resp!.CreatedBy, "CreatedBy must be populated when the directory returns a match");
        Assert.AreEqual(creatorId, resp.CreatedBy!.Id);
        Assert.AreEqual("Bob Bridger", resp.CreatedBy.DisplayName);
        Assert.AreEqual("bob@orga.kartova.local", resp.CreatedBy.Email);
        // The directory call must target the application's CreatedByUserId — a mutant that
        // looked up some other guid (e.g., Guid.Empty) would fail this Received check.
        await directory.Received(1).GetAsync(creatorId, Arg.Any<CancellationToken>());
    }

    [TestMethod]
    public async Task Handle_leaves_CreatedBy_null_when_directory_returns_null()
    {
        // User-deleted-after-application-was-registered branch: GetAsync returns null,
        // the handler must still return the application row, but with CreatedBy = null.
        var (db, appId, creatorId) = await SeedSingleAppAsync();
        await using var _ = db;

        var directory = Substitute.For<IUserDirectory>();
        directory.GetAsync(creatorId, Arg.Any<CancellationToken>()).Returns((UserDisplayInfo?)null);

        var handler = new GetApplicationByIdHandler(directory);
        var resp = await handler.Handle(new GetApplicationByIdQuery(appId), db, CancellationToken.None);

        Assert.IsNotNull(resp);
        Assert.IsNull(resp!.CreatedBy, "CreatedBy must be null when the directory has no entry for CreatedByUserId");
        Assert.AreEqual(creatorId, resp.CreatedByUserId,
            "the row's CreatedByUserId is still the original creator — only the display projection is missing");
    }

    [TestMethod]
    public async Task Handle_returns_null_without_calling_directory_when_application_does_not_exist()
    {
        // Defensive: when the app row is not visible (RLS-hidden or genuinely absent),
        // the handler must short-circuit before issuing the directory call. Avoids a
        // pointless round trip and removes a potential cross-tenant info leak vector.
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;
        await using var db = new CatalogDbContext(options);

        var directory = Substitute.For<IUserDirectory>();

        var handler = new GetApplicationByIdHandler(directory);
        var resp = await handler.Handle(new GetApplicationByIdQuery(Guid.NewGuid()), db, CancellationToken.None);

        Assert.IsNull(resp);
        await directory.DidNotReceive().GetAsync(Arg.Any<Guid>(), Arg.Any<CancellationToken>());
    }
}

// src/Modules/Catalog/Kartova.Catalog.Tests/GraphTraversalTests.cs
using Kartova.Catalog.Application;
using Kartova.Catalog.Domain;

namespace Kartova.Catalog.Tests;

[TestClass]
public class GraphTraversalTests
{
    private static readonly Guid F = Guid.NewGuid();
    private static readonly Guid A = Guid.NewGuid();
    private static readonly Guid B = Guid.NewGuid();
    private static readonly Guid C = Guid.NewGuid();

    private static EntityRef Svc(Guid id) => new(EntityKind.Service, id);

    private static GraphTraversalEdge Edge(Guid src, Guid tgt) =>
        new(Svc(src), Svc(tgt), Guid.NewGuid(), RelationshipType.DependsOn, RelationshipOrigin.Manual);

    // A fetch delegate over a fixed edge list: returns edges touching the frontier (source or target).
    private static Func<IReadOnlyCollection<EntityRef>, CancellationToken, Task<IReadOnlyList<GraphTraversalEdge>>>
        Fetch(params GraphTraversalEdge[] all) =>
        (frontier, _) =>
        {
            var ids = frontier.Select(f => f.Id).ToHashSet();
            IReadOnlyList<GraphTraversalEdge> hit =
                all.Where(e => ids.Contains(e.Source.Id) || ids.Contains(e.Target.Id)).ToList();
            return Task.FromResult(hit);
        };

    [TestMethod]
    public async Task focus_with_no_edges_returns_only_focus()
    {
        var r = await GraphTraversal.BuildAsync(Svc(F), 2, RelationshipDirection.All, 200, Fetch(), CancellationToken.None);
        Assert.AreEqual(1, r.Nodes.Count);
        Assert.AreEqual(F, r.Nodes[0].Ref.Id);
        Assert.AreEqual(0, r.Nodes[0].Depth);
        Assert.AreEqual(0, r.Edges.Count);
        Assert.IsFalse(r.Truncated);
    }

    [TestMethod]
    public async Task depth_2_discovers_two_hops_with_correct_depths()
    {
        // F -> A -> B
        var r = await GraphTraversal.BuildAsync(Svc(F), 2, RelationshipDirection.All, 200,
            Fetch(Edge(F, A), Edge(A, B)), CancellationToken.None);
        Assert.AreEqual(0, r.Nodes.Single(n => n.Ref.Id == F).Depth);
        Assert.AreEqual(1, r.Nodes.Single(n => n.Ref.Id == A).Depth);
        Assert.AreEqual(2, r.Nodes.Single(n => n.Ref.Id == B).Depth);
        Assert.AreEqual(2, r.Edges.Count);
    }

    [TestMethod]
    public async Task depth_1_excludes_the_second_hop()
    {
        var r = await GraphTraversal.BuildAsync(Svc(F), 1, RelationshipDirection.All, 200,
            Fetch(Edge(F, A), Edge(A, B)), CancellationToken.None);
        Assert.IsFalse(r.Nodes.Any(n => n.Ref.Id == B));
        Assert.AreEqual(1, r.Edges.Count); // only F->A; the A->B edge has an excluded endpoint
    }

    [TestMethod]
    public async Task outgoing_only_follows_source_to_target()
    {
        // C -> F (incoming to F) and F -> A (outgoing from F). Outgoing keeps only A.
        var r = await GraphTraversal.BuildAsync(Svc(F), 1, RelationshipDirection.Outgoing, 200,
            Fetch(Edge(C, F), Edge(F, A)), CancellationToken.None);
        Assert.IsTrue(r.Nodes.Any(n => n.Ref.Id == A));
        Assert.IsFalse(r.Nodes.Any(n => n.Ref.Id == C));
    }

    [TestMethod]
    public async Task incoming_only_follows_target_to_source()
    {
        var r = await GraphTraversal.BuildAsync(Svc(F), 1, RelationshipDirection.Incoming, 200,
            Fetch(Edge(C, F), Edge(F, A)), CancellationToken.None);
        Assert.IsTrue(r.Nodes.Any(n => n.Ref.Id == C));
        Assert.IsFalse(r.Nodes.Any(n => n.Ref.Id == A));
    }

    [TestMethod]
    public async Task cycle_terminates_with_one_node_per_entity()
    {
        // F -> A and A -> F (a 2-cycle)
        var r = await GraphTraversal.BuildAsync(Svc(F), 3, RelationshipDirection.All, 200,
            Fetch(Edge(F, A), Edge(A, F)), CancellationToken.None);
        Assert.AreEqual(2, r.Nodes.Count);          // F, A — each once
        Assert.AreEqual(2, r.Edges.Count);          // both edges present
    }

    [TestMethod]
    public async Task cap_truncates_and_flags()
    {
        // F -> A, F -> B, F -> C ; maxNodes=2 keeps focus + one neighbour
        var r = await GraphTraversal.BuildAsync(Svc(F), 1, RelationshipDirection.All, 2,
            Fetch(Edge(F, A), Edge(F, B), Edge(F, C)), CancellationToken.None);
        Assert.AreEqual(2, r.Nodes.Count);
        Assert.IsTrue(r.Truncated);
        Assert.IsTrue(r.Edges.All(e =>
            r.Nodes.Any(n => n.Ref.Id == e.Source.Id) && r.Nodes.Any(n => n.Ref.Id == e.Target.Id)));
    }
}

using Kartova.Catalog.Domain;
using Kartova.SharedKernel;

namespace Kartova.Catalog.Tests;

[TestClass]
public class InvalidLifecycleTransitionExceptionTests
{
    [TestMethod]
    public void Message_for_null_reason_omits_parenthetical()
    {
        var ex = new InvalidLifecycleTransitionException(
            Lifecycle.Decommissioned,
            "Deprecate",
            sunsetDate: null,
            reason: null);

        Assert.AreEqual("Cannot deprecate application currently in state Decommissioned.", ex.Message);
    }

    [TestMethod]
    public void Message_for_non_null_reason_includes_parenthetical()
    {
        var sunsetDate = new DateTimeOffset(2026, 6, 1, 0, 0, 0, TimeSpan.Zero);

        var ex = new InvalidLifecycleTransitionException(
            Lifecycle.Deprecated,
            "Decommission",
            sunsetDate: sunsetDate,
            reason: "before-sunset-date");

        Assert.AreEqual("Cannot decommission application currently in state Deprecated (before-sunset-date).", ex.Message);
    }

    [TestMethod]
    public void Properties_match_constructor_args()
    {
        var sunsetDate = new DateTimeOffset(2026, 7, 15, 9, 30, 0, TimeSpan.Zero);

        var ex = new InvalidLifecycleTransitionException(
            Lifecycle.Active,
            "Decommission",
            sunsetDate: sunsetDate,
            reason: "before-sunset-date");

        Assert.AreEqual(Lifecycle.Active, ex.CurrentLifecycle);
        Assert.AreEqual("Decommission", ex.AttemptedTransition);
        Assert.AreEqual(sunsetDate, ex.SunsetDate);
        Assert.AreEqual("before-sunset-date", ex.Reason);
    }

    [TestMethod]
    [DataRow(Lifecycle.Active, "active")]
    [DataRow(Lifecycle.Deprecated, "deprecated")]
    [DataRow(Lifecycle.Decommissioned, "decommissioned")]
    public void ILifecycleConflict_CurrentLifecycleName_returns_camelCase_wire_shape(
        Lifecycle current, string expectedWire)
    {
        // Pins the explicit-interface implementation that lower-cases the enum
        // name to match JsonStringEnumConverter(JsonNamingPolicy.CamelCase) on
        // ApplicationResponse.lifecycle (ADR-0095). If a refactor accidentally
        // dropped the `: ILifecycleConflict` declaration or the explicit member
        // (e.g. let the public `CurrentLifecycle` enum property satisfy the
        // contract via auto-conversion), the upcast here would call a different
        // implementation that returns PascalCase — caught by this assertion.
        var ex = new InvalidLifecycleTransitionException(current, "Deprecate");

        Assert.AreEqual(expectedWire, ((ILifecycleConflict)ex).CurrentLifecycleName);
    }
}

