using Kartova.Catalog.Infrastructure;
using Kartova.SharedKernel;
using Kartova.SharedKernel.Identity;
using Kartova.SharedKernel.Multitenancy;
using Kartova.SharedKernel.Pagination;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Time.Testing;
using NSubstitute;

// NOTE: Alias needed — the enclosing `Kartova.Catalog` namespace contains a sibling child
// namespace `Kartova.Catalog.Application` which wins simple-name lookup for `Application`.
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Unit-tier tests for the lifecycle and teamId predicates in
/// <see cref="ListApplicationsHandler"/> (ADR-0107). Uses the EF Core InMemory
/// provider so this runs without a database.
/// <para>
/// Lifecycle filter: empty ⇒ ADR-0073 default view (hide Decommissioned);
/// non-empty ⇒ exactly the selected states (<c>IN</c> predicate).
/// TeamId filter: non-empty ⇒ rows whose <c>TeamId</c> is in the supplied set.
/// Both filters are encoded into the cursor <c>f</c>-map when non-empty.
/// </para>
/// </summary>
[TestClass]
public class ListApplicationsHandlerFilterTests
{
    private static readonly TenantId Tenant = new(Guid.Parse("aaaaaaaa-0000-0000-0000-000000000001"));
    private static readonly Guid Creator = Guid.Parse("bbbbbbbb-0000-0000-0000-000000000001");
    private static readonly Guid Team = Guid.Parse("cccccccc-0000-0000-0000-000000000001");

    // Second team for teamId filter tests.
    private static readonly Guid TeamB = Guid.Parse("cccccccc-0000-0000-0000-000000000002");

    private static readonly DateTimeOffset BaseTime =
        new(2026, 5, 7, 12, 0, 0, TimeSpan.Zero);

    private static FakeTimeProvider Clock(DateTimeOffset? at = null) => TestClocks.At(at ?? BaseTime);

    /// <summary>
    /// Builds a fresh InMemory <see cref="CatalogDbContext"/> with one Active and
    /// one Decommissioned application already saved. The two apps use distinct
    /// <c>CreatedAt</c> timestamps (1 minute apart) so the deterministic ordering
    /// assertion is stable regardless of insertion order.
    /// </summary>
    private static async Task<CatalogDbContext> BuildDbWithBothLifecyclesAsync()
    {
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;

        using var seed = new CatalogDbContext(options);

        var activeClock = Clock(BaseTime);
        var active = DomainApplication.Create(
            displayName: "Active App",
            description: "An active application.",
            createdByUserId: Creator,
            teamId: Team,
            tenantId: Tenant,
            clock: activeClock);

        // Drive the decommission state machine: Active → Deprecated → Decommissioned.
        var sunsetClock = Clock(BaseTime.AddMinutes(10));
        var decommClock = Clock(BaseTime.AddMinutes(20));
        var decomm = DomainApplication.Create(
            displayName: "Decomm App",
            description: "A decommissioned application.",
            createdByUserId: Creator,
            teamId: Team,
            tenantId: Tenant,
            clock: Clock(BaseTime.AddMinutes(1)));
        decomm.Deprecate(sunsetDate: BaseTime.AddMinutes(15), clock: sunsetClock);
        decomm.Decommission(clock: decommClock);

        seed.Applications.Add(active);
        seed.Applications.Add(decomm);
        await seed.SaveChangesAsync();

        // Return a fresh context over the same database so the in-memory store is shared
        // but the identity map is clean.
        return new CatalogDbContext(options);
    }

    private static async Task<CatalogDbContext> BuildDbWithTwoTeamsAsync()
    {
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString()).Options;
        using var seed = new CatalogDbContext(options);
        var inA = DomainApplication.Create("In Team A", "d", Creator, Team, Tenant, Clock(BaseTime));
        var inB = DomainApplication.Create("In Team B", "d", Creator, TeamB, Tenant, Clock(BaseTime.AddMinutes(1)));
        seed.Applications.Add(inA);
        seed.Applications.Add(inB);
        await seed.SaveChangesAsync();
        return new CatalogDbContext(options);
    }

    /// <summary>
    /// Returns an <see cref="IUserDirectory"/> stub whose <c>GetManyAsync</c> always
    /// resolves to an empty dictionary. The filter tests intentionally exercise the
    /// lifecycle/teamId predicate paths only — Owner-enrichment branch coverage
    /// lives in <see cref="ListApplicationsHandlerOwnerEnrichmentTests"/>.
    /// </summary>
    private static IUserDirectory NoOpDirectory()
    {
        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>());
        return directory;
    }

    private static ListApplicationsQuery Query(Lifecycle[]? lifecycle = null, Guid[]? teamId = null) =>
        new(ApplicationSortField.CreatedAt, SortOrder.Desc, Cursor: null, Limit: 50,
            Lifecycle: lifecycle ?? Array.Empty<Lifecycle>(),
            TeamId: teamId ?? Array.Empty<Guid>());

    [TestMethod]
    public async Task Handle_with_no_lifecycle_filter_excludes_Decommissioned_rows()
    {
        await using var db = await BuildDbWithBothLifecyclesAsync();
        var page = await new ListApplicationsHandler(NoOpDirectory()).Handle(Query(), db, CancellationToken.None);
        Assert.AreEqual(1, page.Items.Count, "empty lifecycle filter applies the ADR-0073 default view");
        Assert.AreEqual("Active App", page.Items.Single().DisplayName);
    }

    [TestMethod]
    public async Task Handle_with_lifecycle_decommissioned_returns_only_decommissioned()
    {
        await using var db = await BuildDbWithBothLifecyclesAsync();
        var page = await new ListApplicationsHandler(NoOpDirectory())
            .Handle(Query(lifecycle: new[] { Lifecycle.Decommissioned }), db, CancellationToken.None);
        Assert.AreEqual(1, page.Items.Count);
        Assert.AreEqual("Decomm App", page.Items.Single().DisplayName);
    }

    [TestMethod]
    public async Task Handle_with_all_lifecycles_returns_both()
    {
        await using var db = await BuildDbWithBothLifecyclesAsync();
        var page = await new ListApplicationsHandler(NoOpDirectory())
            .Handle(Query(lifecycle: new[] { Lifecycle.Active, Lifecycle.Deprecated, Lifecycle.Decommissioned }), db, CancellationToken.None);
        Assert.AreEqual(2, page.Items.Count);
        CollectionAssert.AreEquivalent(new[] { "Active App", "Decomm App" }, page.Items.Select(i => i.DisplayName).ToArray());
    }

    [TestMethod]
    public async Task Handle_with_lifecycle_deprecated_returns_only_deprecated()
    {
        // Pins the middle enum value (Deprecated = 2): the Contains predicate must
        // match it without confusing it for Active (1) or Decommissioned (3).
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString()).Options;
        using (var seed = new CatalogDbContext(options))
        {
            var active = DomainApplication.Create("Active App", "d", Creator, Team, Tenant, Clock(BaseTime));
            var deprecated = DomainApplication.Create("Deprecated App", "d", Creator, Team, Tenant, Clock(BaseTime.AddMinutes(1)));
            deprecated.Deprecate(sunsetDate: BaseTime.AddMinutes(15), clock: Clock(BaseTime.AddMinutes(10)));
            seed.Applications.Add(active);
            seed.Applications.Add(deprecated);
            await seed.SaveChangesAsync();
        }
        await using var db = new CatalogDbContext(options);

        var page = await new ListApplicationsHandler(NoOpDirectory())
            .Handle(Query(lifecycle: new[] { Lifecycle.Deprecated }), db, CancellationToken.None);

        Assert.AreEqual(1, page.Items.Count);
        Assert.AreEqual("Deprecated App", page.Items.Single().DisplayName);
    }

    [TestMethod]
    public async Task Handle_with_teamId_filters_to_that_team()
    {
        await using var db = await BuildDbWithTwoTeamsAsync();
        var page = await new ListApplicationsHandler(NoOpDirectory())
            .Handle(Query(teamId: new[] { TeamB }), db, CancellationToken.None);
        Assert.AreEqual(1, page.Items.Count);
        Assert.AreEqual("In Team B", page.Items.Single().DisplayName);
    }
}

using Kartova.Catalog.Application;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.Catalog.Infrastructure;
using Kartova.SharedKernel;
using Kartova.SharedKernel.Identity;
using Kartova.SharedKernel.Multitenancy;
using Kartova.SharedKernel.Pagination;
using Microsoft.EntityFrameworkCore;
using NSubstitute;

// NOTE: Alias needed — the enclosing `Kartova.Catalog` namespace contains a sibling child
// namespace `Kartova.Catalog.Application` which wins simple-name lookup for `Application`.
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Unit-tier tests for the CreatedBy-enrichment branch of <see cref="ListApplicationsHandler"/>
/// (slice 9 / E1 — ADR-0098, renamed slice 10 / ADR-0103). The handler must:
/// <list type="bullet">
///   <item>Issue exactly one batched <c>GetManyAsync</c> call with the distinct created-by ids on the page.</item>
///   <item>Populate <see cref="ApplicationResponse.CreatedBy"/> when the directory returns a matching entry.</item>
///   <item>Leave <see cref="ApplicationResponse.CreatedBy"/> as <c>null</c> when the directory does not return a match
///     (e.g., the user row was deleted after the application was registered).</item>
/// </list>
/// Database-shape concerns (sort, cursor, RLS) live in the integration suite; the EF Core
/// InMemory provider here keeps the unit test free of a Postgres container.
/// </summary>
[TestClass]
public sealed class ListApplicationsHandlerOwnerEnrichmentTests
{
    private static readonly TenantId Tenant = new(Guid.Parse("aaaaaaaa-1111-0000-0000-000000000001"));
    private static readonly Guid Team = Guid.Parse("cccccccc-1111-0000-0000-000000000001");
    private static readonly DateTimeOffset BaseTime =
        new(2026, 5, 27, 12, 0, 0, TimeSpan.Zero);

    private static async Task<CatalogDbContext> BuildDbWithAppsAsync(params (Guid CreatorId, string DisplayName)[] apps)
    {
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;

        await using (var seed = new CatalogDbContext(options))
        {
            for (var i = 0; i < apps.Length; i++)
            {
                var (creatorId, displayName) = apps[i];
                seed.Applications.Add(DomainApplication.Create(
                    displayName: displayName,
                    description: "created-by-enrichment unit test",
                    createdByUserId: creatorId,
                    teamId: Team,
                    tenantId: Tenant,
                    clock: TestClocks.At(BaseTime.AddSeconds(i))));
            }
            await seed.SaveChangesAsync();
        }

        return new CatalogDbContext(options);
    }

    private static ListApplicationsQuery DefaultQuery() => new(
        ApplicationSortField.CreatedAt,
        SortOrder.Desc,
        Cursor: null,
        Limit: 50,
        Lifecycle: Array.Empty<Lifecycle>(),
        TeamId: Array.Empty<Guid>());

    [TestMethod]
    public async Task Handle_populates_CreatedBy_when_directory_returns_matching_user()
    {
        // Single app + matching directory entry → CreatedBy must be the directory value verbatim.
        // This is the happy-path branch: TryGetValue succeeds and the `with { CreatedBy = ... }`
        // mutator runs.
        var creatorId = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync((creatorId, "App With Creator"));

        var directory = Substitute.For<IUserDirectory>();
        var displayInfo = new UserDisplayInfo(creatorId, "Alice Anderson", "alice@orga.kartova.local");
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo> { [creatorId] = displayInfo });

        var handler = new ListApplicationsHandler(directory);
        var page = await handler.Handle(DefaultQuery(), db, CancellationToken.None);

        var item = page.Items.Single();
        Assert.IsNotNull(item.CreatedBy, "CreatedBy must be populated when the directory returns a match");
        Assert.AreEqual(creatorId, item.CreatedBy!.Id);
        Assert.AreEqual("Alice Anderson", item.CreatedBy.DisplayName);
        Assert.AreEqual("alice@orga.kartova.local", item.CreatedBy.Email);
    }

    [TestMethod]
    public async Task Handle_leaves_CreatedBy_null_when_directory_has_no_entry_for_creator()
    {
        // The user-deleted-after-application-was-registered branch: the directory returns
        // an empty dictionary, so TryGetValue is false and CreatedBy must stay null.
        // Mutating the `?` to `:` (replacing `with { CreatedBy = creator }` with the bare
        // `resp` in the false branch) would silently drop the CreatedBy-on-match case, but
        // this test pins the false branch on its own.
        var creatorId = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync((creatorId, "Orphaned App"));

        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>());

        var handler = new ListApplicationsHandler(directory);
        var page = await handler.Handle(DefaultQuery(), db, CancellationToken.None);

        var item = page.Items.Single();
        Assert.IsNull(item.CreatedBy, "CreatedBy must be null when the directory returns no entry for the CreatedByUserId");
        // Sanity: the row itself was still returned, only the enrichment was skipped.
        Assert.AreEqual("Orphaned App", item.DisplayName);
        Assert.AreEqual(creatorId, item.CreatedByUserId);
    }

    [TestMethod]
    public async Task Handle_batches_creator_lookup_with_distinct_ids()
    {
        // Two apps created by the same user must result in a single GetManyAsync call
        // with a single distinct id (not two). Pins the `Distinct().ToList()` in the
        // handler — removing Distinct would still pass the populate/null tests above,
        // but would silently re-fetch the same user N times on a page of size N.
        var sharedCreator = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync(
            (sharedCreator, "App One"),
            (sharedCreator, "App Two"));

        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>
            {
                [sharedCreator] = new UserDisplayInfo(sharedCreator, "Shared Creator", "shared@orga.kartova.local"),
            });

        var handler = new ListApplicationsHandler(directory);
        var page = await handler.Handle(DefaultQuery(), db, CancellationToken.None);

        Assert.AreEqual(2, page.Items.Count);
        Assert.IsTrue(page.Items.All(i => i.CreatedBy is not null && i.CreatedBy.Id == sharedCreator),
            "both rows must have CreatedBy populated from the shared directory entry");

        // Exactly one call, exactly one distinct id in the argument.
        await directory.Received(1).GetManyAsync(
            Arg.Is<IReadOnlyCollection<Guid>>(ids => ids.Count == 1 && ids.Single() == sharedCreator),
            Arg.Any<CancellationToken>());
    }

    [TestMethod]
    public async Task Handle_partial_directory_match_populates_only_matched_rows()
    {
        // Two apps with different creators; the directory returns only one of them.
        // Asserts the per-row TryGetValue decision is independent — one CreatedBy populated,
        // the other null. Catches a mutant that always populates CreatedBy from the first
        // match, or always leaves it null after the first miss.
        var matchedCreator = Guid.NewGuid();
        var unmatchedCreator = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync(
            (matchedCreator, "Matched App"),
            (unmatchedCreator, "Unmatched App"));

        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>
            {
                [matchedCreator] = new UserDisplayInfo(matchedCreator, "Matched", "matched@orga.kartova.local"),
            });

        var handler = new ListApplicationsHandler(directory);
        var page = await handler.Handle(DefaultQuery(), db, CancellationToken.None);

        var matched = page.Items.Single(i => i.CreatedByUserId == matchedCreator);
        var unmatched = page.Items.Single(i => i.CreatedByUserId == unmatchedCreator);
        Assert.IsNotNull(matched.CreatedBy);
        Assert.AreEqual("Matched", matched.CreatedBy!.DisplayName);
        Assert.IsNull(unmatched.CreatedBy);
    }

    [TestMethod]
    public async Task Handle_empty_page_still_calls_directory_with_empty_collection()
    {
        // Defensive: an empty result set must not skip the directory call entirely
        // (that would diverge from the documented batched-lookup contract). The
        // production GetManyAsync short-circuits on an empty ids list, so the cost
        // is negligible. This test pins that we don't conditionally bypass the call.
        await using var db = await BuildDbWithAppsAsync(); // no apps seeded

        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>());

        var handler = new ListApplicationsHandler(directory);
        var page = await handler.Handle(DefaultQuery(), db, CancellationToken.None);

        Assert.AreEqual(0, page.Items.Count);
        await directory.Received(1).GetManyAsync(
            Arg.Is<IReadOnlyCollection<Guid>>(ids => ids.Count == 0),
            Arg.Any<CancellationToken>());
    }
}

using Kartova.Catalog.Application;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.Catalog.Infrastructure;
using Kartova.SharedKernel;
using Kartova.SharedKernel.Identity;
using Kartova.SharedKernel.Multitenancy;
using Kartova.SharedKernel.Pagination;
using Microsoft.EntityFrameworkCore;
using NSubstitute;

// NOTE: Alias needed — the enclosing `Kartova.Catalog` namespace contains a sibling child
// namespace `Kartova.Catalog.Application` which wins simple-name lookup for `Application`.
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Unit-tier tests for the <c>CreatedByUserId</c> predicate branch of
/// <see cref="ListApplicationsHandler"/> (slice 9 / E2 — spec §6.5, reframed slice
/// 10 / ADR-0103). The handler must:
/// <list type="bullet">
///   <item>Return all rows when <c>CreatedByUserId</c> is null (default behavior, unchanged).</item>
///   <item>Return only rows whose <c>CreatedByUserId</c> matches when the filter is supplied.</item>
///   <item>Apply the predicate <em>before</em> pagination so the keyset bounds are computed
///     against the filtered subset (consistent with the lifecycle filter).</item>
/// </list>
/// Endpoint-level validation (422 invalid-created-by when the supplied id has no
/// matching users row) is covered by the integration suite; this test class focuses
/// on the query predicate itself, where EF Core InMemory is sufficient.
/// </summary>
[TestClass]
public sealed class ListApplicationsHandlerOwnerFilterTests
{
    private static readonly TenantId Tenant = new(Guid.Parse("aaaaaaaa-2222-0000-0000-000000000001"));
    private static readonly Guid Team = Guid.Parse("cccccccc-2222-0000-0000-000000000001");
    private static readonly DateTimeOffset BaseTime =
        new(2026, 5, 28, 12, 0, 0, TimeSpan.Zero);

    private static async Task<CatalogDbContext> BuildDbWithAppsAsync(params (Guid CreatorId, string DisplayName)[] apps)
    {
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;

        await using (var seed = new CatalogDbContext(options))
        {
            for (var i = 0; i < apps.Length; i++)
            {
                var (creatorId, displayName) = apps[i];
                seed.Applications.Add(DomainApplication.Create(
                    displayName: displayName,
                    description: "created-by-filter unit test",
                    createdByUserId: creatorId,
                    teamId: Team,
                    tenantId: Tenant,
                    clock: TestClocks.At(BaseTime.AddSeconds(i))));
            }
            await seed.SaveChangesAsync();
        }

        return new CatalogDbContext(options);
    }

    private static IUserDirectory NoOpDirectory()
    {
        // The handler's created-by enrichment step calls GetManyAsync for every page,
        // even an empty one. Stubbing it with an empty dictionary keeps these
        // tests focused on the predicate path; CreatedBy-enrichment branch coverage
        // lives in ListApplicationsHandlerOwnerEnrichmentTests.
        var directory = Substitute.For<IUserDirectory>();
        directory.GetManyAsync(Arg.Any<IReadOnlyCollection<Guid>>(), Arg.Any<CancellationToken>())
            .Returns(new Dictionary<Guid, UserDisplayInfo>());
        return directory;
    }

    private static ListApplicationsQuery DefaultQuery(Guid? createdByUserId = null) => new(
        ApplicationSortField.CreatedAt,
        SortOrder.Desc,
        Cursor: null,
        Limit: 50,
        Lifecycle: Array.Empty<Lifecycle>(),
        TeamId: Array.Empty<Guid>(),
        CreatedByUserId: createdByUserId);

    [TestMethod]
    public async Task Handle_with_null_CreatedByUserId_returns_all_rows()
    {
        // Baseline / regression guard: the filter is optional and the default null
        // path must not change pre-E2 behaviour. Pins a mutant that always applies
        // the predicate (e.g., flipping `is { }` to `is null`).
        var creatorA = Guid.NewGuid();
        var creatorB = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync(
            (creatorA, "App A1"), (creatorA, "App A2"), (creatorA, "App A3"),
            (creatorB, "App B1"), (creatorB, "App B2"));

        var handler = new ListApplicationsHandler(NoOpDirectory());
        var page = await handler.Handle(DefaultQuery(createdByUserId: null), db, CancellationToken.None);

        Assert.AreEqual(5, page.Items.Count, "null createdByUserId must return all rows visible under the tenant scope");
    }

    [TestMethod]
    public async Task Handle_with_CreatedByUserId_returns_only_apps_for_that_creator()
    {
        // Happy path: filter narrows to the requested subset and excludes the other.
        // Pins the WHERE clause; a mutant replacing `==` with `!=` would invert the
        // counts, and dropping the WHERE entirely would still see all 5.
        var creatorA = Guid.NewGuid();
        var creatorB = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync(
            (creatorA, "App A1"), (creatorA, "App A2"), (creatorA, "App A3"),
            (creatorB, "App B1"), (creatorB, "App B2"));

        var handler = new ListApplicationsHandler(NoOpDirectory());

        var pageA = await handler.Handle(DefaultQuery(createdByUserId: creatorA), db, CancellationToken.None);
        Assert.AreEqual(3, pageA.Items.Count, "filter must return exactly the 3 apps created by creatorA");
        Assert.IsTrue(pageA.Items.All(i => i.CreatedByUserId == creatorA),
            "every returned row must have CreatedByUserId == filter value");

        var pageB = await handler.Handle(DefaultQuery(createdByUserId: creatorB), db, CancellationToken.None);
        Assert.AreEqual(2, pageB.Items.Count, "filter must return exactly the 2 apps created by creatorB");
        Assert.IsTrue(pageB.Items.All(i => i.CreatedByUserId == creatorB),
            "every returned row must have CreatedByUserId == filter value");
    }

    [TestMethod]
    public async Task Handle_with_CreatedByUserId_no_matches_returns_empty_page()
    {
        // The endpoint validates that the supplied id resolves to a user in the
        // tenant BEFORE calling the handler. But a user can exist (validation
        // passes) and still have created no applications — e.g., a freshly invited
        // member. The handler must return an empty page rather than fall through to
        // "no filter" behaviour. Pins a mutant that swallows the predicate when
        // it produces an empty set.
        var creatorA = Guid.NewGuid();
        var orphanCreator = Guid.NewGuid();
        await using var db = await BuildDbWithAppsAsync(
            (creatorA, "App A1"), (creatorA, "App A2"));

        var handler = new ListApplicationsHandler(NoOpDirectory());
        var page = await handler.Handle(DefaultQuery(createdByUserId: orphanCreator), db, CancellationToken.None);

        Assert.AreEqual(0, page.Items.Count,
            "filter for a creator who created no apps must return an empty page, not fall back to no filter");
    }

    [TestMethod]
    public async Task Handle_CreatedByUserId_filter_composes_with_lifecycle_default_view()
    {
        // Cross-filter composition: the created-by filter must layer on top of the
        // lifecycle default view (empty Lifecycle ⇒ hide Decommissioned per ADR-0073),
        // not replace it. Seed two apps for the same creator and Decommission one; the
        // default empty Lifecycle filter must still hide the Decommissioned row even when
        // the created-by filter is applied.
        var creatorId = Guid.NewGuid();
        var options = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseInMemoryDatabase(Guid.NewGuid().ToString())
            .Options;

        await using (var seed = new CatalogDbContext(options))
        {
            var clockActive = TestClocks.At(BaseTime);
            var active = DomainApplication.Create(
                displayName: "Active",
                description: "active",
                createdByUserId: creatorId,
                teamId: Team,
                tenantId: Tenant,
                clock: clockActive);

            var clockSunset = TestClocks.At(BaseTime.AddMinutes(10));
            var clockDecomm = TestClocks.At(BaseTime.AddMinutes(20));
            var decomm = DomainApplication.Create(
                displayName: "Decomm",
                description: "decomm",
                createdByUserId: creatorId,
                teamId: Team,
                tenantId: Tenant,
                clock: TestClocks.At(BaseTime.AddMinutes(1)));
            decomm.Deprecate(sunsetDate: BaseTime.AddMinutes(15), clock: clockSunset);
            decomm.Decommission(clock: clockDecomm);

            seed.Applications.Add(active);
            seed.Applications.Add(decomm);
            await seed.SaveChangesAsync();
        }

        await using var db = new CatalogDbContext(options);
        var handler = new ListApplicationsHandler(NoOpDirectory());
        var page = await handler.Handle(DefaultQuery(createdByUserId: creatorId), db, CancellationToken.None);

        Assert.AreEqual(1, page.Items.Count,
            "created-by filter must compose with lifecycle default view — Decommissioned row stays hidden");
        Assert.AreEqual("Active", page.Items.Single().DisplayName);
    }
}

using Kartova.Catalog.Contracts;
using Kartova.Catalog.Infrastructure;
using Kartova.SharedKernel.Pagination;

namespace Kartova.Catalog.Tests;

/// <summary>
/// Unit-tier coverage for the dispatch-to-extension wiring around
/// <see cref="ListApplicationsHandler"/> — specifically the
/// <see cref="ApplicationSortSpecs.Resolve"/> branches and the
/// allowlist surfaced on rejection. End-to-end pagination behavior
/// (cursor encode/decode, RLS, real SQL) lives in
/// <c>Kartova.Catalog.IntegrationTests.ListApplicationsPaginationTests</c>.
/// </summary>
[TestClass]
public class ListApplicationsHandlerTests
{
    [TestMethod]
    public void Resolve_CreatedAt_returns_CreatedAt_sort_spec()
    {
        var spec = ApplicationSortSpecs.Resolve(ApplicationSortField.CreatedAt);

        Assert.AreSame(ApplicationSortSpecs.CreatedAt, spec);
        Assert.AreEqual("createdAt", spec.FieldName);
    }

    [TestMethod]
    public void Resolve_DisplayName_returns_DisplayName_sort_spec()
    {
        var spec = ApplicationSortSpecs.Resolve(ApplicationSortField.DisplayName);

        Assert.AreSame(ApplicationSortSpecs.DisplayName, spec);
        Assert.AreEqual("displayName", spec.FieldName);
    }

    [TestMethod]
    public void Resolve_undefined_enum_value_throws_InvalidSortFieldException_with_allowlist()
    {
        // (ApplicationSortField)999 is the exact path Enum.TryParse takes when given a
        // numeric query string — Enum.IsDefined would normally reject it at the
        // endpoint boundary, but the spec mandates the inner Resolve() also be hardened
        // so a future code path (e.g. internal caller bypassing the endpoint guard)
        // cannot fall through to a default sort silently.
        var ex = Assert.ThrowsExactly<InvalidSortFieldException>(
            () => ApplicationSortSpecs.Resolve((ApplicationSortField)999));
        CollectionAssert.AreEquivalent(new[] { "createdAt", "displayName" }, ex.AllowedFields.ToArray());
    }

    [TestMethod]
    public void AllowedFieldNames_lists_only_supported_fields()
    {
        CollectionAssert.AreEquivalent(
            new[] { "createdAt", "displayName" },
            ApplicationSortSpecs.AllowedFieldNames.ToArray());
    }
}

