using System.Diagnostics.CodeAnalysis;
using System.Linq;
using System.Runtime.CompilerServices;
using Microsoft.EntityFrameworkCore.Design;
using NetArchTest.Rules;

namespace Kartova.ArchitectureTests;

/// <summary>
/// DTOs and other pure data carriers do not have testable behavior — equality, hash code,
/// and getters are auto-generated by the compiler or trivially correct. Forcing them
/// into the coverage denominator dilutes the score and rewards busywork "DTO tests."
/// All such types must carry <see cref="ExcludeFromCodeCoverageAttribute"/>.
///
/// Convention: any type living in a *.Contracts assembly, or any type whose name ends in
/// Dto / Request / Response, is treated as a pure data carrier.
/// </summary>
[TestClass]
public class ContractsCoverageRules
{
    // Compiler-emitted and tooling-injected synthetic type names: <Module>, <PrivateImplementationDetails>,
    // closure types like <>c__DisplayClass*, anonymous-type backing classes <>f__AnonymousType*.
    // Coverlet's instrumentation tracker types live in the Coverlet.* namespace and are also filtered
    // out by namespace; this regex covers the "<…>" synthetic-name shape regardless of namespace.
    private const string SyntheticTypeNamePattern = @"^<.*>.*$";


    [TestMethod]
    public void All_types_in_Contracts_assemblies_have_ExcludeFromCodeCoverage()
    {
        var contractsAssemblies = AssemblyRegistry.AllContracts().ToArray();
        Assert.IsTrue(contractsAssemblies.Length > 0);

        // Enums cannot carry [ExcludeFromCodeCoverage] (the attribute's AttributeUsage
        // does not include AttributeTargets.Enum). Coverlet excludes enums from its
        // branch-coverage instrumentation by default, so they are already harmless.
        // We filter them out via reflection after NetArchTest resolves the type list,
        // because NetArchTest's AreClasses() predicate may include enum types depending
        // on its internal Type.IsClass implementation (enums in .NET inherit System.Enum
        // which is a class, so reflection can be ambiguous).
        var offendingNonEnumTypes = contractsAssemblies
            .SelectMany(a => a.GetTypes())
            .Where(t => t.IsClass && !t.IsEnum)
            .Where(t => !Attribute.IsDefined(t, typeof(CompilerGeneratedAttribute)))
            .Where(t => !t.Namespace?.StartsWith("Coverlet.", StringComparison.Ordinal) ?? true)
            .Where(t => !System.Text.RegularExpressions.Regex.IsMatch(t.Name, SyntheticTypeNamePattern))
            .Where(t => !Attribute.IsDefined(t, typeof(ExcludeFromCodeCoverageAttribute), inherit: false))
            .Select(t => t.FullName ?? t.Name)
            .ToArray();

        Assert.AreEqual(
            0,
            offendingNonEnumTypes.Length,
            "Every non-enum type in a *.Contracts assembly is a pure data carrier and must be decorated with [ExcludeFromCodeCoverage]. " +
            $"Offending types: {string.Join(", ", offendingNonEnumTypes)}");
    }

    [TestMethod]
    public void DTO_like_types_have_ExcludeFromCodeCoverage()
    {
        var production = AssemblyRegistry.AllProduction().ToArray();

        var result = Types.InAssemblies(production)
            .That()
            .DoNotHaveCustomAttribute(typeof(CompilerGeneratedAttribute))
            .And().DoNotResideInNamespaceStartingWith("Coverlet.")
            .And().DoNotHaveNameMatching(SyntheticTypeNamePattern)
            .And().HaveNameEndingWith("Dto")
            .Or().HaveNameEndingWith("Request")
            .Or().HaveNameEndingWith("Response")
            .Should().HaveCustomAttribute(typeof(ExcludeFromCodeCoverageAttribute))
            .GetResult();

        Assert.IsTrue(
            result.IsSuccessful,
            BuildFailureMessage(result, "Types named *Dto / *Request / *Response are pure data carriers and must be decorated with [ExcludeFromCodeCoverage]"));
    }

    [TestMethod]
    public void DesignTime_DbContext_factories_have_ExcludeFromCodeCoverage()
    {
        var production = AssemblyRegistry.AllProduction().ToArray();
        var factoryInterface = typeof(IDesignTimeDbContextFactory<>);

        var factories = production
            .SelectMany(a => a.GetTypes())
            .Where(t => !t.IsAbstract && t.IsClass &&
                t.GetInterfaces().Any(i => i.IsGenericType && i.GetGenericTypeDefinition() == factoryInterface))
            .ToArray();

        var missing = factories
            .Where(t => t.GetCustomAttributes(typeof(ExcludeFromCodeCoverageAttribute), inherit: false).Length == 0)
            .Select(t => t.FullName)
            .ToArray();

        Assert.AreEqual(
            0,
            missing.Length,
            "Design-time IDesignTimeDbContextFactory<> implementations are run only by `dotnet ef`. " +
            "They must carry [ExcludeFromCodeCoverage] per CLAUDE.md §Coverage exclusion. " +
            "Offending types: " + string.Join(", ", missing));
    }

    private static string BuildFailureMessage(NetArchTest.Rules.TestResult result, string lead)
    {
        if (result.IsSuccessful) return lead;
        var offenders = result.FailingTypeNames is null
            ? "(no failing types reported)"
            : string.Join(", ", result.FailingTypeNames);
        return $"{lead}. Offending types: {offenders}";
    }
}

using Kartova.SharedKernel;
using Kartova.SharedKernel.AspNetCore;
using Kartova.SharedKernel.Postgres;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Pins lifetime contracts that ADR-0090 + ADR-0093 rely on: tenant-scoped collaborators
/// must live in the HTTP request scope so they observe the same <c>ITenantScope</c> the
/// transport adapter began. Singleton or Transient drift would silently break tenant isolation
/// at scale (a singleton ICurrentUser would freeze on the first caller's identity).
/// </summary>
[TestClass]
public class DiLifetimeRules
{
    [TestMethod]
    public void ICurrentUser_is_registered_as_scoped()
    {
        var services = BuildContainer();

        var descriptor = services.SingleOrDefault(d => d.ServiceType == typeof(ICurrentUser));

        Assert.IsNotNull(descriptor, "AddKartovaJwtAuth wires ICurrentUser → HttpContextCurrentUser");
        Assert.AreEqual(
            ServiceLifetime.Scoped,
            descriptor!.Lifetime,
            "ICurrentUser reads per-request claims; singleton or transient would either freeze or " +
            "fail to share the JWT-derived tenant scope (ADR-0090/0093)");
    }

    [TestMethod]
    [DataRow(typeof(Kartova.Catalog.Infrastructure.CatalogDbContext))]
    [DataRow(typeof(Kartova.Organization.Infrastructure.OrganizationDbContext))]
    public void Tenant_scoped_DbContexts_are_registered_as_scoped(Type dbContextType)
    {
        var services = BuildContainer();

        var descriptor = services.SingleOrDefault(d => d.ServiceType == dbContextType);

        Assert.IsNotNull(descriptor, $"{dbContextType.Name} is registered by its module's RegisterServices");
        Assert.AreEqual(
            ServiceLifetime.Scoped,
            descriptor!.Lifetime,
            $"{dbContextType.Name} resolves its connection from ITenantScope; " +
            "singleton/transient would either share state across tenants or open extra connections " +
            "outside the request scope (ADR-0090)");
    }

    private static IServiceCollection BuildContainer()
    {
        var configuration = new ConfigurationBuilder()
            .AddInMemoryCollection(new Dictionary<string, string?>
            {
                [AuthenticationConfigKeys.Authority] = "https://keycloak.example.com/realms/kartova",
                [AuthenticationConfigKeys.Audience] = "kartova-api",
                [AuthenticationConfigKeys.RequireHttpsMetadata] = "false",
                ["ConnectionStrings:Main"] = "Host=localhost;Database=test;Username=test;Password=test",
                ["ConnectionStrings:Bypass"] = "Host=localhost;Database=test;Username=test;Password=test",
            })
            .Build();

        var services = new ServiceCollection();
        services.AddLogging();
        services.AddNpgsqlDataSource(configuration.GetConnectionString("Main")!);
        services.AddTenantScope();
        services.AddKartovaJwtAuth(configuration);

        foreach (var module in DiscoverModules())
        {
            module.RegisterServices(services, configuration);
        }

        return services;
    }

    private static IEnumerable<IModule> DiscoverModules() =>
        AssemblyRegistry.AllProduction()
            .SelectMany(a => a.GetTypes())
            .Where(t => !t.IsAbstract && typeof(IModule).IsAssignableFrom(t))
            .Select(t => (IModule)Activator.CreateInstance(t)!);
}

using System.Diagnostics.CodeAnalysis;
using Kartova.SharedKernel.AspNetCore;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.RateLimiting;
using Microsoft.AspNetCore.Routing;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.DependencyInjection.Extensions;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Pins the HTTP route surface declared by every <see cref="IModuleEndpoints"/>
/// implementation in the solution. Resolves slice-3 spec §13.9.
///
/// The mutation report's parallel from slice-2 showed `MapGet(...)` mutated to
/// `;` survives — the endpoint disappears and no test catches it. The hard
/// inventory check below kills that mutant for every module's named routes; the
/// soft "every endpoint has a name" guard catches accidental drops on routes
/// that don't yet appear in the inventory.
/// </summary>
[ExcludeFromCodeCoverage]
[TestClass]
public class EndpointRouteRules
{
    private const string Get = "GET";
    private const string Post = "POST";
    private const string Put = "PUT";

    /// <summary>
    /// The single source of truth for what HTTP routes the API must expose.
    /// Every entry here is asserted against the live <see cref="EndpointDataSource"/>;
    /// missing entries fail the test, extra entries are allowed (covered by the
    /// "every endpoint has a name" guard so they can't drift unnamed).
    /// </summary>
    private static readonly EndpointFingerprint[] ExpectedEndpoints =
    [
        // Catalog (ADR-0092 module-prefixed URL convention)
        new("RegisterApplication",         Post, "/api/v1/catalog/applications"),
        new("GetApplicationById",          Get,  "/api/v1/catalog/applications/{id:guid}"),
        new("ListApplications",            Get,  "/api/v1/catalog/applications"),
        new("EditApplication",             Put,  "/api/v1/catalog/applications/{id:guid}"),
        new("DeprecateApplication",        Post, "/api/v1/catalog/applications/{id:guid}/deprecate"),
        new("DecommissionApplication",     Post, "/api/v1/catalog/applications/{id:guid}/decommission"),

        // Organization (slug doubles as the primary collection per ADR-0092 skip rule)
        new("GetOrganizationMe",           Get,  "/api/v1/organizations/me"),
        new("GetOrganizationMeAdminOnly",  Get,  "/api/v1/organizations/me/admin-only"),

        // Organization admin (BYPASSRLS, separate auth surface, same slug)
        new("AdminCreateOrganization",     Post, "/api/v1/admin/organizations/"),

        // Invitation accept — anonymous, tenant-less (slice 9, task 8)
        new("GetInvitationAcceptContext",  Get,  "/api/v1/invitations/accept"),
        new("AcceptInvitation",            Post, "/api/v1/invitations/accept"),
    ];

    [TestMethod]
    public void Every_expected_endpoint_is_registered_with_correct_verb_and_template()
    {
        var actual = MapEndpointsForArchTest();

        foreach (var expected in ExpectedEndpoints)
        {
            var match = actual.SingleOrDefault(e =>
                string.Equals(e.Name, expected.Name, StringComparison.Ordinal));

            Assert.IsNotNull(
                match,
                $"named route '{expected.Name}' must exist — kills `MapGet(...)` → `;` style mutants");
            Assert.AreEqual(
                expected.HttpMethod,
                match!.HttpMethod,
                $"named route '{expected.Name}' must keep its HTTP method");
            Assert.AreEqual(
                expected.Template,
                match.Template,
                $"named route '{expected.Name}' must keep its URL template (ADR-0092)");
        }
    }

    [TestMethod]
    public void Every_module_endpoint_has_a_route_name()
    {
        var actual = MapEndpointsForArchTest();

        var unnamed = actual.Where(e => string.IsNullOrEmpty(e.Name)).ToArray();

        Assert.AreEqual(
            0,
            unnamed.Length,
            "every endpoint mapped via IModuleEndpoints.MapEndpoints must call .WithName(...) " +
            "so the route inventory in EndpointRouteRules can pin verb+template+name. " +
            "Unnamed endpoints (count: " + unnamed.Length + "): " +
            string.Join(", ", unnamed.Select(e => $"{e.HttpMethod} {e.Template}")));
    }

    [TestMethod]
    public void Route_names_are_unique_across_modules()
    {
        var actual = MapEndpointsForArchTest();

        var duplicates = actual
            .Where(e => !string.IsNullOrEmpty(e.Name))
            .GroupBy(e => e.Name)
            .Where(g => g.Count() > 1)
            .Select(g => g.Key)
            .ToArray();

        Assert.AreEqual(
            0,
            duplicates.Length,
            "route names are used as link-relation identifiers and must be unique across the API. " +
            "Duplicates: " + string.Join(", ", duplicates));
    }

    /// <summary>
    /// Boots a minimal <see cref="WebApplication"/> with just enough services
    /// to make <see cref="IEndpointRouteBuilder"/>-based mapping succeed
    /// (auth/authz are required by <see cref="ModuleRouteExtensions.MapAdminModule"/>),
    /// instantiates every <see cref="IModuleEndpoints"/> implementation found
    /// in production assemblies via parameterless ctor, calls <c>MapEndpoints</c>,
    /// and snapshots the resulting <see cref="EndpointDataSource"/>.
    /// </summary>
    private static List<EndpointFingerprint> MapEndpointsForArchTest()
    {
        var builder = WebApplication.CreateBuilder();
        // Auth / authz must be present because MapAdminModule calls RequireAuthorization;
        // we don't need a working JWT pipeline, just a valid scheme registration.
        builder.Services.AddAuthentication("Test").AddJwtBearer("Test", _ => { });
        builder.Services.AddAuthorization();
        builder.Services.AddRouting();
        // Rate limiter must be present because InvitationAcceptRoutes calls RequireRateLimiting.
        builder.Services.AddRateLimiter(_ => { });

        // The endpoint delegates take handler/DbContext/abstraction parameters that
        // RequestDelegateFactory must classify as [FromServices] rather than [FromBody].
        // RDF asks the IServiceProviderIsService whether a type is registered; without
        // a real DI graph we'd have to register every single handler/DbContext just to
        // make the metadata inference pass. Instead, override the marker so any reference
        // type is treated as a service. This only affects the arch-test composition root —
        // production wires types through actual registrations.
        // Register stub services for every reference type referenced by an endpoint
        // delegate parameter. RequestDelegateFactory uses IServiceProviderIsService —
        // backed by ServiceProviderEngine — to decide [FromServices] vs [FromBody].
        // Without registrations the binder treats handler/DbContext parameters as bodies
        // and fails on "multiple bodies". Stubbing them as null factories makes the
        // service-marker positive without requiring real DI graphs.
        foreach (var type in DiscoverEndpointDelegateServiceTypes())
        {
            builder.Services.AddTransient(type, _ => null!);
        }

        var app = builder.Build();

        foreach (var moduleType in DiscoverModuleEndpointsTypes())
        {
            var module = (IModuleEndpoints)Activator.CreateInstance(moduleType)!;
            module.MapEndpoints(app);
        }

        return ((IEndpointRouteBuilder)app).DataSources
            .SelectMany(ds => ds.Endpoints)
            .OfType<RouteEndpoint>()
            .Select(e => new EndpointFingerprint(
                Name: e.Metadata.GetMetadata<IEndpointNameMetadata>()?.EndpointName ?? string.Empty,
                HttpMethod: e.Metadata.GetMetadata<HttpMethodMetadata>()?.HttpMethods.SingleOrDefault() ?? string.Empty,
                Template: e.RoutePattern.RawText ?? string.Empty))
            .ToList();
    }

    private static IEnumerable<Type> DiscoverModuleEndpointsTypes() =>
        AssemblyRegistry.AllProduction()
            .SelectMany(a => a.GetTypes())
            .Where(t => !t.IsAbstract && typeof(IModuleEndpoints).IsAssignableFrom(t))
            .Where(t => t.GetConstructor(Type.EmptyTypes) is not null);

    /// <summary>
    /// Finds every reference-type parameter on every static endpoint delegate
    /// referenced by any <c>*EndpointDelegates</c> class in production assemblies.
    /// Registering each as a null-factory transient makes
    /// <see cref="IServiceProviderIsService.IsService"/> return true so RDF binds
    /// them as <c>[FromServices]</c> rather than failing inference.
    /// </summary>
    private static IEnumerable<Type> DiscoverEndpointDelegateServiceTypes()
    {
        var seen = new HashSet<Type>();
        foreach (var assembly in AssemblyRegistry.AllProduction())
        {
            foreach (var type in assembly.GetTypes())
            {
                if (!type.Name.EndsWith("EndpointDelegates", StringComparison.Ordinal)
                    && !type.Name.EndsWith("Routes", StringComparison.Ordinal)) continue;
                foreach (var method in type.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static))
                {
                    foreach (var p in method.GetParameters())
                    {
                        var pt = p.ParameterType;
                        if (pt.IsValueType) continue;
                        if (pt == typeof(string)) continue;
                        if (pt == typeof(CancellationToken)) continue;
                        if (pt.Namespace?.StartsWith("Microsoft.AspNetCore", StringComparison.Ordinal) == true) continue;
                        // Skip [FromBody] request types — they should NOT be treated as services.
                        if (p.GetCustomAttributes(typeof(Microsoft.AspNetCore.Mvc.FromBodyAttribute), inherit: false).Length > 0) continue;
                        if (seen.Add(pt)) yield return pt;
                    }
                }
            }
        }
    }

    private sealed record EndpointFingerprint(string Name, string HttpMethod, string Template);
}

using NetArchTest.Rules;

namespace Kartova.ArchitectureTests;

[TestClass]
public class ForbiddenDependencyTests
{
    [TestMethod]
    public void No_Module_References_MediatR()
    {
        foreach (var assembly in AssemblyRegistry.AllProduction())
        {
            var result = Types.InAssembly(assembly)
                .Should()
                .NotHaveDependencyOn("MediatR")
                .GetResult();

            Assert.IsTrue(
                result.IsSuccessful,
                $"MediatR is not used per ADR-0080; assembly {assembly.GetName().Name} should route through Wolverine IMessageBus. " +
                $"Violating types: {string.Join(", ", result.FailingTypeNames ?? [])}");
        }
    }

    [TestMethod]
    public void No_Module_References_MassTransit()
    {
        foreach (var assembly in AssemblyRegistry.AllProduction())
        {
            var result = Types.InAssembly(assembly)
                .Should()
                .NotHaveDependencyOn("MassTransit")
                .GetResult();

            Assert.IsTrue(
                result.IsSuccessful,
                $"MassTransit is not used per ADR-0003/ADR-0080; Kafka is Wolverine (outbound) + KafkaFlow (inbound). " +
                $"Violating types in {assembly.GetName().Name}: {string.Join(", ", result.FailingTypeNames ?? [])}");
        }
    }
}

using System.Text.RegularExpressions;
using Kartova.SharedKernel;
using Kartova.SharedKernel.AspNetCore;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Reflection-based pin for the <see cref="IModule"/> URL convention (ADR-0092):
/// every module declares a non-empty, lowercase kebab-case <c>Slug</c>, and every
/// module that participates in DI also exposes endpoints via <see cref="IModuleEndpoints"/>.
/// </summary>
[TestClass]
public class IModuleRules
{
    private static readonly Regex KebabCase = new("^[a-z][a-z0-9-]*$", RegexOptions.Compiled);

    [TestMethod]
    public void Every_IModule_implementation_declares_non_empty_Slug()
    {
        foreach (var t in AllModuleTypes())
        {
            var module = (IModule)Activator.CreateInstance(t)!;
            Assert.IsFalse(
                string.IsNullOrWhiteSpace(module.Slug),
                $"{t.FullName} must declare a non-empty Slug per ADR-0092");
        }
    }

    [TestMethod]
    public void Every_IModule_Slug_is_lowercase_kebab_case()
    {
        foreach (var t in AllModuleTypes())
        {
            var module = (IModule)Activator.CreateInstance(t)!;
            Assert.IsTrue(
                KebabCase.IsMatch(module.Slug),
                $"{t.FullName}.Slug='{module.Slug}' must match ^[a-z][a-z0-9-]*$ per ADR-0092");
        }
    }

    [TestMethod]
    public void Every_IModule_implementation_also_implements_IModuleEndpoints()
    {
        foreach (var t in AllModuleTypes())
        {
            Assert.IsTrue(
                typeof(IModuleEndpoints).IsAssignableFrom(t),
                $"{t.FullName} implements IModule and must also implement IModuleEndpoints " +
                "so the API composition root can map its routes (ADR-0092)");
        }
    }

    private static IEnumerable<Type> AllModuleTypes() =>
        AssemblyRegistry.AllProduction()
            .SelectMany(a => a.GetTypes())
            .Where(t => !t.IsAbstract && typeof(IModule).IsAssignableFrom(t));
}

using System.IO;
using System.Reflection;
using System.Text.Json;
using Kartova.SharedKernel.Multitenancy;

namespace Kartova.ArchitectureTests;

[TestClass]
public sealed class KartovaPermissionsRules
{
    [TestMethod]
    public void All_collection_contains_every_public_string_constant()
    {
        var declared = typeof(KartovaPermissions)
            .GetFields(BindingFlags.Public | BindingFlags.Static | BindingFlags.FlattenHierarchy)
            .Where(f => f.IsLiteral && f.FieldType == typeof(string))
            .Select(f => (string)f.GetRawConstantValue()!)
            .ToHashSet(StringComparer.Ordinal);

        foreach (var v in declared)
        {
            Assert.IsTrue(KartovaPermissions.All.Contains(v),
                $"KartovaPermissions.All must list every declared constant — missing '{v}'.");
        }

        Assert.AreEqual(declared.Count, KartovaPermissions.All.Count,
            "KartovaPermissions.All must not contain entries that are not declared as constants.");
    }

    [TestMethod]
    public void Every_permission_appears_in_at_least_one_role_set()
    {
        var permissionsInUse = KartovaRolePermissions.Map
            .SelectMany(kvp => kvp.Value)
            .ToHashSet(StringComparer.Ordinal);

        foreach (var perm in KartovaPermissions.All)
        {
            Assert.IsTrue(permissionsInUse.Contains(perm),
                $"Orphan permission '{perm}' — not granted to any role in KartovaRolePermissions.Map.");
        }
    }

    [TestMethod]
    public void Every_mapped_value_is_a_known_permission()
    {
        var declared = new HashSet<string>(KartovaPermissions.All, StringComparer.Ordinal);

        foreach (var (role, perms) in KartovaRolePermissions.Map)
        {
            foreach (var perm in perms)
            {
                Assert.IsTrue(declared.Contains(perm),
                    $"Role {role} grants unknown permission '{perm}' — not declared in KartovaPermissions.");
            }
        }
    }

    [TestMethod]
    public void Every_map_key_is_a_known_role()
    {
        var declaredRoles = typeof(KartovaRoles)
            .GetFields(BindingFlags.Public | BindingFlags.Static | BindingFlags.FlattenHierarchy)
            .Where(f => f.IsLiteral && f.FieldType == typeof(string))
            .Select(f => (string)f.GetRawConstantValue()!)
            .ToHashSet(StringComparer.Ordinal);

        foreach (var role in KartovaRolePermissions.Map.Keys)
        {
            Assert.IsTrue(declaredRoles.Contains(role),
                $"Map key '{role}' is not declared in KartovaRoles.");
        }
    }

    [TestMethod]
    public void Ts_snapshot_equals_csharp_KartovaPermissions_All()
    {
        var snapshotPath = FindRepoFile("web/src/shared/auth/permissions.snapshot.json");
        Assert.IsTrue(File.Exists(snapshotPath),
            $"Drift sentinel missing: {snapshotPath}. The TS side must commit a JSON list of permission names.");

        using var doc = JsonDocument.Parse(File.ReadAllText(snapshotPath));
        var snapshot = doc.RootElement.EnumerateArray()
                                      .Select(e => e.GetString()!)
                                      .ToHashSet(StringComparer.Ordinal);

        CollectionAssert.AreEquivalent(
            KartovaPermissions.All.ToList(),
            snapshot.ToList(),
            "TS permissions.snapshot.json must match C# KartovaPermissions.All exactly.");
    }

    [TestMethod]
    public void Team_permissions_are_present_in_KartovaPermissions_All()
    {
        string[] expected = ["team.read", "team.create"];
        foreach (var perm in expected)
            Assert.IsTrue(KartovaPermissions.All.Contains(perm), $"missing: {perm}");
    }

    [TestMethod]
    [DataRow(KartovaRoles.Viewer,   new[] { "team.read" })]
    [DataRow(KartovaRoles.Member,   new[] { "team.read" })]
    [DataRow(KartovaRoles.OrgAdmin, new[] { "team.read", "team.create" })]
    public void Role_permissions_include_team_perms(string role, string[] requiredPerms)
    {
        Assert.IsTrue(KartovaRolePermissions.Map.TryGetValue(role, out var perms), $"role missing: {role}");
        foreach (var p in requiredPerms)
            Assert.IsTrue(perms.Contains(p), $"role {role} missing perm {p}");
    }

    private static string FindRepoFile(string relativePath)
    {
        var dir = new DirectoryInfo(Directory.GetCurrentDirectory());
        while (dir != null && !File.Exists(Path.Combine(dir.FullName, "Kartova.slnx")))
        {
            dir = dir.Parent;
        }
        if (dir is null) throw new InvalidOperationException("Kartova.slnx not found walking up from current directory.");
        return Path.Combine(dir.FullName, relativePath.Replace('/', Path.DirectorySeparatorChar));
    }
}

using System.IO;
using System.Linq;
using System.Reflection;
using System.Text.Json;
using Kartova.SharedKernel.Multitenancy;

namespace Kartova.ArchitectureTests;

[TestClass]
public sealed class KeycloakRealmSeedRules
{
    private static readonly string SeedPath =
        Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "..", "..",
            "deploy", "keycloak", "kartova-realm.json");

    [TestMethod]
    public void RealmSeed_RegistersKartovaWebPublicClientWithPkce()
    {
        Assert.IsTrue(File.Exists(SeedPath), $"realm seed not found at {SeedPath}");

        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));
        var clients = doc.RootElement.GetProperty("clients");
        var web = clients.EnumerateArray()
            .FirstOrDefault(c => c.GetProperty("clientId").GetString() == "kartova-web");

        Assert.AreNotEqual(
            JsonValueKind.Undefined,
            web.ValueKind,
            "slice-4 spec §4.5 requires a kartova-web public client.");

        Assert.IsTrue(web.GetProperty("publicClient").GetBoolean());
        Assert.IsTrue(web.GetProperty("standardFlowEnabled").GetBoolean());
        Assert.IsFalse(
            web.GetProperty("directAccessGrantsEnabled").GetBoolean(),
            "password grant is forbidden — PKCE only.");

        var attrs = web.GetProperty("attributes");
        Assert.AreEqual(
            "S256",
            attrs.GetProperty("pkce.code.challenge.method").GetString());
        Assert.AreEqual(
            "900",
            attrs.GetProperty("access.token.lifespan").GetString(),
            "SPA access tokens must remain short-lived (15 min) per slice-4 §4.5.");

        var redirects = web.GetProperty("redirectUris").EnumerateArray()
            .Select(e => e.GetString()).ToList();
        CollectionAssert.Contains(redirects, "http://localhost:5173/callback");
        CollectionAssert.Contains(redirects, "http://localhost:5173/silent-callback");
        // 4173 = the E2E web container origin (ADR-0113); the dev-server 5173 stays.
        CollectionAssert.Contains(redirects, "http://localhost:4173/callback");
        CollectionAssert.Contains(redirects, "http://localhost:4173/silent-callback");

        var origins = web.GetProperty("webOrigins").EnumerateArray()
            .Select(e => e.GetString()).ToList();
        // Exact set (not Contains) so an UNINTENDED origin still fails this guard.
        // 5173 = vite dev server; 4173 = the E2E rootless web container (ADR-0113).
        CollectionAssert.AreEquivalent(
            new[] { "http://localhost:5173", "http://localhost:4173" },
            origins,
            "additional web origins would silently widen CORS for kartova-web tokens.");
    }

    [TestMethod]
    public void KartovaWebClient_ProjectsAudienceMapperToKartovaApi()
    {
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));
        var web = doc.RootElement.GetProperty("clients").EnumerateArray()
            .First(c => c.GetProperty("clientId").GetString() == "kartova-web");

        var mappers = web.GetProperty("protocolMappers").EnumerateArray().ToList();
        var audience = mappers.FirstOrDefault(m =>
            m.GetProperty("protocolMapper").GetString() == "oidc-audience-mapper");
        Assert.AreNotEqual(
            JsonValueKind.Undefined,
            audience.ValueKind,
            "kartova-web tokens must include kartova-api as audience so the API JWT validator accepts them.");
        Assert.AreEqual(
            "kartova-api",
            audience.GetProperty("config").GetProperty("included.client.audience").GetString());
    }

    [TestMethod]
    public void KartovaWebClient_IncludesTenantIdProtocolMapper()
    {
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));
        var web = doc.RootElement.GetProperty("clients").EnumerateArray()
            .First(c => c.GetProperty("clientId").GetString() == "kartova-web");

        var mappers = web.GetProperty("protocolMappers").EnumerateArray().ToList();
        var tenantIdMapper = mappers.FirstOrDefault(m =>
            m.GetProperty("name").GetString() == "tenant_id" &&
            m.GetProperty("protocolMapper").GetString() == "oidc-usermodel-attribute-mapper");
        Assert.AreNotEqual(
            JsonValueKind.Undefined,
            tenantIdMapper.ValueKind,
            "kartova-web tokens must carry the tenant_id claim, same as kartova-api.");
        Assert.AreEqual(
            "tenant_id",
            tenantIdMapper.GetProperty("config").GetProperty("claim.name").GetString());
    }

    [TestMethod]
    public void Realm_seed_includes_Viewer_role_excludes_TeamAdmin_role_and_includes_dev_users()
    {
        Assert.IsTrue(File.Exists(SeedPath), $"realm seed not found at {SeedPath}");
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));

        var roles = doc.RootElement
            .GetProperty("roles")
            .GetProperty("realm")
            .EnumerateArray()
            .Select(r => r.GetProperty("name").GetString())
            .ToHashSet(StringComparer.Ordinal);

        Assert.IsTrue(roles.Contains("Viewer"), "Realm must include 'Viewer' role.");
        Assert.IsFalse(roles.Contains("TeamAdmin"), "TeamAdmin realm role was removed in ADR-0101.");

        var usernames = doc.RootElement
            .GetProperty("users")
            .EnumerateArray()
            .Select(u => u.GetProperty("username").GetString())
            .ToHashSet(StringComparer.Ordinal);

        Assert.IsTrue(usernames.Contains("viewer@orga.kartova.local"),
            "Realm must include a 'viewer@orga' dev user.");
        Assert.IsTrue(usernames.Contains("team-admin@orga.kartova.local"),
            "Realm must include a 'team-admin@orga' dev user (now a realm Member, team Admin via membership).");
    }

    [TestMethod]
    public void Every_KartovaRoles_constant_except_ServiceAccount_appears_in_realm_seed()
    {
        Assert.IsTrue(File.Exists(SeedPath), $"realm seed not found at {SeedPath}");
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));

        var realmRoles = doc.RootElement.GetProperty("roles").GetProperty("realm")
            .EnumerateArray()
            .Select(r => r.GetProperty("name").GetString()!)
            .ToHashSet(StringComparer.Ordinal);

        var constantValues = typeof(KartovaRoles)
            .GetFields(BindingFlags.Public | BindingFlags.Static | BindingFlags.FlattenHierarchy)
            .Where(f => f.IsLiteral && f.FieldType == typeof(string))
            .Select(f => (Name: f.Name, Value: (string)f.GetRawConstantValue()!))
            .Where(t => t.Name != nameof(KartovaRoles.ServiceAccount))
            .ToArray();

        foreach (var (name, value) in constantValues)
        {
            Assert.IsTrue(realmRoles.Contains(value),
                $"KartovaRoles.{name} = '{value}' has no matching entry in kartova-realm.json roles.realm.");
        }
    }

    [TestMethod]
    public void Every_role_in_KartovaRolePermissions_Map_has_at_least_one_dev_user()
    {
        Assert.IsTrue(File.Exists(SeedPath), $"realm seed not found at {SeedPath}");
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));

        // Group dev users by the roles they hold.
        var usersByRole = new Dictionary<string, List<string>>(StringComparer.Ordinal);
        foreach (var user in doc.RootElement.GetProperty("users").EnumerateArray())
        {
            var username = user.GetProperty("username").GetString()!;
            if (!user.TryGetProperty("realmRoles", out var rolesProp)) continue;
            foreach (var roleElem in rolesProp.EnumerateArray())
            {
                var role = roleElem.GetString();
                if (string.IsNullOrEmpty(role)) continue;
                if (!usersByRole.TryGetValue(role, out var list))
                {
                    list = new List<string>();
                    usersByRole[role] = list;
                }
                list.Add(username);
            }
        }

        foreach (var role in KartovaRolePermissions.Map.Keys)
        {
            Assert.IsTrue(usersByRole.ContainsKey(role) && usersByRole[role].Count > 0,
                $"Role '{role}' in KartovaRolePermissions.Map must have at least one dev user in kartova-realm.json.");
        }
    }

    /// <summary>
    /// Slice-9 carry-forward #14: drift sentinel for the <c>kartova-admin</c> service-account
    /// client used by <c>KeycloakAdminClient</c> to provision invited users. If anyone disables
    /// service accounts, re-enables the password grant, or flips the client to public, the
    /// admin REST flow breaks silently — this test catches it at CI time.
    /// </summary>
    [TestMethod]
    public void RealmSeed_RegistersKartovaAdminClientWithServiceAccount()
    {
        Assert.IsTrue(File.Exists(SeedPath), $"realm seed not found at {SeedPath}");

        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));
        var admin = doc.RootElement.GetProperty("clients").EnumerateArray()
            .FirstOrDefault(c => c.GetProperty("clientId").GetString() == "kartova-admin");

        Assert.AreNotEqual(
            JsonValueKind.Undefined,
            admin.ValueKind,
            "slice-9 §6.7 requires a kartova-admin service-account client for invitation provisioning.");

        Assert.IsFalse(
            admin.GetProperty("publicClient").GetBoolean(),
            "kartova-admin must be a confidential client — it holds an admin secret.");
        Assert.IsTrue(
            admin.GetProperty("serviceAccountsEnabled").GetBoolean(),
            "kartova-admin must have serviceAccountsEnabled — client-credentials flow is the only allowed mechanism.");
        Assert.IsFalse(
            admin.GetProperty("directAccessGrantsEnabled").GetBoolean(),
            "kartova-admin must NOT have password grant enabled — confidential service-account only.");
        Assert.IsFalse(
            admin.GetProperty("standardFlowEnabled").GetBoolean(),
            "kartova-admin is not a user-facing OIDC client — standard flow must be disabled.");

        Assert.AreEqual(
            "admin-dev-secret",
            admin.GetProperty("secret").GetString(),
            "kartova-admin secret must match RealmSeedConstants.AdminClientSecret (test fixtures rely on it).");
    }

    /// <summary>
    /// Slice-9 carry-forward #14: the <c>kartova-admin</c> service-account user must hold the
    /// <c>realm-management</c> client roles required by <see cref="Kartova.SharedKernel.Identity.IKeycloakAdminClient"/>
    /// (create / search / delete users + assign realm roles). Without these the client gets
    /// 403 on every admin REST call and invitation acceptance silently fails.
    /// </summary>
    [TestMethod]
    public void KartovaAdmin_service_account_has_realm_management_admin_role()
    {
        using var doc = JsonDocument.Parse(File.ReadAllText(SeedPath));

        var serviceAccountUser = doc.RootElement.GetProperty("users").EnumerateArray()
            .FirstOrDefault(u => u.TryGetProperty("serviceAccountClientId", out var sac)
                                  && sac.GetString() == "kartova-admin");

        Assert.AreNotEqual(
            JsonValueKind.Undefined,
            serviceAccountUser.ValueKind,
            "kartova-admin must have a corresponding service-account user (Keycloak convention: " +
            "users[].serviceAccountClientId == 'kartova-admin').");

        Assert.IsTrue(
            serviceAccountUser.TryGetProperty("clientRoles", out var clientRoles),
            "kartova-admin service-account user must declare clientRoles for realm-management.");
        Assert.IsTrue(
            clientRoles.TryGetProperty("realm-management", out var realmMgmt),
            "kartova-admin service-account user must hold roles from the realm-management client.");

        var roles = realmMgmt.EnumerateArray()
            .Select(r => r.GetString())
            .Where(s => !string.IsNullOrEmpty(s))
            .ToHashSet(StringComparer.Ordinal);

        // KeycloakAdminClient calls CreateUser, SearchUsers, DeleteUser, AssignRealmRole.
        // manage-users covers create + delete + role assignment; view-users covers search.
        Assert.IsTrue(
            roles.Contains("manage-users"),
            "kartova-admin needs realm-management:manage-users (create/delete users, assign roles).");
        Assert.IsTrue(
            roles.Contains("view-users"),
            "kartova-admin needs realm-management:view-users (search users by email/query).");
    }
}

using System.Diagnostics.CodeAnalysis;
using Kartova.Catalog.Domain;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Pins the Lifecycle enum's persisted-value stability. The numeric values
/// (1=Active, 2=Deprecated, 3=Decommissioned) are stored in the
/// <c>lifecycle smallint</c> column on <c>catalog.applications</c> — reordering
/// or renumbering would silently corrupt rows already on disk. Linear ordering
/// is also pinned so future SQL filters (<c>WHERE lifecycle &gt;= :x</c>) can
/// rely on monotonic numeric values.
/// </summary>
[ExcludeFromCodeCoverage]
[TestClass]
public class LifecycleEnumRules
{
    // MSTEST0032 (assertion always true) is a false positive here: the analyzer correctly
    // sees these as compile-time-constant comparisons, but that is precisely the point of
    // a pinning test — if a future edit renumbers the enum, the constant changes and the
    // assertion flips to "always false". The runtime assertion guards the on-disk schema
    // contract documented in the class summary. We deliberately do NOT rewrite via
    // reflection to defeat the analyzer: that would lose the compile-time re-binding that
    // makes this test fail at the next edit of Lifecycle, near the change site.
#pragma warning disable MSTEST0032
    [TestMethod]
    public void Lifecycle_has_exactly_three_members_with_explicit_values()
    {
        Assert.AreEqual(3, Enum.GetValues<Lifecycle>().Length);

        Assert.AreEqual(1, (int)Lifecycle.Active);
        Assert.AreEqual(2, (int)Lifecycle.Deprecated);
        Assert.AreEqual(3, (int)Lifecycle.Decommissioned);
    }

    [TestMethod]
    public void Lifecycle_members_are_linearly_ordered()
    {
        Assert.IsTrue((int)Lifecycle.Active < (int)Lifecycle.Deprecated);
        Assert.IsTrue((int)Lifecycle.Deprecated < (int)Lifecycle.Decommissioned);
    }
#pragma warning restore MSTEST0032
}

