using NetArchTest.Rules;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Enforces ADR-0095 §8: every <c>List*Handler</c> in any module's
/// <c>*.Infrastructure</c> assembly must return <c>Task&lt;CursorPage&lt;T&gt;&gt;</c>,
/// unless the handler class is decorated with <c>[BoundedListResult]</c>.
/// </summary>
[TestClass]
public sealed class PaginationConventionRules
{
    [TestMethod]
    public void List_handlers_in_infrastructure_assemblies_return_CursorPage_or_are_BoundedListResult()
    {
        var infraAssemblies = AssemblyRegistry.AllInfrastructureAssemblies();

        foreach (var asm in infraAssemblies)
        {
            var listHandlers = Types.InAssembly(asm)
                .That()
                .HaveNameMatching(@"^List.*Handler$")
                .And().AreClasses()
                .GetTypes()
                .ToList();

            foreach (var t in listHandlers)
            {
                var bounded = t.GetCustomAttributes(typeof(BoundedListResultAttribute), inherit: false)
                    .Cast<BoundedListResultAttribute>()
                    .FirstOrDefault();

                if (bounded is not null)
                {
                    Assert.IsFalse(
                        string.IsNullOrWhiteSpace(bounded.Reason),
                        $"{t.FullName} is [BoundedListResult] — reason must be set");
                    continue;
                }

                var handle = t.GetMethod("Handle")
                    ?? throw new InvalidOperationException($"{t.FullName} has no Handle method");
                var ret = handle.ReturnType;

                Assert.IsTrue(
                    ret.IsGenericType,
                    $"{t.FullName}.Handle must return Task<CursorPage<...>> per ADR-0095");
                Assert.AreEqual(
                    typeof(Task<>),
                    ret.GetGenericTypeDefinition(),
                    $"{t.FullName}.Handle must return Task<CursorPage<...>> per ADR-0095");
                var inner = ret.GetGenericArguments()[0];
                Assert.IsTrue(
                    inner.IsGenericType,
                    $"{t.FullName}.Handle must return Task<CursorPage<...>> per ADR-0095");
                Assert.AreEqual(
                    typeof(CursorPage<>),
                    inner.GetGenericTypeDefinition(),
                    $"{t.FullName}.Handle returns {ret} — must be Task<CursorPage<...>> per ADR-0095, " +
                    "or annotate the class with [BoundedListResult(reason: \"...\")]");
            }
        }
    }
}

using System.Text.RegularExpressions;

namespace Kartova.ArchitectureTests;

/// <summary>
/// ADR-0091: every HTTP error response uses RFC 7807 <c>application/problem+json</c>
/// via <c>Results.Problem(...)</c>. The ADR's Implementation Notes section calls for
/// an architecture test that prevents ad-hoc <c>{ error = ... }</c> body shapes from
/// landing.
///
/// Implementation: source-text scan of <c>src/</c>. Regex-based, so it catches the
/// common shapes (<c>Results.Json(new { error ...</c>, <c>Results.Ok(new { error ...</c>,
/// <c>Results.BadRequest(new { error ...</c>) but is bypassable by reformatting or
/// extracting to a variable. That is a deliberate trade-off — a Roslyn analyzer would
/// catch every shape but adds a heavy compile-time dependency. The text scan covers
/// the realistic accident path; reviewers handle the rest.
/// </summary>
[TestClass]
public class ProblemDetailsConventionRules
{
    [TestMethod]
    public void Source_does_not_emit_ad_hoc_error_shapes_per_ADR_0091()
    {
        var srcDir = LocateSrcDir();
        Assert.IsTrue(
            Directory.Exists(srcDir),
            $"expected to locate the project's src directory at {srcDir}");

        var offenders = new List<string>();
        foreach (var file in EnumerateProductionSources(srcDir))
        {
            var content = File.ReadAllText(file);
            foreach (var (description, pattern) in ForbiddenPatterns())
            {
                if (pattern.IsMatch(content))
                {
                    offenders.Add($"{ToRelativePath(srcDir, file)}: {description}");
                }
            }
        }

        Assert.AreEqual(
            0,
            offenders.Count,
            "ADR-0091 requires error responses to use Results.Problem(...) with a type from " +
            "ProblemTypes — not ad-hoc anonymous-error shapes. Offending source: " +
            string.Join("; ", offenders));
    }

    /// <summary>
    /// Self-test: verifies each forbidden-shape regex actually matches a known-bad
    /// string. Without this, a regex that accidentally matches nothing would let the
    /// production scan pass while silently providing no protection.
    /// </summary>
    [TestMethod]
    [DataRow("Results.Json(new { error = \"x\" })")]
    [DataRow("Results . Json ( new { error = \"x\" } )")]
    [DataRow("Results.Json(new {\n            error = \"x\"\n        })")]
    [DataRow("Results.Ok(new { error = \"x\" })")]
    [DataRow("Results.BadRequest(new { error = \"x\" })")]
    [DataRow("Results.Conflict(new { error = \"x\" })")]
    [DataRow("Results.UnprocessableEntity(new { error = \"x\" })")]
    public void Forbidden_patterns_match_known_bad_shapes(string sample)
    {
        var anyMatched = ForbiddenPatterns().Any(p => p.Pattern.IsMatch(sample));
        Assert.IsTrue(
            anyMatched,
            $"the production scan must catch this shape: '{sample}'");
    }

    /// <summary>
    /// Counter-test: legitimate <c>Results.Problem(...)</c> and <c>Results.Json(dto, statusCode: 201)</c>
    /// shapes must not trigger the forbidden-shape rule.
    /// </summary>
    [TestMethod]
    [DataRow("Results.Problem(type: ProblemTypes.ValidationFailed, statusCode: 400)")]
    [DataRow("Results.Json(org, statusCode: StatusCodes.Status201Created)")]
    [DataRow("Results.Ok(dto)")]
    [DataRow("Results.Created(\"/api/v1/organizations/abc\", org)")]
    public void Forbidden_patterns_do_not_match_legitimate_shapes(string sample)
    {
        var anyMatched = ForbiddenPatterns().Any(p => p.Pattern.IsMatch(sample));
        Assert.IsFalse(
            anyMatched,
            $"this shape is ADR-0091-compliant and must not flag: '{sample}'");
    }

    private static (string Description, Regex Pattern)[] ForbiddenPatterns() => new (string, Regex)[]
    {
        ("Results.Json(new { error ... })",
            new Regex(@"Results\s*\.\s*Json\s*\(\s*new\s*\{\s*error\b", RegexOptions.Compiled | RegexOptions.Singleline)),
        ("Results.Ok(new { error ... })",
            new Regex(@"Results\s*\.\s*Ok\s*\(\s*new\s*\{\s*error\b", RegexOptions.Compiled | RegexOptions.Singleline)),
        ("Results.BadRequest(new { error ... })",
            new Regex(@"Results\s*\.\s*BadRequest\s*\(\s*new\s*\{\s*error\b", RegexOptions.Compiled | RegexOptions.Singleline)),
        ("Results.Conflict(new { error ... })",
            new Regex(@"Results\s*\.\s*Conflict\s*\(\s*new\s*\{\s*error\b", RegexOptions.Compiled | RegexOptions.Singleline)),
        ("Results.UnprocessableEntity(new { error ... })",
            new Regex(@"Results\s*\.\s*UnprocessableEntity\s*\(\s*new\s*\{\s*error\b", RegexOptions.Compiled | RegexOptions.Singleline)),
    };

    private static IEnumerable<string> EnumerateProductionSources(string srcDir) =>
        Directory.EnumerateFiles(srcDir, "*.cs", SearchOption.AllDirectories)
            .Where(p => !p.Contains($"{Path.DirectorySeparatorChar}bin{Path.DirectorySeparatorChar}"))
            .Where(p => !p.Contains($"{Path.DirectorySeparatorChar}obj{Path.DirectorySeparatorChar}"))
            .Where(p => !p.Contains($"{Path.DirectorySeparatorChar}Migrations{Path.DirectorySeparatorChar}"));

    private static string LocateSrcDir()
    {
        // Test bin path: tests/Kartova.ArchitectureTests/bin/Debug/net10.0/
        // Five levels up reaches the repo root.
        var testAssemblyLocation = Path.GetDirectoryName(typeof(ProblemDetailsConventionRules).Assembly.Location)!;
        var repoRoot = Path.GetFullPath(
            Path.Combine(testAssemblyLocation, "..", "..", "..", "..", ".."));
        return Path.Combine(repoRoot, "src");
    }

    private static string ToRelativePath(string root, string path) =>
        Path.GetRelativePath(root, path).Replace('\\', '/');
}

using System.Diagnostics.CodeAnalysis;
using Kartova.SharedKernel.AspNetCore;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.RateLimiting;
using Microsoft.AspNetCore.Routing;
using Microsoft.Extensions.DependencyInjection;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Pins ADR-0096 — the Kartova HTTP API does not use the PATCH verb.
/// PUT for full-resource replacement, POST /&lt;action&gt; for named action endpoints.
/// Sparse-update demand is met by named actions, not PATCH semantics.
///
/// Boot mirrors <see cref="EndpointRouteRules"/>: a minimal <see cref="WebApplication"/>
/// is composed with every <see cref="IModuleEndpoints"/> implementation discovered in
/// production assemblies, then the live <see cref="EndpointDataSource"/> is walked and
/// every endpoint's <see cref="HttpMethodMetadata"/> is inspected for the PATCH verb.
/// The arch test is GREEN today (no PATCH route exists); it goes RED if anyone ever
/// adds one — at which point this comment, the ADR, and the offending endpoint must be
/// reconciled before the test can be unsuppressed.
/// </summary>
[ExcludeFromCodeCoverage]
[TestClass]
public class RestVerbPolicyRules
{
    [TestMethod]
    public void No_endpoint_uses_PATCH_verb()
    {
        var endpoints = MapEndpointsForArchTest();

        var patchEndpoints = endpoints
            .Where(e => e.HttpMethods.Contains("PATCH", StringComparer.OrdinalIgnoreCase))
            .Select(e => $"{e.HttpMethods.Single()} {e.Template}")
            .ToList();

        Assert.AreEqual(
            0,
            patchEndpoints.Count,
            "ADR-0096 forbids PATCH endpoints. Use PUT for full-resource replacement " +
            "or POST /<action> for named commands. Offending routes: " +
            string.Join(", ", patchEndpoints));
    }

    /// <summary>
    /// Boots a minimal <see cref="WebApplication"/> with just enough services to make
    /// <see cref="IEndpointRouteBuilder"/>-based mapping succeed (auth/authz are required
    /// by <c>MapAdminModule</c> et al.), instantiates every <see cref="IModuleEndpoints"/>
    /// implementation in production assemblies via parameterless ctor, calls
    /// <c>MapEndpoints</c>, and snapshots the resulting <see cref="EndpointDataSource"/>
    /// down to (httpMethods, template) pairs. Mirrors
    /// <see cref="EndpointRouteRules.MapEndpointsForArchTest"/>; duplication is preferred
    /// over extraction at two callers.
    /// </summary>
    private static List<EndpointVerbFingerprint> MapEndpointsForArchTest()
    {
        var builder = WebApplication.CreateBuilder();
        builder.Services.AddAuthentication("Test").AddJwtBearer("Test", _ => { });
        builder.Services.AddAuthorization();
        builder.Services.AddRouting();
        // Rate limiter must be present because InvitationAcceptRoutes calls RequireRateLimiting.
        builder.Services.AddRateLimiter(_ => { });

        // Stub every reference type referenced by an endpoint delegate parameter so
        // RequestDelegateFactory's IServiceProviderIsService check classifies them as
        // [FromServices] rather than [FromBody]. See EndpointRouteRules for the long-form
        // rationale.
        foreach (var type in DiscoverEndpointDelegateServiceTypes())
        {
            builder.Services.AddTransient(type, _ => null!);
        }

        var app = builder.Build();

        foreach (var moduleType in DiscoverModuleEndpointsTypes())
        {
            var module = (IModuleEndpoints)Activator.CreateInstance(moduleType)!;
            module.MapEndpoints(app);
        }

        return ((IEndpointRouteBuilder)app).DataSources
            .SelectMany(ds => ds.Endpoints)
            .OfType<RouteEndpoint>()
            .Select(e => new EndpointVerbFingerprint(
                HttpMethods: e.Metadata.GetMetadata<HttpMethodMetadata>()?.HttpMethods.ToArray()
                             ?? Array.Empty<string>(),
                Template: e.RoutePattern.RawText ?? string.Empty))
            .ToList();
    }

    private static IEnumerable<Type> DiscoverModuleEndpointsTypes() =>
        AssemblyRegistry.AllProduction()
            .SelectMany(a => a.GetTypes())
            .Where(t => !t.IsAbstract && typeof(IModuleEndpoints).IsAssignableFrom(t))
            .Where(t => t.GetConstructor(Type.EmptyTypes) is not null);

    private static IEnumerable<Type> DiscoverEndpointDelegateServiceTypes()
    {
        var seen = new HashSet<Type>();
        foreach (var assembly in AssemblyRegistry.AllProduction())
        {
            foreach (var type in assembly.GetTypes())
            {
                if (!type.Name.EndsWith("EndpointDelegates", StringComparison.Ordinal)
                    && !type.Name.EndsWith("Routes", StringComparison.Ordinal)) continue;
                foreach (var method in type.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static))
                {
                    foreach (var p in method.GetParameters())
                    {
                        var pt = p.ParameterType;
                        if (pt.IsValueType) continue;
                        if (pt == typeof(string)) continue;
                        if (pt == typeof(CancellationToken)) continue;
                        if (pt.Namespace?.StartsWith("Microsoft.AspNetCore", StringComparison.Ordinal) == true) continue;
                        if (p.GetCustomAttributes(typeof(Microsoft.AspNetCore.Mvc.FromBodyAttribute), inherit: false).Length > 0) continue;
                        if (seen.Add(pt)) yield return pt;
                    }
                }
            }
        }
    }

    private sealed record EndpointVerbFingerprint(string[] HttpMethods, string Template);
}

using System.IO;
using System.Linq;
using Kartova.SharedKernel;

namespace Kartova.ArchitectureTests;

/// <summary>
/// Slice-9 §11.1 boundary sentinels — drift tests that codify the architectural
/// contracts the slice depends on. A failure here means a regression has snuck
/// past the per-task review loop.
/// </summary>
[TestClass]
public sealed class Slice9BoundarySentinels
{
    /// <summary>
    /// The <c>User</c> and <c>Invitation</c> aggregates are owned by the Organization
    /// module — Catalog and SharedKernel must not carry copies. Cross-module access
    /// goes through <c>IUserDirectory</c> (the cross-cutting port in
    /// <c>Kartova.SharedKernel.Multitenancy</c>), never via duplicated entity types.
    /// </summary>
    [TestMethod]
    public void Organization_owns_users_and_invitations_tables()
    {
        AssertExactlyOneTypeNamed("User", typeof(Kartova.Organization.Domain.User));
        AssertExactlyOneTypeNamed("Invitation", typeof(Kartova.Organization.Domain.Invitation));
    }

    private static void AssertExactlyOneTypeNamed(string simpleName, Type expectedType)
    {
        var matches = AssemblyRegistry.AllProduction()
            .SelectMany(a => SafeGetTypes(a))
            .Where(t => t.Name == simpleName)
            .ToArray();

        Assert.AreEqual(
            1,
            matches.Length,
            $"Expected exactly one production type named '{simpleName}' (owned by Organization.Domain). " +
            $"Found: {string.Join(", ", matches.Select(t => t.FullName))}");

        Assert.AreEqual(
            expectedType.FullName,
            matches[0].FullName,
            $"Type '{simpleName}' must live at '{expectedType.FullName}', not '{matches[0].FullName}'.");

        Assert.AreEqual(
            "Kartova.Organization.Domain",
            matches[0].Namespace,
            $"Type '{simpleName}' must reside in 'Kartova.Organization.Domain'.");
    }

    /// <summary>
    /// There must be exactly ONE production implementation of <see cref="IDistributedLock"/>:
    /// <c>PostgresAdvisoryLock</c> in <c>Kartova.SharedKernel.Postgres</c>. The implementation
    /// must use session-level <c>pg_try_advisory_lock</c> (auto-released on connection drop),
    /// not transaction-scoped <c>pg_try_advisory_xact_lock</c> (would deadlock leader-elected
    /// periodic services that span longer than a transaction — ADR-0099).
    /// </summary>
    [TestMethod]
    public void IDistributedLock_implementations_use_session_advisory_locks()
    {
        var implementations = AssemblyRegistry.AllProduction()
            .SelectMany(a => SafeGetTypes(a))
            .Where(t => t is { IsClass: true, IsAbstract: false }
                        && typeof(IDistributedLock).IsAssignableFrom(t))
            .ToArray();

        Assert.AreEqual(
            1,
            implementations.Length,
            "Expected exactly one production IDistributedLock implementation. " +
            $"Found: {string.Join(", ", implementations.Select(t => t.FullName))}");

        var impl = implementations[0];
        Assert.AreEqual(
            "PostgresAdvisoryLock",
            impl.Name,
            $"The single IDistributedLock implementation must be PostgresAdvisoryLock, not '{impl.Name}'.");
        Assert.AreEqual(
            "Kartova.SharedKernel.Postgres",
            impl.Namespace,
            $"PostgresAdvisoryLock must reside in 'Kartova.SharedKernel.Postgres', not '{impl.Namespace}'.");

        // Surrogate for "uses pg_try_advisory_lock not pg_try_advisory_xact_lock". NetArchTest
        // can't introspect SQL strings, so we read the source file directly. The repo layout is
        // stable enough for this to be reliable (ADR-0082 modular monolith — one csproj per BC).
        var sourcePath = LocatePostgresAdvisoryLockSource();
        Assert.IsTrue(
            File.Exists(sourcePath),
            $"PostgresAdvisoryLock.cs source not found at expected path: {sourcePath}");

        var source = File.ReadAllText(sourcePath);
        Assert.IsTrue(
            source.Contains("pg_try_advisory_lock", StringComparison.Ordinal),
            "PostgresAdvisoryLock.cs must call session-level pg_try_advisory_lock (ADR-0099).");
        Assert.IsFalse(
            source.Contains("pg_try_advisory_xact_lock", StringComparison.Ordinal),
            "PostgresAdvisoryLock must NOT use transaction-scoped pg_try_advisory_xact_lock — " +
            "leader-elected periodic services hold the lock across many transactions (ADR-0099).");
    }

    private static string LocatePostgresAdvisoryLockSource() =>
        Path.GetFullPath(
            Path.Combine(
                AppContext.BaseDirectory,
                "..", "..", "..", "..", "..",
                "src", "Kartova.SharedKernel.Postgres", "PostgresAdvisoryLock.cs"));

    /// <summary>
    /// Slice-9 H3 surfaced that Alpine-based runtime containers without the
    /// <c>tzdata</c> package cannot resolve IANA timezone ids — every call to
    /// <see cref="TimeZoneInfo.FindSystemTimeZoneById"/> with a non-UTC id returns null,
    /// and <c>Organization.UpdateProfile</c> rejects the request with
    /// "Unknown IANA time-zone id." → HTTP 400. The production fix is
    /// <c>apk add --no-cache tzdata</c> in <c>src/Kartova.Api/Dockerfile</c>.
    /// <para>
    /// This sentinel runs on the test host (typically Windows or Linux with tzdata)
    /// and confirms the IANA ids slice-9 advertises do resolve. It won't catch the
    /// Alpine regression by itself (CI may run on Linux with tzdata), but it makes
    /// the timezone-resolution dependency visible and would fail on a stripped-down
    /// minimal Linux runtime.
    /// </para>
    /// </summary>
    [TestMethod]
    public void Runtime_can_resolve_common_IANA_timezones()
    {
        foreach (var tz in new[] { "Europe/Warsaw", "Europe/London", "America/New_York", "UTC" })
        {
            Assert.IsTrue(
                TimeZoneInfo.TryFindSystemTimeZoneById(tz, out _),
                $"Test host runtime cannot resolve IANA timezone '{tz}' — " +
                "production Alpine container needs tzdata package installed " +
                "(see src/Kartova.Api/Dockerfile, slice-9 H3 deviation).");
        }
    }

    private static IEnumerable<Type> SafeGetTypes(System.Reflection.Assembly a)
    {
        try
        {
            return a.GetTypes();
        }
        catch (System.Reflection.ReflectionTypeLoadException ex)
        {
            return ex.Types.Where(t => t is not null)!;
        }
    }
}

using System.Reflection;
using Kartova.SharedKernel;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using NetArchTest.Rules;

namespace Kartova.ArchitectureTests;

[TestClass]
public class TenantScopeRules
{
    private static readonly Assembly SharedKernel = typeof(Kartova.SharedKernel.Multitenancy.ITenantScope).Assembly;
    private static readonly Assembly SharedKernelAspNetCore = typeof(Kartova.SharedKernel.AspNetCore.TenantScopeBeginMiddleware).Assembly;
    private static readonly Assembly SharedKernelPostgres = typeof(Kartova.SharedKernel.Postgres.TenantScope).Assembly;
    private static readonly Assembly SharedKernelWolverine = typeof(Kartova.SharedKernel.Wolverine.TenantScopeWolverineMiddleware).Assembly;
    private static readonly Assembly OrganizationInfrastructure = typeof(Kartova.Organization.Infrastructure.OrganizationDbContext).Assembly;
    private static readonly Assembly OrganizationInfrastructureAdmin = typeof(Kartova.Organization.Infrastructure.Admin.AdminOrganizationDbContext).Assembly;

    [TestMethod]
    public void SharedKernel_has_no_framework_dependencies()
    {
        // KafkaFlow is added when the inbound consumer adapter lands in a later slice;
        // when added, append it here.
        var forbidden = new[]
        {
            "Npgsql",
            "Microsoft.EntityFrameworkCore",
            "Microsoft.AspNetCore",
            "WolverineFx",
        };

        var result = Types.InAssembly(SharedKernel)
            .Should()
            .NotHaveDependencyOnAny(forbidden)
            .GetResult();

        Assert.IsTrue(
            result.IsSuccessful,
            "Kartova.SharedKernel must stay technology-agnostic; tech-specific code lives in SharedKernel.Postgres/AspNetCore/Wolverine (ADR-0090)");
    }

    [TestMethod]
    public void Admin_bypass_DbContext_is_isolated_to_admin_assembly()
    {
        var result = Types.InAssembly(OrganizationInfrastructure)
            .Should()
            .NotHaveDependencyOn("Kartova.Organization.Infrastructure.Admin")
            .GetResult();

        Assert.IsTrue(
            result.IsSuccessful,
            "Tenant-scoped Infrastructure must not depend on the BYPASSRLS Admin DbContext (ADR-0090)");
    }

    [TestMethod]
    public void AspNetCore_adapter_does_not_reference_Postgres_adapter()
    {
        // Spec §3.2: SharedKernel.AspNetCore and SharedKernel.Postgres are sibling
        // adapters consumed by the API composition root. Cross-reference would force
        // any future transport adapter (Wolverine, Kafka) to inherit a Postgres
        // dependency. ADR-0090 + slice-2-followup design 2026-04-28.
        var aspNetCoreRefs = SharedKernelAspNetCore
            .GetReferencedAssemblies()
            .Select(a => a.Name)
            .ToArray();

        Assert.IsFalse(
            aspNetCoreRefs.Contains("Kartova.SharedKernel.Postgres"),
            "Spec §3.2 forbids the cross-reference; transport adapters " +
            "exchange failures via Kartova.SharedKernel.Multitenancy.TenantScopeBeginException");
    }

    [TestMethod]
    public void Wolverine_middleware_project_exists()
    {
        // Sanity: ensure the Wolverine adapter skeleton is compiled and present.
        var mw = typeof(Kartova.SharedKernel.Wolverine.TenantScopeWolverineMiddleware);
        Assert.IsNotNull(mw.GetMethod("BeforeAsync", BindingFlags.Static | BindingFlags.Public));
    }

    [TestMethod]
    public void Every_tenant_owned_entity_has_RLS_policy_in_a_migration()
    {
        // Explicit allowlist of ITenantOwned aggregates this rule covers. Each entry must
        // have a migration in its Infrastructure assembly that contains ENABLE ROW LEVEL
        // SECURITY for its table. Add new tenant-owned aggregates here as they appear.
        var tenantOwnedTypes = new[] { typeof(Kartova.Organization.Domain.Organization) };

        foreach (var t in tenantOwnedTypes)
        {
            var tableName = t.Name.ToLowerInvariant() + "s"; // convention
            // Navigate from the test output assembly location to the source tree.
            // Test assembly is at: {repo}/tests/Kartova.ArchitectureTests/bin/Debug/net10.0/
            // Source infrastructure migrations are at: {repo}/src/Modules/Organization/Kartova.Organization.Infrastructure/Migrations/
            var testAssemblyLocation = Path.GetDirectoryName(OrganizationInfrastructure.Location)!;
            // Go up to repo root: ../../../../../..
            var repoRoot = Path.GetFullPath(Path.Combine(testAssemblyLocation, "..", "..", "..", "..", ".."));
            var migrationsDir = Path.Combine(repoRoot, "src", "Modules", "Organization", "Kartova.Organization.Infrastructure", "Migrations");

            var migrationSources = Directory.GetFiles(migrationsDir, "*InitialOrganization.cs", SearchOption.AllDirectories);
            Assert.IsTrue(
                migrationSources.Length > 0,
                $"expected a migration for {tableName}");

            var anyHasRls = migrationSources.Any(f =>
                File.ReadAllText(f).Contains("ENABLE ROW LEVEL SECURITY", StringComparison.OrdinalIgnoreCase));
            Assert.IsTrue(
                anyHasRls,
                $"migration for {tableName} must ENABLE ROW LEVEL SECURITY per ADR-0012/0090");
        }
    }

    [TestMethod]
    public void Module_DbContexts_register_via_AddModuleDbContext()
    {
        // Spec §6.1 / ADR-0090: every IModule's runtime DbContext registration must flow
        // through AddModuleDbContext so the scope's connection + interceptors are wired.
        // We verify this behaviorally: build a ServiceProvider WITHOUT INpgsqlTenantScope
        // and assert that resolving the module's DbContext fails because the AddModuleDbContext
        // factory requires it. Raw AddDbContext (which would silently bypass RLS) would not
        // require INpgsqlTenantScope and thus would succeed here — failing the test.

        var modules = new IModule[]
        {
            new Kartova.Catalog.Infrastructure.CatalogModule(),
            new Kartova.Organization.Infrastructure.OrganizationModule(),
        };

        // ConfigurationManager is empty — neither module reads configuration in its
        // tenant-scoped RegisterServices path; only RegisterForMigrator does (and that
        // path is not exercised here).
        var emptyConfig = new ConfigurationManager();

        foreach (var module in modules)
        {
            var services = new ServiceCollection();
            module.RegisterServices(services, emptyConfig);

            // Deliberately do NOT call AddTenantScope() — that's what makes the test
            // distinguish AddModuleDbContext (needs scope) from raw AddDbContext (doesn't).
            using var sp = services.BuildServiceProvider();
            using var scope = sp.CreateScope();

            var ex = Assert.ThrowsExactly<InvalidOperationException>(
                () => scope.ServiceProvider.GetRequiredService(module.DbContextType),
                $"module '{module.Name}' must register its DbContext via AddModuleDbContext (ADR-0090)");
            // INpgsqlTenantScope is the missing collaborator AddModuleDbContext requires —
            // its absence pins the registration path (raw AddDbContext would resolve fine).
            StringAssert.Contains(ex.Message, "INpgsqlTenantScope");
        }
    }

    [TestMethod]
    public void AddModuleDbContext_helper_is_exposed()
    {
        var type = typeof(Kartova.SharedKernel.Postgres.AddModuleDbContextExtensions);
        Assert.IsNotNull(type.GetMethod("AddModuleDbContext", BindingFlags.Static | BindingFlags.Public));
        Assert.IsNotNull(type.GetMethod("AddTenantScope", BindingFlags.Static | BindingFlags.Public));
    }

    [TestMethod]
    public void TestJwtSigner_is_not_referenced_outside_test_projects()
    {
        // Kartova.Api must NOT reference Kartova.Testing.Auth.
        var apiRefs = typeof(Kartova.Api.Program).Assembly.GetReferencedAssemblies()
            .Select(a => a.Name)
            .ToArray();
        Assert.IsFalse(
            apiRefs.Contains("Kartova.Testing.Auth"),
            "Production API must not reference test-only JWT signer");
    }
}

using NetArchTest.Rules;

namespace Kartova.ArchitectureTests;

[TestClass]
public class WolverinePersistenceBoundaryTests
{
    [TestMethod]
    public void No_Production_Assembly_Depends_On_WolverinePostgresql()
    {
        foreach (var assembly in AssemblyRegistry.AllProduction())
        {
            var result = Types.InAssembly(assembly)
                .Should()
                .NotHaveDependencyOn("Wolverine.Postgresql")
