[assembly: DoNotParallelize]

using System.Net;
using System.Net.Http.Headers;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;

namespace Kartova.Organization.IntegrationTests;

/// <summary>
/// Integration tests for <c>DELETE /api/v1/organizations/teams/{id}/members/{userId}</c>
/// (slice 8, spec §10).
/// </summary>
[TestClass]
public sealed class RemoveTeamMemberTests : OrganizationIntegrationTestBase
{
    private const byte MemberRole = 1;
    private const byte AdminRole = 2;

    private static readonly TenantId Tenant =
        new(Guid.Parse("aaaaaaaa-0007-0007-0007-000000000007"));

    [TestMethod]
    public async Task OrgAdmin_removes_member_returns_204()
    {
        await Fx.SeedOrganizationAsync(Tenant.Value, "OrgA-Remove");
        var teamId = await Fx.SeedTeamAsync(Tenant.Value, "Platform");
        var memberId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamId, memberId, MemberRole);
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(Tenant, new[] { KartovaRoles.OrgAdmin },
                subject: "00000000-0000-0000-0007-000000000001");
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.DeleteAsync(
                $"/api/v1/organizations/teams/{teamId}/members/{memberId}");

            Assert.AreEqual(HttpStatusCode.NoContent, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Removing_nonexistent_member_returns_404()
    {
        await Fx.SeedOrganizationAsync(Tenant.Value, "OrgA-Remove-404");
        var teamId = await Fx.SeedTeamAsync(Tenant.Value, "Platform");
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(Tenant, new[] { KartovaRoles.OrgAdmin });
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.DeleteAsync(
                $"/api/v1/organizations/teams/{teamId}/members/{Guid.NewGuid()}");

            Assert.AreEqual(HttpStatusCode.NotFound, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Member_who_is_team_admin_of_other_team_removing_member_returns_403()
    {
        // Caller is a realm-Member who is Admin of team B but NOT of team A. The
        // resource gate (TeamAdminOfThis) is now the sole authorization (ADR-0101 —
        // the claim gate is gone); it must short-circuit with 403 before the
        // membership row is touched. We seed a real member in team A so the path
        // exercised is the resource gate, not "member doesn't exist". Addresses
        // deep-review MT-2.
        await Fx.SeedOrganizationAsync(Tenant.Value, "OrgA-Remove-OtherTeam-403");
        var teamA = await Fx.SeedTeamAsync(Tenant.Value, "Team A");
        var teamB = await Fx.SeedTeamAsync(Tenant.Value, "Team B");
        var memberInA = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamA, memberInA, MemberRole);
        var teamAdminUserId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamB, teamAdminUserId, AdminRole);
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(
                Tenant,
                new[] { KartovaRoles.Member },
                subject: teamAdminUserId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.DeleteAsync(
                $"/api/v1/organizations/teams/{teamA}/members/{memberInA}");

            Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Plain_member_not_admin_returns_403()
    {
        await Fx.SeedOrganizationAsync(Tenant.Value, "OrgA-Remove-403");
        var teamId = await Fx.SeedTeamAsync(Tenant.Value, "Platform");
        var memberId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamId, memberId, MemberRole);
        try
        {
            var client = Fx.CreateClient();
            // Caller is a plain Member of this team — the resource gate
            // (TeamAdminOfThis) denies because their membership role is Member,
            // not Admin (ADR-0101 — the resource gate is now the sole check).
            var token = Fx.Signer.IssueForTenant(
                Tenant,
                new[] { KartovaRoles.Member },
                subject: memberId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.DeleteAsync(
                $"/api/v1/organizations/teams/{teamId}/members/{memberId}");

            Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Member_who_is_team_admin_of_this_team_removes_member_returns_204()
    {
        // The footgun fix (ADR-0101, spec §8): a realm-Member who holds an Admin
        // membership on THIS team can remove members. Pre-change this returned 403
        // (Member lacked the team.members.manage claim); the resource gate
        // (TeamAdminOfThis) is now the sole authorization and recognises the
        // per-team Admin membership.
        await Fx.SeedOrganizationAsync(Tenant.Value, "OrgA-Remove-MemberAdmin");
        var teamId = await Fx.SeedTeamAsync(Tenant.Value, "Platform");
        var actingUserId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamId, actingUserId, AdminRole);
        var memberId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamId, memberId, MemberRole);
        try
        {
            var client = Fx.CreateClient();
            // The subject claim must match the seeded Admin membership — the
            // middleware reads it to populate TeamMemberships, which the resource
            // policy then queries. The realm role is Member, not TeamAdmin.
            var token = Fx.Signer.IssueForTenant(
                Tenant,
                new[] { KartovaRoles.Member },
                subject: actingUserId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.DeleteAsync(
                $"/api/v1/organizations/teams/{teamId}/members/{memberId}");

            Assert.AreEqual(HttpStatusCode.NoContent, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }
}

using System.Net;
using System.Net.Http.Json;
using Kartova.Organization.Contracts;
using Kartova.Organization.Domain;
using Kartova.Organization.Infrastructure;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;
using Microsoft.EntityFrameworkCore;

namespace Kartova.Organization.IntegrationTests;

/// <summary>
/// Integration tests for the slice-9 session-bootstrap endpoint
/// <c>POST /api/v1/auth/session</c> (spec §11.3 scenarios #7 + #8) — verifies the
/// invitation-acceptance side effect end-to-end against the real Postgres +
/// WebApplicationFactory pipeline. The handler itself is unit-tested at
/// <see cref="Infrastructure.Tests.SessionStartHandlerTests"/>; these tests
/// cover the request-pipeline integration that the unit tests can't reach:
/// JWT claim → <c>SessionStartHandler</c> upsert + Pending → Accepted flip →
/// HTTP response.
///
/// Key technical gotcha: <c>SessionStartHandler</c> requires an <c>email</c>
/// claim on the JWT (it throws otherwise — see <c>SessionStartHandler.cs</c>).
/// H1 batch 4 extended <see cref="TestJwtSigner"/> +
/// <see cref="KartovaApiFixtureBase.CreateAuthenticatedClientAsync"/> with an
/// optional <c>emailClaim</c> parameter so these tests can mint the right
/// shape. Tests not exercising session-bootstrap continue to pass without an
/// email claim — the default is opt-out.
/// </summary>
[TestClass]
public sealed class SessionBootstrapTests : OrganizationIntegrationTestBase
{
    /// <summary>
    /// Common scenario seed for the two session-bootstrap tests: a tenant + org row,
    /// an inviter user row, and a Pending invitation whose
    /// <c>KeycloakUserId</c> equals the <c>sub</c> claim that the invitee's JWT
    /// will carry. Returned tuple lets each test mint the invitee client and clean
    /// up afterwards (each cleanup hook is exception-safe).
    /// </summary>
    private static async Task<SessionBootstrapSeed> SeedAsync(string scenarioSlug)
    {
        var (adminEmail, tenantId) = await NewTenantAsync(scenarioSlug);
        var domain = adminEmail.Split('@')[1];
        var inviterUserId = await Fx.SeedUserInOrganizationAsync(
            new TenantId(tenantId), "Inviter Display", $"inviter@{domain}");

        var inviteeEmail = $"invitee@{domain}";
        var inviteeKcId = Guid.NewGuid();
        // Backdate invitedAt so AcceptedAt > InvitedAt is observable when the
        // handler flips the row in the request. ExpiresAt defaults to
        // invited_at + 7d (well in the future) so the handler's expiry guard
        // (ExpiresAt > now) lets the acceptance branch run.
        var invitedAt = TimeProvider.System.GetUtcNow().AddMinutes(-10);
        var invitationId = await Fx.SeedInvitationAsync(
            tenantId: tenantId,
            email: inviteeEmail,
            role: KartovaRoles.Member,
            invitedByUserId: inviterUserId,
            keycloakUserId: inviteeKcId,
            invitedAt: invitedAt);

        return new SessionBootstrapSeed(
            ScenarioSlug: scenarioSlug,
            TenantId: tenantId,
            OrgDisplayName: $"Org-{scenarioSlug}",
            InviterUserId: inviterUserId,
            InviteeEmail: inviteeEmail,
            InviteeKcUserId: inviteeKcId,
            InvitationId: invitationId,
            InvitedAt: invitedAt);
    }

    private sealed record SessionBootstrapSeed(
        string ScenarioSlug,
        Guid TenantId,
        string OrgDisplayName,
        Guid InviterUserId,
        string InviteeEmail,
        Guid InviteeKcUserId,
        Guid InvitationId,
        DateTimeOffset InvitedAt);

    /// <summary>
    /// Tears down everything the seed planted plus the row the handler upserts
    /// for the invitee. Cleanup order: invitations first (mirrors
    /// <see cref="KartovaApiFixture.DeleteInvitationsForTenantAsync"/>'s internal
    /// contract), users second (no FK from users to invitations or vice versa,
    /// so either order works), organizations last (parent row). Each step in
    /// its own try/catch so a leak on one row doesn't strand the next.
    /// </summary>
    private static async Task CleanupAsync(SessionBootstrapSeed seed)
    {
#pragma warning disable CA1031 // best-effort test teardown — log and continue
        try { await Fx.DeleteInvitationsForTenantAsync(seed.TenantId); }
        catch (Exception ex)
        {
            await Console.Error.WriteLineAsync(
                $"[cleanup] invitations delete failed for tenant {seed.TenantId}: {ex.Message}");
        }
        try
        {
            await using var db = new OrganizationDbContext(BypassOptions());
            // Wipe both inviter + invitee rows (the latter is hook-upserted, so the
            // test never sees the userId directly — clearing by tenant is robust).
            await db.Database.ExecuteSqlRawAsync(
                "DELETE FROM users WHERE tenant_id = {0}", seed.TenantId);
        }
        catch (Exception ex)
        {
            await Console.Error.WriteLineAsync(
                $"[cleanup] users delete failed for tenant {seed.TenantId}: {ex.Message}");
        }
        try { await Fx.DeleteOrganizationsForTenantAsync(seed.TenantId); }
        catch (Exception ex)
        {
            await Console.Error.WriteLineAsync(
                $"[cleanup] organizations delete failed for tenant {seed.TenantId}: {ex.Message}");
        }
#pragma warning restore CA1031
    }

    // ---------- Scenario #7 (spec §11.3): first session-start flips invitation -----

    [TestMethod]
    public async Task Session_start_after_invitation_login_marks_accepted()
    {
        var seed = await SeedAsync("session-bootstrap-7");
        try
        {
            // Impersonate the invitee — JWT sub = the KC user id stored on the
            // invitation, email = the invitation email. Role = Member (the role
            // the invitation carried). The TestJwtSigner emits the email claim
            // because emailClaim is non-null; without it SessionStartHandler
            // throws (the email claim is now a required bootstrap input).
            var inviteeClient = await Fx.CreateAuthenticatedClientAsync(
                seed.InviteeEmail,
                roles: new[] { KartovaRoles.Member },
                subjectOverride: seed.InviteeKcUserId,
                emailClaim: seed.InviteeEmail);

            var resp = await inviteeClient.PostAsync("/api/v1/auth/session", content: null);
            Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);

            var body = await resp.Content.ReadFromJsonAsync<SessionStartResponse>(
                KartovaApiFixtureBase.WireJson);
            Assert.IsNotNull(body);

            // Me: SessionStartHandler upserted the row, OrganizationUserDirectory returned it.
            Assert.AreEqual(seed.InviteeKcUserId, body!.Me.Id);
            Assert.AreEqual(seed.InviteeEmail, body.Me.Email);

            // Role + permissions: the Member set must be present (not the empty
            // PlatformAdmin fallback, not the Viewer fallback). Member includes
            // TeamRead — assert that specifically to kill mutants that swap the
            // role lookup for the Viewer set (also has TeamRead) by also asserting
            // a Member-specific permission (CatalogApplicationsRegister) that
            // Viewer does NOT carry.
            Assert.AreEqual(KartovaRoles.Member, body.Role);
            CollectionAssert.Contains(body.Permissions.ToArray(), KartovaPermissions.TeamRead);
            CollectionAssert.Contains(
                body.Permissions.ToArray(), KartovaPermissions.CatalogApplicationsRegister);

            // Org profile: came from the NewTenantAsync seed.
            Assert.AreEqual(seed.OrgDisplayName, body.Organization.DisplayName);

            // AcceptedInvitation: present + matches the seeded invitation.
            Assert.IsNotNull(body.AcceptedInvitation);
            Assert.AreEqual(seed.OrgDisplayName, body.AcceptedInvitation!.OrgDisplayName);
            Assert.AreEqual(seed.InviterUserId, body.AcceptedInvitation.InvitedBy.Id);
            Assert.AreEqual("Inviter Display", body.AcceptedInvitation.InvitedBy.DisplayName);

            // InvitedAt: should match the seeded value within DB rounding (Postgres
            // stores DateTimeOffset as microseconds). One-second tolerance is more
            // than enough.
            var invitedDelta = (body.AcceptedInvitation.InvitedAt - seed.InvitedAt).Duration();
            Assert.IsTrue(
                invitedDelta < TimeSpan.FromSeconds(1),
                $"InvitedAt should match seed within 1s; actual delta = {invitedDelta}.");

            // AcceptedAt: set by MarkAccepted in this request, must be after
            // InvitedAt and within ~10s of "now" (allow container clock drift).
            Assert.IsTrue(
                body.AcceptedInvitation.AcceptedAt > body.AcceptedInvitation.InvitedAt,
                $"AcceptedAt ({body.AcceptedInvitation.AcceptedAt:o}) must be after " +
                $"InvitedAt ({body.AcceptedInvitation.InvitedAt:o}).");
            var acceptedAge = TimeProvider.System.GetUtcNow() - body.AcceptedInvitation.AcceptedAt;
            Assert.IsTrue(
                acceptedAge < TimeSpan.FromSeconds(10) && acceptedAge >= TimeSpan.Zero,
                $"AcceptedAt must be recent; observed age = {acceptedAge}.");

            // DB: status flipped + AcceptedAt populated.
            await using (var db = new OrganizationDbContext(BypassOptions()))
            {
                var inv = await db.Invitations.SingleAsync(
                    i => EF.Property<Guid>(i, "_id") == seed.InvitationId);
                Assert.AreEqual(InvitationStatus.Accepted, inv.Status);
                Assert.IsNotNull(inv.AcceptedAt);

                // Users projection: handler upserted the invitee row keyed by
                // KeycloakUserId.
                var userRow = await db.Users.SingleAsync(u => u.Id == seed.InviteeKcUserId);
                Assert.AreEqual(seed.InviteeEmail, userRow.Email);
                Assert.AreEqual(new TenantId(seed.TenantId), userRow.TenantId);
            }
        }
        finally
        {
            await CleanupAsync(seed);
        }
    }

    // ---------- Scenario #8 (spec §11.3): subsequent call has no welcome ----------

    [TestMethod]
    public async Task Session_start_subsequent_call_returns_no_accepted_invitation()
    {
        var seed = await SeedAsync("session-bootstrap-8");
        try
        {
            var inviteeClient = await Fx.CreateAuthenticatedClientAsync(
                seed.InviteeEmail,
                roles: new[] { KartovaRoles.Member },
                subjectOverride: seed.InviteeKcUserId,
                emailClaim: seed.InviteeEmail);

            // First call: flips Pending → Accepted via SessionStartHandler. We
            // don't assert the welcome payload here — that's #7's job. We just
            // need the state transition to happen so the second call observes
            // the Accepted row.
            var first = await inviteeClient.PostAsync("/api/v1/auth/session", content: null);
            Assert.AreEqual(HttpStatusCode.OK, first.StatusCode);

            // Second call: same client, same JWT. The handler now finds no
            // Pending invitation (the row is Accepted from the first call), so
            // it does not flip anything and emits a null AcceptedInvitation
            // block — the welcome banner is a one-shot in-request signal.
            var second = await inviteeClient.PostAsync("/api/v1/auth/session", content: null);
            Assert.AreEqual(HttpStatusCode.OK, second.StatusCode);

            var body = await second.Content.ReadFromJsonAsync<SessionStartResponse>(
                KartovaApiFixtureBase.WireJson);
            Assert.IsNotNull(body);

            // Core payload still valid — only the welcome block differs from #7.
            Assert.AreEqual(seed.InviteeKcUserId, body!.Me.Id);
            Assert.AreEqual(KartovaRoles.Member, body.Role);
            Assert.IsTrue(
                body.Permissions.Count > 0,
                "Member role must yield a non-empty permission set even on subsequent session-starts.");
            CollectionAssert.Contains(body.Permissions.ToArray(), KartovaPermissions.TeamRead);

            Assert.IsNull(
                body.AcceptedInvitation,
                "AcceptedInvitation must be null on the second session-start — the welcome banner " +
                "is a one-shot signal driven by the in-request invitation flip, not the persisted status.");

            // DB: status is STILL Accepted from the first call (no re-flip —
            // the handler only acts on Pending invitations; the second call
            // found no Pending row and short-circuited).
            await using var db = new OrganizationDbContext(BypassOptions());
            var inv = await db.Invitations.SingleAsync(
                i => EF.Property<Guid>(i, "_id") == seed.InvitationId);
            Assert.AreEqual(InvitationStatus.Accepted, inv.Status);
        }
        finally
        {
            await CleanupAsync(seed);
        }
    }

    // ---------- Regression test: realm_role sync on session bootstrap -----------

    /// <summary>
    /// Regression guard for the slice-10 DoD bug: a user whose JWT carries realm
    /// role <c>OrgAdmin</c> must have <c>realm_role = 'OrgAdmin'</c> persisted in
    /// the <c>users</c> table after a session bootstrap, and must appear as
    /// <c>OrgAdmin</c> in <c>GET /api/v1/organizations/users</c>. The pre-fix
    /// behaviour was: <c>UpsertAsync</c> never set <c>RealmRole</c>, so the DB
    /// default <c>'Viewer'</c> remained regardless of the JWT role.
    /// </summary>
    [TestMethod]
    public async Task Session_start_syncs_OrgAdmin_realm_role_to_users_projection()
    {
        var (adminEmail, tenantId) = await NewTenantAsync("session-realm-role-sync");
        // The domain of subjectEmail MUST match adminEmail's domain so that
        // TenantFor(subjectEmail) == TenantFor(adminEmail) == tenantId (the seeded org's
        // tenant). Using the same domain ensures the JWT carries the correct tenant claim.
        var domain = adminEmail.Split('@')[1];
        var subjectKcId = Guid.NewGuid();
        var subjectEmail = $"orgadmin@{domain}";

        // Seed an inviter row so the directory listing has a second member.
        var inviterUserId = await Fx.SeedUserInOrganizationAsync(
            new TenantId(tenantId), "Inviter User", $"inviter@{domain}",
            realmRole: KartovaRoles.Member);

        try
        {
            // Bootstrap as OrgAdmin — the JWT carries that realm role.
            var client = await Fx.CreateAuthenticatedClientAsync(
                subjectEmail,
                roles: new[] { KartovaRoles.OrgAdmin },
                subjectOverride: subjectKcId,
                emailClaim: subjectEmail);

            var bootstrapResp = await client.PostAsync("/api/v1/auth/session", content: null);
            Assert.AreEqual(
                System.Net.HttpStatusCode.OK,
                bootstrapResp.StatusCode,
                $"Session bootstrap must return 200. Body: {await bootstrapResp.Content.ReadAsStringAsync()}");

            // Verify DB row: realm_role must be OrgAdmin, NOT the default Viewer.
            await using (var db = new OrganizationDbContext(BypassOptions()))
            {
                var userRow = await db.Users.SingleOrDefaultAsync(u => u.Id == subjectKcId);
                Assert.IsNotNull(userRow, "Session bootstrap must create a users row keyed by the JWT sub.");
                Assert.AreEqual(
                    KartovaRoles.OrgAdmin,
                    userRow!.RealmRole,
                    $"users.realm_role must be '{KartovaRoles.OrgAdmin}' after bootstrapping with an " +
                    $"OrgAdmin JWT — was '{userRow.RealmRole}'. " +
                    "Pre-fix: UpsertAsync never set RealmRole → DB default 'Viewer' persisted.");
            }

            // Verify via HTTP directory: the bootstrapped user must appear as OrgAdmin.
            var resp = await client.GetAsync("/api/v1/organizations/users?limit=50");
            Assert.AreEqual(
                System.Net.HttpStatusCode.OK,
                resp.StatusCode,
                $"GET /users must return 200. Body: {await resp.Content.ReadAsStringAsync()}");

            var page = await resp.Content.ReadFromJsonAsync<Kartova.SharedKernel.Pagination.CursorPage<MemberSummaryResponse>>(
                KartovaApiFixtureBase.WireJson);
            Assert.IsNotNull(page, "Directory response must deserialize to CursorPage<MemberSummaryResponse>.");

            var row = page!.Items.SingleOrDefault(r => r.Id == subjectKcId);
            Assert.IsNotNull(row,
                "The bootstrapped OrgAdmin user must appear in the members directory.");
            Assert.AreEqual(
                KartovaRoles.OrgAdmin,
                row!.Role,
                $"Directory row for the bootstrapped user must show Role = '{KartovaRoles.OrgAdmin}', " +
                $"not '{row.Role}'. Pre-fix: realm_role column stayed at DB default 'Viewer'.");
        }
        finally
        {
#pragma warning disable CA1031 // best-effort test teardown — log and continue
            try
            {
                await using var db = new OrganizationDbContext(BypassOptions());
                await db.Database.ExecuteSqlRawAsync(
                    "DELETE FROM users WHERE tenant_id = {0}", tenantId);
            }
            catch (Exception ex)
            {
                await Console.Error.WriteLineAsync(
                    $"[cleanup] users delete failed for tenant {tenantId}: {ex.Message}");
            }
            try { await Fx.DeleteOrganizationsForTenantAsync(tenantId); }
            catch (Exception ex)
            {
                await Console.Error.WriteLineAsync(
                    $"[cleanup] organizations delete failed for tenant {tenantId}: {ex.Message}");
            }
#pragma warning restore CA1031
        }
    }
}

using System.Diagnostics.CodeAnalysis;
using System.Net;
using System.Net.Http.Headers;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;

namespace Kartova.Organization.IntegrationTests;

[ExcludeFromCodeCoverage]
[TestClass]
public class StreamingDurabilityTests : OrganizationFaultInjectionTestBase
{
    [TestMethod]
    public async Task Commit_failure_on_streaming_endpoint_returns_clean_5xx()
    {
        // Endpoint filter contract: handle.CommitAsync runs BEFORE IResult.ExecuteAsync,
        // so a commit failure propagates as 500 + problem-details with no bytes
        // streamed. With middleware-only commit (the slice-2 deviation that was
        // ratified back to a hybrid two-piece adapter in 79bd0e2), the response
        // body would begin flushing during _next(context) and a commit failure
        // would surface AFTER partial bytes had already been sent.
        Fx.CommitFailFlag.Fail = true;
        try
        {
            var client = Fx.CreateClient();
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue(
                "Bearer", Fx.Signer.IssueForTenant(SeededOrgs.OrgA, new[] { KartovaRoles.OrgAdmin }));

            var resp = await client.GetAsync("/__test/stream");

            // commit failure must surface as 5xx, not as a partial 200 stream
            Assert.AreEqual(HttpStatusCode.InternalServerError, resp.StatusCode);
            // The streaming payload is 2 KB of zero bytes. ProblemDetails replaces
            // the body when commit throws BEFORE IResult.ExecuteAsync runs, so the
            // body must be smaller than the streamed payload (in practice it's a
            // small JSON problem-details document).
            var body = await resp.Content.ReadAsByteArrayAsync();
            // no streamed bytes should reach the client when commit fails
            Assert.IsTrue(body.Length < 2048);
        }
        finally
        {
            Fx.CommitFailFlag.Fail = false;
        }
    }
}

