using System.Net;
using System.Net.Http.Headers;
using System.Net.Http.Json;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.SharedKernel.AspNetCore;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;

namespace Kartova.Catalog.IntegrationTests;

/// <summary>
/// Integration tests for <c>PUT /api/v1/catalog/applications/{id}/team</c>
/// (slice 8, spec §10 / ADR-0098 §6.4). Exercises the happy assignment,
/// the 422 invalid-team branch (target team does not exist in the tenant),
/// and the 403 resource-auth branch (caller not in the app's current team).
/// </summary>
[TestClass]
public sealed class AssignApplicationTeamTests : CatalogIntegrationTestBase
{
    private const byte MemberRole = 1;

    private static readonly TenantId Tenant =
        new(Guid.Parse("cccccccc-0001-0001-0001-000000000001"));

    [TestMethod]
    public async Task OrgAdmin_assigns_app_to_team_returns_200_and_GET_reflects_teamId()
    {
        var teamId = await Fx.SeedTeamInOrganizationAsync(Tenant, "Platform");
        var appId = await Fx.SeedSingleApplicationAsync(Tenant, Guid.NewGuid(), teamId: null);
        try
        {
            var client = Fx.CreateClient();
            // Audit wiring records the actor from the JWT `sub` (parsed as a Guid),
            // so a successful (audited) assignment needs a real Guid subject — the
            // default "test-user" sub would fail Guid.Parse. The 422/403/409 cases
            // reject before the audit append, so they don't need this.
            var token = Fx.Signer.IssueForTenant(
                Tenant, new[] { KartovaRoles.OrgAdmin }, subject: Guid.NewGuid().ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(teamId));

            Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);

            // GET-after-PUT roundtrip pins SaveChangesAsync side-effect — guards
            // against a regression where the handler returns 200 without persisting.
            var getResp = await client.GetAsync($"/api/v1/catalog/applications/{appId}");
            Assert.AreEqual(HttpStatusCode.OK, getResp.StatusCode);
            var body = await getResp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);
            Assert.AreEqual(teamId, body!.TeamId);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(Tenant, "assign-app");
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Reassigning_Decommissioned_app_to_another_team_returns_409()
    {
        // ADR-0103: AssignTeam is reassign-only and blocked on Decommissioned
        // (terminal-write guard). Reassigning a Decommissioned app surfaces the
        // shared lifecycle-conflict 409 (mirrors the domain unit test
        // AssignTeam_when_Decommissioned_throws). Replaces the slice-8 unassign
        // carve-out, which ADR-0103 removed (no ownerless apps).
        var tenant = new TenantId(Guid.Parse("aaaaaaaa-0020-0020-0020-000000000001"));
        var teamId = await Fx.SeedTeamInOrganizationAsync(tenant, "TeamForDecomm");
        var otherTeamId = await Fx.SeedTeamInOrganizationAsync(tenant, "OtherTeamForDecomm");
        var appId = await Fx.SeedSingleApplicationAsync(tenant, Guid.NewGuid(), teamId,
            namePrefix: "decomm-reassign");
        await Fx.SetApplicationLifecycleAsync(appId, Lifecycle.Decommissioned);
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(tenant, new[] { KartovaRoles.OrgAdmin });
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(otherTeamId));

            Assert.AreEqual(HttpStatusCode.Conflict, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(tenant, "decomm-reassign");
            await Fx.DeleteTeamsForTenantAsync(tenant.Value);
        }
    }

    [TestMethod]
    public async Task Assigning_to_unknown_team_returns_422_invalid_team()
    {
        // App has no team yet (so the resource policy passes for OrgAdmin trivially),
        // and the target team uuid is one we never created — the cross-module existence
        // check must surface a 422 with type=invalid-team.
        var appId = await Fx.SeedSingleApplicationAsync(Tenant, Guid.NewGuid(), teamId: null);
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(Tenant, new[] { KartovaRoles.OrgAdmin });
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var unknownTeamId = Guid.NewGuid();
            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(unknownTeamId));

            Assert.AreEqual(HttpStatusCode.UnprocessableEntity, resp.StatusCode);
            Assert.AreEqual("application/problem+json", resp.Content.Headers.ContentType?.MediaType);
            var body = await resp.Content.ReadAsStringAsync();
            StringAssert.Contains(body, ProblemTypes.InvalidTeam);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(Tenant, "assign-app");
        }
    }

    [TestMethod]
    public async Task PUT_with_other_tenant_team_id_returns_422_invalid_team()
    {
        // Slice-boundary review fix #4: cross-tenant safety — assigning tenant-A's
        // app to a team that exists only in tenant-B must surface the same
        // 422 invalid-team envelope as an unknown team uuid. RLS hides team-B from
        // tenant-A's lookup, so the cross-module existence check
        // (IOrganizationTeamExistenceChecker) sees no row and returns false.
        var tenantA = new TenantId(Guid.Parse("aaaaaaaa-0019-0019-0019-000000000001"));
        var tenantB = new TenantId(Guid.Parse("aaaaaaaa-0019-0019-0019-000000000002"));

        var teamInB = await Fx.SeedTeamInOrganizationAsync(tenantB, "Team in OrgB");
        var appInA  = await Fx.SeedSingleApplicationAsync(tenantA, Guid.NewGuid(), teamId: null,
            namePrefix: "xtenant-app");
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(tenantA, new[] { KartovaRoles.OrgAdmin });
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appInA}/team",
                new AssignTeamRequest(teamInB));

            Assert.AreEqual(HttpStatusCode.UnprocessableEntity, resp.StatusCode);
            Assert.AreEqual("application/problem+json", resp.Content.Headers.ContentType?.MediaType);
            var body = await resp.Content.ReadAsStringAsync();
            StringAssert.Contains(body, ProblemTypes.InvalidTeam);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(tenantA, "xtenant-app");
            await Fx.DeleteTeamsForTenantAsync(tenantB.Value);
        }
    }

    [TestMethod]
    public async Task Member_not_in_apps_current_team_returns_403()
    {
        // App is assigned to teamA; caller is a Member of NO team. The resource
        // policy (ApplicationTeamScoped) requires the caller to be a member of
        // the app's current team — they aren't, so the gate rejects with 403.
        var teamA = await Fx.SeedTeamInOrganizationAsync(Tenant, "TeamA");
        var appId = await Fx.SeedSingleApplicationAsync(Tenant, Guid.NewGuid(), teamId: teamA);
        try
        {
            var callerId = Guid.NewGuid();
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(
                Tenant,
                new[] { KartovaRoles.Member },
                subject: callerId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(teamA));

            Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(Tenant, "assign-app");
            await Fx.DeleteTeamsForTenantAsync(Tenant.Value);
        }
    }

    [TestMethod]
    public async Task Member_in_team_A_reassigning_app_to_team_B_they_do_not_belong_to_returns_403()
    {
        // Slice-8 boundary-review fix SF-2: caller is a Member of teamA only.
        // App is in teamA, so the source-team gate (ApplicationTeamScoped) passes.
        // Target is teamB — caller isn't in teamB, so the target-team check must
        // 403 before the handler reassigns and orphans the caller from the app.
        var tenant = new TenantId(Guid.Parse("aaaaaaaa-0030-0030-0030-000000000001"));
        var teamA = await Fx.SeedTeamInOrganizationAsync(tenant, "Team A");
        var teamB = await Fx.SeedTeamInOrganizationAsync(tenant, "Team B");

        var memberId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamA, memberId, MemberRole);

        var appId = await Fx.SeedSingleApplicationAsync(tenant, Guid.NewGuid(), teamId: teamA,
            namePrefix: "sf2-cross");
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(
                tenant,
                new[] { KartovaRoles.Member },
                subject: memberId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(teamB));

            Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(tenant, "sf2-cross");
            await Fx.DeleteTeamsForTenantAsync(tenant.Value);
        }
    }

    [TestMethod]
    public async Task Member_in_both_teams_reassigning_app_to_team_they_belong_to_succeeds()
    {
        // Control case for SF-2: caller is a Member of teamA1 AND teamA2.
        // App is in teamA1. Reassign to teamA2 — both source and target gates
        // pass and the handler runs. Verifies the SF-2 check doesn't over-block.
        var tenant = new TenantId(Guid.Parse("aaaaaaaa-0030-0030-0030-000000000002"));
        var teamA1 = await Fx.SeedTeamInOrganizationAsync(tenant, "Team A1");
        var teamA2 = await Fx.SeedTeamInOrganizationAsync(tenant, "Team A2");

        var memberId = Guid.NewGuid();
        await Fx.SeedTeamMembershipAsync(teamA1, memberId, MemberRole);
        await Fx.SeedTeamMembershipAsync(teamA2, memberId, MemberRole);

        var appId = await Fx.SeedSingleApplicationAsync(tenant, Guid.NewGuid(), teamId: teamA1,
            namePrefix: "sf2-ok");
        try
        {
            var client = Fx.CreateClient();
            var token = Fx.Signer.IssueForTenant(
                tenant,
                new[] { KartovaRoles.Member },
                subject: memberId.ToString());
            client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);

            var resp = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{appId}/team",
                new AssignTeamRequest(teamA2));

            Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        }
        finally
        {
            await Fx.DeleteApplicationsByPrefixAsync(tenant, "sf2-ok");
            await Fx.DeleteTeamsForTenantAsync(tenant.Value);
        }
    }

}

using System.Net;
using System.Net.Http.Json;
using System.Text.Json;
using Kartova.Catalog.Application;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.SharedKernel.AspNetCore;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;

namespace Kartova.Catalog.IntegrationTests;

[TestClass]
public class AuditWiringTests : CatalogIntegrationTestBase
{
    private const string OrgAUser = "admin@orga.kartova.local";

    // --- Happy: register writes a correct, chained audit row ---
    [TestMethod]
    public async Task Register_WritesApplicationRegisteredAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit Reg Team", nameClaim: "Ada Catalog");

        var resp = await client.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest("Audit Reg App", "Desc.", teamId));
        Assert.AreEqual(HttpStatusCode.Created, resp.StatusCode,
            $"Expected 201. Body: {await resp.Content.ReadAsStringAsync()}");
        var body = await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);

        var rows = await Fx.ReadAuditLogAsync(tenantId);
        var row = rows.Single(r =>
            r.Action == CatalogAuditActions.ApplicationRegistered &&
            r.TargetId == body!.Id.ToString());
        Assert.AreEqual(await Fx.GetSubClaimAsync(OrgAUser), row.ActorId);
        Assert.AreEqual("Ada Catalog", row.ActorDisplay);
        Assert.AreEqual("User", row.ActorType);
        Assert.AreEqual(CatalogAuditTargetTypes.Application, row.TargetType);
        using var data = JsonDocument.Parse(row.DataJson!);
        Assert.AreEqual("Audit Reg App", data.RootElement.GetProperty("displayName").GetString());
        Assert.AreEqual(teamId.ToString(), data.RootElement.GetProperty("teamId").GetString());

        // Catalog rows interleave into the same per-tenant hash chain as the
        // Organization rows — verify the whole tenant chain stays contiguous and
        // linked (seq 1..n, each prev_hash == predecessor row_hash). Design §7.
        AssertChainLinked(rows);
    }

    // --- Happy: register API writes a correct api.registered audit row ---
    [TestMethod]
    public async Task RegisterApi_WritesApiRegisteredAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit Api Team", nameClaim: "Ada Catalog");

        var resp = await client.PostAsJsonAsync("/api/v1/catalog/apis", new
        {
            displayName = "Audit Reg Api", description = "Desc.", style = ApiStyle.Rest, version = "v1",
            specUrl = (string?)null, teamId,
        });
        Assert.AreEqual(HttpStatusCode.Created, resp.StatusCode,
            $"Expected 201. Body: {await resp.Content.ReadAsStringAsync()}");
        var body = await resp.Content.ReadFromJsonAsync<ApiResponse>(KartovaApiFixtureBase.WireJson);

        var rows = await Fx.ReadAuditLogAsync(tenantId);
        var row = rows.Single(r =>
            r.Action == CatalogAuditActions.ApiRegistered &&
            r.TargetId == body!.Id.ToString());
        Assert.AreEqual(await Fx.GetSubClaimAsync(OrgAUser), row.ActorId);
        Assert.AreEqual("Ada Catalog", row.ActorDisplay);
        Assert.AreEqual("User", row.ActorType);
        Assert.AreEqual(CatalogAuditTargetTypes.Api, row.TargetType);
        using var data = JsonDocument.Parse(row.DataJson!);
        Assert.AreEqual("Audit Reg Api", data.RootElement.GetProperty("displayName").GetString());
        Assert.AreEqual(teamId.ToString(), data.RootElement.GetProperty("teamId").GetString());
    }

    // --- Happy: PUT spec writes a correct api.spec.updated audit row ---
    [TestMethod]
    public async Task PutSpec_WritesApiSpecUpdatedAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit Spec Team", nameClaim: "Ada Catalog");

        var apiResp = await client.PostAsJsonAsync("/api/v1/catalog/apis", new
        {
            displayName = "Audit Spec Api", description = "Desc.", style = ApiStyle.Rest, version = "v1",
            specUrl = (string?)null, teamId,
        });
        Assert.AreEqual(HttpStatusCode.Created, apiResp.StatusCode,
            $"Expected 201. Body: {await apiResp.Content.ReadAsStringAsync()}");
        var api = await apiResp.Content.ReadFromJsonAsync<ApiResponse>(KartovaApiFixtureBase.WireJson);

        var specReq = new HttpRequestMessage(HttpMethod.Put, $"/api/v1/catalog/apis/{api!.Id}/spec")
        {
            Content = new StringContent("{\"openapi\":\"3.0.0\"}", System.Text.Encoding.UTF8, "application/json"),
        };
        var specResp = await client.SendAsync(specReq);
        Assert.AreEqual(HttpStatusCode.Created, specResp.StatusCode,
            $"Expected 201. Body: {await specResp.Content.ReadAsStringAsync()}");

        var rows = await Fx.ReadAuditLogAsync(tenantId);
        var row = rows.Single(r =>
            r.Action == CatalogAuditActions.ApiSpecUpdated &&
            r.TargetId == api.Id.ToString());
        Assert.AreEqual(await Fx.GetSubClaimAsync(OrgAUser), row.ActorId);
        Assert.AreEqual("Ada Catalog", row.ActorDisplay);
        Assert.AreEqual("User", row.ActorType);
        Assert.AreEqual(CatalogAuditTargetTypes.Api, row.TargetType);
        using var data = JsonDocument.Parse(row.DataJson!);
        Assert.AreEqual("application/json", data.RootElement.GetProperty("mediaType").GetString());
        Assert.AreEqual("true", data.RootElement.GetProperty("created").GetString());
    }

    private static void AssertChainLinked(IReadOnlyList<KartovaApiFixture.AuditRowRecord> rows)
    {
        for (var i = 0; i < rows.Count; i++)
        {
            Assert.AreEqual(i + 1, rows[i].Seq, "seq must be contiguous from 1");
            var expectedPrev = i == 0 ? new byte[32] : rows[i - 1].RowHash;
            CollectionAssert.AreEqual(expectedPrev, rows[i].PrevHash,
                "prev_hash must link to predecessor row_hash");
        }
    }

    private async Task<ApplicationResponse> RegisterAsync(HttpClient client, Guid teamId, string name)
    {
        var resp = await client.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest(name, "Desc.", teamId));
        Assert.AreEqual(HttpStatusCode.Created, resp.StatusCode,
            $"Expected 201. Body: {await resp.Content.ReadAsStringAsync()}");
        return (await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson))!;
    }

    /// <summary>
    /// Shared arrange step: seeds an owning team for the OrgA tenant and returns
    /// (tenantId, teamId, authenticated OrgAdmin client). Pass <paramref name="nameClaim"/>
    /// when the test asserts <c>actor_display</c>.
    /// </summary>
    private async Task<(Guid TenantId, Guid TeamId, HttpClient Client)> ArrangeAsync(
        string teamName, string? nameClaim = null)
    {
        var tenant = Fx.TenantIdForEmail(OrgAUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(tenant, teamName);
        var client = await Fx.CreateAuthenticatedClientAsync(
            OrgAUser, new[] { KartovaRoles.OrgAdmin }, nameClaim: nameClaim);
        return (tenant.Value, teamId, client);
    }

    // --- Happy: deprecate writes a lifecycle_changed row with from/to ---
    [TestMethod]
    public async Task Deprecate_WritesLifecycleChangedAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit Dep Team");
        var app = await RegisterAsync(client, teamId, "Audit Dep App");

        var sunset = DateTimeOffset.UtcNow.AddDays(30);
        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{app.Id}/deprecate",
            new DeprecateApplicationRequest(sunset));
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode,
            $"Expected 200. Body: {await resp.Content.ReadAsStringAsync()}");

        var rows = await Fx.ReadAuditLogAsync(tenantId);
        var row = rows.Single(r =>
            r.Action == CatalogAuditActions.ApplicationLifecycleChanged &&
            r.TargetId == app.Id.ToString());
        Assert.AreEqual(await Fx.GetSubClaimAsync(OrgAUser), row.ActorId);
        Assert.AreEqual("User", row.ActorType);
        using var data = JsonDocument.Parse(row.DataJson!);
        Assert.AreEqual("Active", data.RootElement.GetProperty("from").GetString());
        Assert.AreEqual("Deprecated", data.RootElement.GetProperty("to").GetString());
        Assert.IsFalse(string.IsNullOrEmpty(data.RootElement.GetProperty("sunsetDate").GetString()));
    }

    // --- Negative: a rejected transition writes no row ---
    [TestMethod]
    public async Task Decommission_BeforeSunset_WritesNoAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit NoRow Team");
        var app = await RegisterAsync(client, teamId, "Audit NoRow App");

        // Deprecate with a far-future sunset, then attempt to decommission before it -> 409.
        var depResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{app.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.AreEqual(HttpStatusCode.OK, depResp.StatusCode);

        var decResp = await client.PostAsync(
            $"/api/v1/catalog/applications/{app.Id}/decommission", content: null);
        Assert.AreEqual(HttpStatusCode.Conflict, decResp.StatusCode,
            $"Expected 409. Body: {await decResp.Content.ReadAsStringAsync()}");

        // Exactly one lifecycle_changed row (the deprecate), none for the rejected decommission.
        var rows = await Fx.ReadAuditLogAsync(tenantId);
        var lifecycleRows = rows.Where(r =>
            r.Action == CatalogAuditActions.ApplicationLifecycleChanged &&
            r.TargetId == app.Id.ToString()).ToList();
        Assert.AreEqual(1, lifecycleRows.Count, "rejected decommission must not write an audit row");
        using var data = JsonDocument.Parse(lifecycleRows[0].DataJson!);
        Assert.AreEqual("Deprecated", data.RootElement.GetProperty("to").GetString());
    }

    // --- Happy: edit writes an application.edited row with the new state ---
    [TestMethod]
    public async Task Edit_WritesApplicationEditedAuditRow()
    {
        var (tenantId, teamId, client) = await ArrangeAsync("Audit Edit Team");
