    // ADR-0110 — successor reference on deprecate.

    [TestMethod]
    public async Task POST_deprecate_with_valid_successor_returns_200_and_sets_successorApplicationId()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
