    [TestMethod]
    public async Task derived_depends_on_appears_with_provenance_and_drives_discovery()
    {
        // Topology: svcS --consumes--> api <--provides-- app --instance-of-- svcT
        // svcS has no direct edge to svcT; the derived depends-on edge is what must drive discovery.
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgAUser), "Graph Derived Team");
        var svcS = await SeedServiceAsync(client, teamId, "derived-consumer");
        var svcT = await SeedServiceAsync(client, teamId, "derived-provider-instance");
        var app = await SeedApplicationAsync(client, teamId, "Provider App");
        var api = await SeedApiAsync(client, teamId, "Orders API");

        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Service, svcT, RelationshipType.InstanceOf, EntityKind.Application, app)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Application, app, RelationshipType.ProvidesApiFor, EntityKind.Api, api)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Service, svcS, RelationshipType.ConsumesApiFrom, EntityKind.Api, api)).StatusCode);

        var resp = await client.GetAsync($"/api/v1/catalog/graph?entityKind=Service&entityId={svcS}&depth=2&direction=all");
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var graph = await resp.Content.ReadFromJsonAsync<GraphResponse>(KartovaApiFixtureBase.WireJson);

        Assert.IsTrue(graph!.Nodes.Any(n => n.Id == svcT), "derived edge must drive discovery of svcT");
        var derived = graph.DerivedEdges.Single(e => e.Source.Id == svcS && e.Target.Id == svcT);
        var path = derived.Paths.Single();
        Assert.AreEqual(api, path.ApiId);
        Assert.AreEqual("Orders API", path.ApiName);
        Assert.AreEqual(app, path.ViaApplicationId);
        Assert.AreEqual("Provider App", path.ViaApplicationDisplayName);
    }

    [TestMethod]
    public async Task explicit_depends_on_suppresses_the_derived_duplicate()
    {
        // Same consume/provide topology PLUS an explicit depends-on svcS->svcT.
        // Expect: persisted edge in Edges, NO derived edge for (svcS, svcT).
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgAUser), "Graph Suppress Team");
        var svcT = await SeedServiceAsync(client, teamId, "Prov Svc 2");
        var svcS = await SeedServiceAsync(client, teamId, "Cons Svc 2");
        var api = await SeedApiAsync(client, teamId, "Billing API");

        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Service, svcT, RelationshipType.ProvidesApiFor, EntityKind.Api, api)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Service, svcS, RelationshipType.ConsumesApiFrom, EntityKind.Api, api)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(client, EntityKind.Service, svcS, RelationshipType.DependsOn, EntityKind.Service, svcT)).StatusCode);

        var resp = await client.GetAsync($"/api/v1/catalog/graph?entityKind=Service&entityId={svcS}&depth=2&direction=all");
        var graph = await resp.Content.ReadFromJsonAsync<GraphResponse>(KartovaApiFixtureBase.WireJson);

        Assert.IsFalse(graph!.DerivedEdges.Any(e => e.Source.Id == svcS && e.Target.Id == svcT),
            "explicit depends-on should suppress the derived duplicate");
        Assert.IsTrue(graph.Edges.Any(e =>
            e.Source.Id == svcS && e.Target.Id == svcT && e.Type == RelationshipType.DependsOn));
    }

    [TestMethod]
    public async Task derived_edges_are_tenant_isolated()
    {
        // Both tenants seed a COMPLETE derived topology (svcS --consumes--> api <--provides-- app --instance-of-- svcT),
        // so each tenant genuinely has its own derived depends-on edge. This proves tenant A's precompute
        // is scoped to tenant A's data, not merely that an incomplete topology trivially yields zero edges.

        // Tenant B: appB / svcTB instance-of appB / apiB provided by appB / svcSB consumes apiB.
        var clientB = await Fx.CreateAuthenticatedClientAsync(OrgBUser);
        var teamB = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgBUser), "Graph Iso Derived B");
        var svcSB = await SeedServiceAsync(clientB, teamB, "iso-consumer-b");
        var svcTB = await SeedServiceAsync(clientB, teamB, "iso-provider-instance-b");
        var appB = await SeedApplicationAsync(clientB, teamB, "Iso App B");
        var apiB = await SeedApiAsync(clientB, teamB, "Iso API B");
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientB, EntityKind.Service, svcTB, RelationshipType.InstanceOf, EntityKind.Application, appB)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientB, EntityKind.Application, appB, RelationshipType.ProvidesApiFor, EntityKind.Api, apiB)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientB, EntityKind.Service, svcSB, RelationshipType.ConsumesApiFrom, EntityKind.Api, apiB)).StatusCode);

        // Tenant A: appA / svcTA instance-of appA / apiA provided by appA / svcSA consumes apiA.
        var clientA = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var teamA = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgAUser), "Graph Iso Derived A");
        var svcSA = await SeedServiceAsync(clientA, teamA, "iso-consumer-a");
        var svcTA = await SeedServiceAsync(clientA, teamA, "iso-provider-instance-a");
        var appA = await SeedApplicationAsync(clientA, teamA, "Iso App A");
        var apiA = await SeedApiAsync(clientA, teamA, "Iso API A");
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientA, EntityKind.Service, svcTA, RelationshipType.InstanceOf, EntityKind.Application, appA)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientA, EntityKind.Application, appA, RelationshipType.ProvidesApiFor, EntityKind.Api, apiA)).StatusCode);
        Assert.AreEqual(HttpStatusCode.Created,
            (await PostRelAsync(clientA, EntityKind.Service, svcSA, RelationshipType.ConsumesApiFrom, EntityKind.Api, apiA)).StatusCode);

        var resp = await clientA.GetAsync($"/api/v1/catalog/graph?entityKind=service&entityId={svcSA}&depth=2&direction=all");
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var graph = await resp.Content.ReadFromJsonAsync<GraphResponse>(KartovaApiFixtureBase.WireJson);

        Assert.AreEqual(1, graph!.DerivedEdges.Count, "tenant A must see exactly its own derived edge");
        var derived = graph.DerivedEdges.Single();
        Assert.AreEqual(svcSA, derived.Source.Id);
        Assert.AreEqual(svcTA, derived.Target.Id);

        var leakedIds = new[] { svcSB, svcTB, appB, apiB };
        Assert.IsFalse(graph.Nodes.Any(n => leakedIds.Contains(n.Id)),
            "no tenant-B node should leak into tenant A's graph nodes");
        Assert.IsFalse(graph.DerivedEdges.Any(e => leakedIds.Contains(e.Source.Id) || leakedIds.Contains(e.Target.Id)),
            "no tenant-B id should appear in tenant A's derived edges");
    }
}

using System.Net;
using System.Net.Http.Json;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.Testing.Auth;

namespace Kartova.Catalog.IntegrationTests;

[TestClass]
public class GetServiceByIdTests : CatalogIntegrationTestBase
{
    private const string OrgAUser = "admin@orga.kartova.local";
    private const string OrgBUser = "admin@orgb.kartova.local";

    private static async Task<ServiceResponse> RegisterAsync(HttpClient client, string email)
    {
        var teamId = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(email), "Get Team");
        var resp = await client.PostAsJsonAsync("/api/v1/catalog/services", new
        {
            displayName = "get-svc", description = "d", teamId,
            endpoints = new[] { new { url = "https://api.example.com", protocol = Protocol.Rest } },
        });
        Assert.IsTrue(resp.IsSuccessStatusCode);
        return (await resp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson))!;
    }

    [TestMethod]
    public async Task GET_returns_200_for_service_in_same_tenant()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var created = await RegisterAsync(client, OrgAUser);
        var resp = await client.GetAsync($"/api/v1/catalog/services/{created.Id}");
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var body = await resp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson);
        Assert.AreEqual(created.Id, body!.Id);
    }

    [TestMethod]
    public async Task GET_returns_404_for_nonexistent_id()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var resp = await client.GetAsync($"/api/v1/catalog/services/{Guid.NewGuid()}");
        Assert.AreEqual(HttpStatusCode.NotFound, resp.StatusCode);
    }

    [TestMethod]
    public async Task GET_returns_404_for_other_tenants_id()
    {
        var orgA = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var created = await RegisterAsync(orgA, OrgAUser);
        var orgB = await Fx.CreateAuthenticatedClientAsync(OrgBUser);
        var resp = await orgB.GetAsync($"/api/v1/catalog/services/{created.Id}");
        Assert.AreEqual(HttpStatusCode.NotFound, resp.StatusCode);
    }

    // F13(a): multi-endpoint round-trip — url, protocol, and order are preserved
    [TestMethod]
    public async Task GET_returns_endpoints_with_correct_url_protocol_and_order()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgAUser), "Get Team Multi");
        var registerResp = await client.PostAsJsonAsync("/api/v1/catalog/services", new
        {
            displayName = "multi-ep-svc", description = "endpoint round-trip test", teamId,
            endpoints = new[]
            {
                new { url = "https://api.example.com/rest", protocol = Protocol.Rest },
                new { url = "grpc://api.example.com:443", protocol = Protocol.Grpc },
            },
        });
        Assert.IsTrue(registerResp.IsSuccessStatusCode);
        var created = (await registerResp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson))!;

        var resp = await client.GetAsync($"/api/v1/catalog/services/{created.Id}");
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var body = await resp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson);
        Assert.AreEqual(2, body!.Endpoints.Count);
        Assert.AreEqual("https://api.example.com/rest", body.Endpoints[0].Url);
        Assert.AreEqual(Protocol.Rest, body.Endpoints[0].Protocol);
        Assert.AreEqual("grpc://api.example.com:443", body.Endpoints[1].Url);
        Assert.AreEqual(Protocol.Grpc, body.Endpoints[1].Protocol);
    }

    // F13(b): zero-endpoint round-trip — Endpoints is non-null and empty; Health is Unknown
    [TestMethod]
    public async Task GET_returns_empty_endpoints_and_unknown_health_for_zero_endpoint_service()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(Fx.TenantIdForEmail(OrgAUser), "Get Team Zero");
        var registerResp = await client.PostAsJsonAsync("/api/v1/catalog/services", new
        {
            displayName = "zero-ep-svc", description = "zero endpoint round-trip test", teamId,
            endpoints = Array.Empty<object>(),
        });
        Assert.IsTrue(registerResp.IsSuccessStatusCode);
        var created = (await registerResp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson))!;

        var resp = await client.GetAsync($"/api/v1/catalog/services/{created.Id}");
        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var body = await resp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson);
        Assert.IsNotNull(body!.Endpoints);
        Assert.AreEqual(0, body.Endpoints.Count);
        Assert.AreEqual(HealthStatus.Unknown, body.Health);
    }

    // F10 (gate9 SF-2): CreatedBy enrichment — GET by id returns non-null CreatedBy whose
    // display fields match the registering user (mirrors ApplicationOwnerEnrichmentTests).
    [TestMethod]
    public async Task GET_returns_CreatedBy_populated_when_user_row_exists()
    {
        var unique = $"svc-creator-{Guid.NewGuid():N}";
        var tenantId = Fx.TenantIdForEmail(OrgAUser);
        var creatorUserId = await Fx.SeedUserInOrganizationAsync(
            tenantId,
            displayName: "Service Creator",
            email: $"{unique}@orga.kartova.local");

        var client = await Fx.CreateAuthenticatedClientAsync(
            OrgAUser, subjectOverride: creatorUserId);
        var teamId = await Fx.SeedTeamInOrganizationAsync(tenantId, "Get Team Enrich");
        var registerResp = await client.PostAsJsonAsync("/api/v1/catalog/services", new
        {
            displayName = $"enrich-svc-{unique}",
            description = "CreatedBy enrichment test.",
            teamId,
            endpoints = Array.Empty<object>(),
        });
        Assert.IsTrue(registerResp.IsSuccessStatusCode);
        var created = (await registerResp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson))!;

        try
        {
            var resp = await client.GetAsync($"/api/v1/catalog/services/{created.Id}");
            Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
            var body = await resp.Content.ReadFromJsonAsync<ServiceResponse>(KartovaApiFixtureBase.WireJson);
            Assert.IsNotNull(body!.CreatedBy,
                "CreatedBy must be populated when a matching users row exists.");
            Assert.AreEqual(creatorUserId, body.CreatedBy!.Id);
            Assert.AreEqual("Service Creator", body.CreatedBy.DisplayName);
            Assert.AreEqual($"{unique}@orga.kartova.local", body.CreatedBy.Email);
        }
        finally
        {
            await Fx.DeleteUserInOrganizationAsync(creatorUserId);
        }
    }
}

namespace Kartova.Catalog.IntegrationTests;

/// <summary>
/// Assembly-scoped singleton that hosts the shared <see cref="KartovaApiFixture"/>
/// for every Catalog API integration test class. Exactly one Postgres Testcontainer
/// + EF migration run + <see cref="Microsoft.AspNetCore.Mvc.Testing.WebApplicationFactory{Program}"/>
/// per assembly run, regardless of how many derived test classes exist.
///
/// Requires <c>[assembly: DoNotParallelize]</c> (see <c>Properties/AssemblyInfo.cs</c>):
/// integration tests serialise at the class level, so the single shared fixture is
/// never accessed concurrently.
/// </summary>
[TestClass]
public sealed class IntegrationTestAssemblySetup
{
    public static KartovaApiFixture Fx { get; private set; } = null!;

    [AssemblyInitialize]
    public static async Task InitAsync(TestContext _)
    {
        Fx = new KartovaApiFixture();
        await Fx.InitializeAsync();
    }

    [AssemblyCleanup]
    public static async Task CleanupAsync()
    {
        // MSTest only invokes [AssemblyCleanup] if [AssemblyInitialize] completed —
        // Fx is guaranteed non-null here.
        await ((IAsyncDisposable)Fx).DisposeAsync();
    }
}

using System.Diagnostics.CodeAnalysis;
using System.Net.Http.Headers;
using Kartova.Catalog.Domain;
using Kartova.Catalog.Infrastructure;
using Kartova.Audit.Infrastructure;
using Kartova.Organization.Infrastructure;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Time.Testing;
using DomainApplication = Kartova.Catalog.Domain.Application;

namespace Kartova.Catalog.IntegrationTests;

/// <summary>
/// Catalog-specific fixture. All cross-module plumbing (Postgres container,
/// role bootstrap, JWT signer wiring, env-var wiring of the Kartova.Api host,
/// JWT minting helpers) lives in <see cref="KartovaApiFixtureBase"/>; this
/// type only declares which DbContexts to migrate.
///
/// Slice 8 — migrates the Organization schema too: the Catalog module's
/// <c>AssignApplicationTeamHandler</c> resolves the cross-module
/// <c>IOrganizationTeamExistenceChecker</c>, which queries <c>teams</c>.
/// Without that table the PUT /applications/{id}/team endpoint would throw on
/// a missing relation rather than evaluate the 422 invalid-team branch.
/// </summary>
[ExcludeFromCodeCoverage]
public class KartovaApiFixture : KartovaApiFixtureBase
{
    protected override async Task RunModuleMigrationsAsync(string migratorConnectionString)
    {
        await PostgresTestBootstrap.RunMigrationsAsync<CatalogDbContext>(
            migratorConnectionString,
            opts => new CatalogDbContext(opts));
        await PostgresTestBootstrap.RunMigrationsAsync<OrganizationDbContext>(
            migratorConnectionString,
            opts => new OrganizationDbContext(opts));
        // Audit event-wiring: AuditWiringTests assert rows in audit_log; the table must exist
        // before the test host starts. Mirrors the Organization fixture.
        await PostgresTestBootstrap.RunMigrationsAsync<AuditDbContext>(
            migratorConnectionString,
            opts => new AuditDbContext(opts));
    }

    /// <summary>
    /// Creates an HTTP client with a bearer token scoped to OrgA
    /// ("admin@orga.kartova.local"). Synchronous overload for tests that
    /// cannot await during field initialisation.
    /// </summary>
    public HttpClient CreateClientForOrgA() => CreateClientForEmail("admin@orga.kartova.local");

    /// <summary>
    /// Creates an HTTP client with a bearer token scoped to OrgB
    /// ("admin@orgb.kartova.local").
    /// </summary>
    public HttpClient CreateClientForOrgB() => CreateClientForEmail("admin@orgb.kartova.local");

    private HttpClient CreateClientForEmail(string email)
    {
        // Reuse the deterministic sub + tenant derivation from the base class
        // by issuing a token directly via the TestJwtSigner — mirrors what
        // CreateAuthenticatedClientAsync does but without the async wrapper.
        var tenant = TenantFor(email);
        var token = Signer.IssueForTenant(tenant, [KartovaRoles.OrgAdmin], subject: SubFor(email).ToString());
        var client = CreateClient();
        client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token);
        return client;
    }

    /// <summary>
    /// Returns the deterministic <see cref="TenantId"/> for <paramref name="email"/>'s
    /// domain — the same value RLS uses. Exposed so test classes can seed rows for
    /// the correct tenant without re-implementing the derivation algorithm.
    /// </summary>
    public TenantId TenantIdForEmail(string email) => TenantFor(email);

    /// <summary>
    /// Seeds <paramref name="count"/> applications for the given tenant, with
    /// spread-apart <c>createdAt</c> timestamps so sort-by-createdAt tests are
    /// deterministic. Uses the bypass-RLS connection so rows can be inserted
    /// without an active tenant scope. <paramref name="namePrefix"/> drives the
    /// <c>displayName</c> column (ADR-0098: the kebab <c>name</c> column was dropped).
    /// </summary>
    public async Task SeedApplicationsAsync(TenantId tenantId, int count, string namePrefix)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;

        await using var db = new CatalogDbContext(opts);
        var origin = DateTimeOffset.UtcNow.AddMinutes(-count);
        for (var i = 0; i < count; i++)
        {
            // ADR-0103: TeamId is required. These pagination/RLS fixtures never join to
            // a teams row, so a fresh id satisfies the non-null invariant (no FK exists).
            db.Applications.Add(DomainApplication.Create(
                displayName: $"{namePrefix}{i:D3}",
                description: "seeded for pagination tests",
                createdByUserId: Guid.NewGuid(),
                teamId: Guid.NewGuid(),
                tenantId: tenantId,
                createdAt: origin.AddMinutes(i)));
        }
        await db.SaveChangesAsync();
    }

    /// <summary>
    /// Deletes a single application row, bypassing RLS so the delete is not
    /// blocked by the missing tenant scope.
    /// </summary>
    public async Task DeleteApplicationAsync(TenantId tenantId, Guid applicationId)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;

        await using var db = new CatalogDbContext(opts);
        await db.Database.ExecuteSqlRawAsync(
            "DELETE FROM catalog_applications WHERE id = {0} AND tenant_id = {1}",
            applicationId, tenantId.Value);
    }

    /// <summary>
    /// Seeds <paramref name="count"/> applications in the given lifecycle state
    /// for the given tenant, with spread-apart <c>createdAt</c> timestamps.
    /// Slice 6 — used by ListApplicationsPaginationTests to populate Decommissioned
    /// rows that ADR-0073's default-view filter must hide.
    /// </summary>
    public async Task SeedApplicationsWithLifecycleAsync(
        TenantId tenantId,
        int count,
        string namePrefix,
        Lifecycle lifecycle)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;

        await using var db = new CatalogDbContext(opts);
        var origin = DateTimeOffset.UtcNow.AddMinutes(-count);
        for (var i = 0; i < count; i++)
        {
            var app = DomainApplication.Create(
                displayName: $"{namePrefix}{i:D3}",
                description: "seeded for filter tests",
                createdByUserId: Guid.NewGuid(),
                teamId: Guid.NewGuid(),
                tenantId: tenantId,
                createdAt: origin.AddMinutes(i));

            // Drive the aggregate into the desired terminal state via its own methods,
            // not by reflection on the private setter — keeps the test honest about
            // what the production state machine actually does.
            if (lifecycle == Lifecycle.Deprecated || lifecycle == Lifecycle.Decommissioned)
            {
                var clock = new FakeTimeProvider();
                clock.SetUtcNow(origin.AddMinutes(i).AddHours(1));
                app.Deprecate(sunsetDate: clock.GetUtcNow().AddMinutes(1), clock);

                if (lifecycle == Lifecycle.Decommissioned)
                {
                    // Advance the same clock past the sunset date so Decommission's
                    // "now >= SunsetDate" invariant holds. Using one provider makes the
                    // temporal relationship explicit; otherwise a future tweak to the first
                    // clock could silently invalidate the decommission step.
                    clock.SetUtcNow(origin.AddMinutes(i).AddHours(2));
                    app.Decommission(clock);
                }
            }

            db.Applications.Add(app);
        }
        await db.SaveChangesAsync();
    }

    /// <summary>
    /// Deletes application rows for a tenant whose <c>DisplayName</c> starts with
    /// <paramref name="namePrefix"/>. Use in test teardown when the test seeded
    /// rows with a unique (e.g., Guid-suffixed) prefix — preserves rows seeded
    /// by other tests in the same class fixture. Slice 6.
    /// <para>
    /// ADR-0098 / slice 8: previously this filtered on the <c>name</c> column;
    /// after the kebab slug was retired, callers pass display-name-prefix strings
    /// (via <see cref="SeedApplicationsAsync"/> / <see cref="SeedApplicationsWithLifecycleAsync"/>
    /// which now write to <c>display_name</c>), so we filter on <c>display_name</c>.
    /// </para>
    /// </summary>
    public async Task DeleteApplicationsByPrefixAsync(TenantId tenantId, string namePrefix)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;

        await using var db = new CatalogDbContext(opts);
        await db.Database.ExecuteSqlRawAsync(
            "DELETE FROM catalog_applications WHERE tenant_id = {0} AND display_name LIKE {1} || '%'",
            tenantId.Value, namePrefix);
    }

    /// <summary>
    /// Seeds a single Catalog application for a tenant and returns its id.
    /// Used by slice-8 assign-team tests that need exactly one row. ADR-0103:
    /// TeamId is required — when <paramref name="teamId"/> is null the app is
    /// owned by a fresh, unrelated team id (callers that don't care about team
    /// membership); pass an explicit team id when the test joins to a teams row.
    /// Bypass-RLS so RLS does not block the insert.
    /// </summary>
    public async Task<Guid> SeedSingleApplicationAsync(
        TenantId tenantId, Guid createdByUserId, Guid? teamId, string? namePrefix = null)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;
        await using var db = new CatalogDbContext(opts);

        var name = (namePrefix ?? "assign-app") + "-" + Guid.NewGuid().ToString("N").Substring(0, 8);
        var app = DomainApplication.Create(
            displayName: name,
            description: "seeded for assign-team tests",
            createdByUserId: createdByUserId,
            teamId: teamId ?? Guid.NewGuid(),
            tenantId: tenantId,
            createdAt: DateTimeOffset.UtcNow);

        db.Applications.Add(app);
        await db.SaveChangesAsync();
        return app.Id.Value;
    }

    /// <summary>
    /// Inserts a team row directly into the Organization schema via BYPASSRLS so
    /// the Catalog AssignApplicationTeam endpoint's cross-module existence check
    /// (<c>IOrganizationTeamExistenceChecker</c>) finds a real row in the active
    /// tenant. Returns the new team's id. Slice 8.
    /// </summary>
    public async Task<Guid> SeedTeamInOrganizationAsync(TenantId tenantId, string displayName)
    {
        var teamId = Guid.NewGuid();
        await using var conn = new Npgsql.NpgsqlConnection(BypassConnectionString);
        await conn.OpenAsync();
        await using var cmd = conn.CreateCommand();
        cmd.CommandText = """
            INSERT INTO teams (id, tenant_id, display_name, description, created_at)
            VALUES ($1, $2, $3, NULL, NOW())
            """;
        cmd.Parameters.AddWithValue(teamId);
        cmd.Parameters.AddWithValue(tenantId.Value);
        cmd.Parameters.AddWithValue(displayName);
        await cmd.ExecuteNonQueryAsync();
        return teamId;
    }

    /// <summary>
    /// Seeds a <c>users</c> row in the Organization schema via BYPASSRLS. Slice 9
    /// / E1 — exercised by the Catalog list+detail handlers, which join through
    /// <c>IUserDirectory</c> to enrich <c>ApplicationResponse.Owner</c>. Mirrors
    /// <see cref="SeedTeamInOrganizationAsync"/> for consistency. Columns line up
    /// with <c>UserEntityTypeConfiguration</c> + the <c>AddUsersTable</c> migration.
    /// </summary>
    public async Task<Guid> SeedUserInOrganizationAsync(
        TenantId tenantId, string displayName, string email)
    {
        var userId = Guid.NewGuid();
        await using var conn = new Npgsql.NpgsqlConnection(BypassConnectionString);
        await conn.OpenAsync();
        await using var cmd = conn.CreateCommand();
        cmd.CommandText = """
            INSERT INTO users (id, tenant_id, email, display_name, created_at)
            VALUES ($1, $2, $3, $4, NOW())
            """;
        cmd.Parameters.AddWithValue(userId);
        cmd.Parameters.AddWithValue(tenantId.Value);
        cmd.Parameters.AddWithValue(email);
        cmd.Parameters.AddWithValue(displayName);
        await cmd.ExecuteNonQueryAsync();
        return userId;
    }

    /// <summary>
    /// Deletes a single <c>users</c> row via BYPASSRLS. Slice 9 / E1 cleanup hook
    /// for tests that seeded a directory user to verify Owner enrichment.
    /// </summary>
    public async Task DeleteUserInOrganizationAsync(Guid userId)
    {
        await using var conn = new Npgsql.NpgsqlConnection(BypassConnectionString);
        await conn.OpenAsync();
        await using var cmd = conn.CreateCommand();
        cmd.CommandText = "DELETE FROM users WHERE id = $1";
        cmd.Parameters.AddWithValue(userId);
        await cmd.ExecuteNonQueryAsync();
    }

    /// <summary>
    /// Seeds a team_members row directly via BYPASSRLS. <paramref name="roleByte"/>
    /// matches <c>TeamRole</c> (1 = Member, 2 = Admin). Idempotent.
    /// </summary>
    public async Task SeedTeamMembershipAsync(Guid teamId, Guid userId, byte roleByte)
    {
        var opts = new DbContextOptionsBuilder<OrganizationDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;
        await using var db = new OrganizationDbContext(opts);
        await db.Database.ExecuteSqlRawAsync(
            "INSERT INTO team_members (team_id, user_id, role, added_at) VALUES ({0}, {1}, {2}, NOW()) ON CONFLICT (team_id, user_id) DO NOTHING",
            teamId, userId, (int)roleByte);
    }

    /// <summary>
    /// Forces an application's lifecycle column directly via BYPASSRLS, skipping
    /// domain transition guards. Slice 8 — used by the assign-team endpoint
    /// tests to put a freshly-seeded app into Decommissioned without driving
    /// through Active → Deprecated → Decommissioned via the HTTP endpoints.
    /// </summary>
    public async Task SetApplicationLifecycleAsync(Guid applicationId, Lifecycle lifecycle)
    {
        var opts = new DbContextOptionsBuilder<CatalogDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;
        await using var db = new CatalogDbContext(opts);
        await db.Database.ExecuteSqlRawAsync(
            "UPDATE catalog_applications SET lifecycle = {0} WHERE id = {1}",
            (short)lifecycle, applicationId);
    }

    /// <summary>
    /// Removes every team + team_members row for a tenant. Two-step is defensive
    /// (a follow-up FK migration adds <c>ON DELETE CASCADE</c>, so the explicit
    /// <c>team_members</c> wipe is redundant but harmless and remains explicit).
    /// </summary>
    public async Task DeleteTeamsForTenantAsync(Guid tenantId)
    {
        var opts = new DbContextOptionsBuilder<OrganizationDbContext>()
            .UseNpgsql(BypassConnectionString)
            .Options;
        await using var db = new OrganizationDbContext(opts);
        await db.Database.ExecuteSqlRawAsync(
            "DELETE FROM team_members WHERE team_id IN (SELECT id FROM teams WHERE tenant_id = {0})",
            tenantId);
        await db.Database.ExecuteSqlRawAsync(
            "DELETE FROM teams WHERE tenant_id = {0}",
            tenantId);
    }

    /// <summary>Reads audit_log rows for a tenant via the BYPASSRLS pool, ordered by seq.</summary>
    public async Task<IReadOnlyList<AuditRowRecord>> ReadAuditLogAsync(Guid tenantId)
    {
        await using var conn = new Npgsql.NpgsqlConnection(BypassConnectionString);
        await conn.OpenAsync();
        await using var cmd = conn.CreateCommand();
        cmd.CommandText = """
            SELECT seq, action, actor_id, actor_display, target_type, target_id,
                   data::text, prev_hash, row_hash, actor_type
            FROM audit_log WHERE tenant_id = $1 ORDER BY seq
            """;
        cmd.Parameters.AddWithValue(tenantId);
        var rows = new List<AuditRowRecord>();
        await using var r = await cmd.ExecuteReaderAsync();
        while (await r.ReadAsync())
        {
            rows.Add(new AuditRowRecord(
                r.GetInt64(0), r.GetString(1),
                r.IsDBNull(2) ? null : r.GetGuid(2),
                r.IsDBNull(3) ? null : r.GetString(3),
                r.GetString(4), r.GetString(5),
                r.IsDBNull(6) ? null : r.GetString(6),
                (byte[])r[7], (byte[])r[8],
                r.GetString(9)));
        }
        return rows;
    }

    public sealed record AuditRowRecord(
        long Seq, string Action, Guid? ActorId, string? ActorDisplay,
        string TargetType, string TargetId, string? DataJson, byte[] PrevHash, byte[] RowHash,
        string ActorType);
}

