namespace Kartova.Catalog.IntegrationTests;

/// <summary>
/// Real-seam tests for PUT /applications/{id}/successor (ADR-0110). Mirrors
/// <see cref="DeprecateApplicationTests"/>'s structure and helpers. PUT is
/// idempotent replacement (ADR-0096) — a null body clears the successor.
///
/// Existence pre-check (delegate) → 422 invalid-successor for an unknown or
/// cross-tenant id. Domain guards (<c>Application.SetSuccessor</c>) own 409 for a
/// not-Deprecated source and 400 for a self-successor id — this file does not
/// duplicate either guard, only asserts the resulting envelope.
/// </summary>
[TestClass]
public sealed class SetApplicationSuccessorTests : CatalogIntegrationTestBase
{
    private const string OrgAUser = "admin@orga.kartova.local";
    private const string OrgBUser = "admin@orgb.kartova.local";

    [TestMethod]
    public async Task PUT_successor_on_Deprecated_app_with_valid_same_tenant_successor_returns_200_and_sets_it()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 1", "Desc.");
        var successor = await RegisterAsync(client, "Successor App 1", "Desc.");

        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var resp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(successor.Id));

        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var body = await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);
        Assert.AreEqual(successor.Id, body!.SuccessorApplicationId);
    }

    [TestMethod]
    public async Task PUT_successor_on_Deprecated_app_with_existing_successor_to_null_returns_200_and_clears_it()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 2", "Desc.");
        var successor = await RegisterAsync(client, "Successor App 2", "Desc.");

        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var setResp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(successor.Id));
        Assert.IsTrue(setResp.IsSuccessStatusCode);

        var clearResp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(null));

        Assert.AreEqual(HttpStatusCode.OK, clearResp.StatusCode);
        var body = await clearResp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);
        Assert.IsNull(body!.SuccessorApplicationId);
    }

    [TestMethod]
    public async Task PUT_successor_on_Active_app_returns_409()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 3", "Desc.");
        var successor = await RegisterAsync(client, "Successor App 3", "Desc.");

        var resp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(successor.Id));

        Assert.AreEqual(HttpStatusCode.Conflict, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.LifecycleConflict, problem!.Type);
        Assert.AreEqual("active", problem.CurrentLifecycle);
    }

    [TestMethod]
    public async Task PUT_successor_on_Decommissioned_app_returns_409()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 4", "Desc.");
        var successor = await RegisterAsync(client, "Successor App 4", "Desc.");

        // Drive Active → Deprecated → Decommissioned via the far-future-sunset +
        // OrgAdmin overrideSunset path (DecommissionApplicationTests' fast route —
        // avoids a real-time Task.Delay past a near sunsetDate).
        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var decommissionResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/decommission",
            new DecommissionApplicationRequest(OverrideSunset: true));
        Assert.IsTrue(decommissionResp.IsSuccessStatusCode);

        var resp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(successor.Id));

        Assert.AreEqual(HttpStatusCode.Conflict, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.LifecycleConflict, problem!.Type);
        Assert.AreEqual("decommissioned", problem.CurrentLifecycle);
    }

    [TestMethod]
    public async Task PUT_successor_on_Deprecated_app_with_unknown_successor_id_returns_422()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 5", "Desc.");

        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var resp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(Guid.NewGuid()));

        Assert.AreEqual(HttpStatusCode.UnprocessableEntity, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.InvalidSuccessor, problem!.Type);
    }

    [TestMethod]
    public async Task PUT_successor_on_Deprecated_app_with_self_id_returns_400()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Target 6", "Desc.");

        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var resp = await client.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(target.Id));

        Assert.AreEqual(HttpStatusCode.BadRequest, resp.StatusCode);
        // Self-reference is a domain guard (RejectSelfSuccessor → ArgumentException),
        // mapped to the generic validation-failed envelope — pin the type so a future
        // change to the mapping (e.g. a dedicated successor-self-reference type) is a
        // conscious decision, matching the sibling assertion in DeprecateApplicationTests.
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.ValidationFailed, problem!.Type);
    }

    [TestMethod]
    public async Task PUT_successor_on_Deprecated_app_with_cross_tenant_successor_id_returns_422()
    {
        // The successor id resolves to a REAL application — but in another tenant.
        // RejectUnknownSuccessorAsync's existence check runs under RLS, so the OrgB
        // row is invisible to OrgA and collapses to the same 422 as an unknown id.
        // This is the case that actually proves cross-tenant successor linkage is
        // impossible: a random Guid (the test above) would 422 even if RLS scoping
        // were broken; a real cross-tenant id would leak through if it were.
        var orgA = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(orgA, "Successor XT Target", "Desc.");

        var deprecateResp = await orgA.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var orgBSuccessor = await RegisterInOrgBAsync("Cross-Tenant Successor");

        var resp = await orgA.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(orgBSuccessor.Id));

        Assert.AreEqual(HttpStatusCode.UnprocessableEntity, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.InvalidSuccessor, problem!.Type);
    }

    [TestMethod]
    public async Task PUT_successor_set_change_clear_writes_successor_changed_audit_rows_with_from_to()
    {
        // Accountability: each set/change/clear must emit an application.successor_changed
        // row capturing the transition. The deprecate-time path only ever writes from=null;
        // the change (A→B) and clear (B→null) transitions are unique to the PUT path.
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var target = await RegisterAsync(client, "Successor Audit Target", "Desc.");
        var appA = await RegisterAsync(client, "Successor Audit A", "Desc.");
        var appB = await RegisterAsync(client, "Successor Audit B", "Desc.");

        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        foreach (var successor in new Guid?[] { appA.Id, appB.Id, null })
        {
            var put = await client.PutAsJsonAsync(
                $"/api/v1/catalog/applications/{target.Id}/successor",
                new SetApplicationSuccessorRequest(successor));
            Assert.IsTrue(put.IsSuccessStatusCode);
        }

        var tenantId = Fx.TenantIdForEmail(OrgAUser);
        var rows = (await Fx.ReadAuditLogAsync(tenantId.Value))
            .Where(r => r.Action == CatalogAuditActions.ApplicationSuccessorChanged
                        && r.TargetId == target.Id.ToString())
            .OrderBy(r => r.Seq)
            .ToList();

        Assert.AreEqual(3, rows.Count);
        AssertFromTo(rows[0].DataJson!, from: null, to: appA.Id.ToString());
        AssertFromTo(rows[1].DataJson!, from: appA.Id.ToString(), to: appB.Id.ToString());
        AssertFromTo(rows[2].DataJson!, from: appB.Id.ToString(), to: null);
    }

    private static void AssertFromTo(string dataJson, string? from, string? to)
    {
        using var data = JsonDocument.Parse(dataJson);
        Assert.AreEqual(from, data.RootElement.GetProperty("from").GetString());
        Assert.AreEqual(to, data.RootElement.GetProperty("to").GetString());
    }

    [TestMethod]
    public async Task PUT_successor_as_non_member_of_the_apps_team_returns_403()
    {
        var admin = await Fx.CreateAuthenticatedClientAsync(OrgAUser);
        var tenant = Fx.TenantIdForEmail(OrgAUser);
        var appTeamId = await Fx.SeedTeamInOrganizationAsync(tenant, "Successor 403 App Team");
        var registerResp = await admin.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest("Successor Target 7", "Desc.", appTeamId));
        Assert.IsTrue(registerResp.IsSuccessStatusCode);
        var target = (await registerResp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson))!;
        var successor = await RegisterAsync(admin, "Successor App 7", "Desc.");

        var deprecateResp = await admin.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        // A Member seeded onto a DIFFERENT team in the SAME tenant: visible under RLS
        // (so LoadAndAuthorizeApplicationAsync's existence check passes, ruling out
        // 404), but fails ApplicationTeamScoped (not OrgAdmin, not a member of the
        // app's own team "Successor 403 App Team") — Forbid() before the command
        // dispatches. Mirrors DecommissionApplicationTests' override-403 test's
        // seeding mechanics, but the member team is deliberately NOT the app's team
        // (that test does the opposite, to clear this same gate before testing a
        // different, deeper one).
        var otherTeamId = await Fx.SeedTeamInOrganizationAsync(tenant, "Successor 403 Other Team");
        const string memberEmail = "member-successor-403@orga.kartova.local";
        var member = await Fx.CreateAuthenticatedClientAsync(memberEmail, new[] { KartovaRoles.Member });
        var memberId = await Fx.GetSubClaimAsync(memberEmail);
        await Fx.SeedTeamMembershipAsync(otherTeamId, memberId, roleByte: 1 /* Member */);

        var resp = await member.PutAsJsonAsync(
            $"/api/v1/catalog/applications/{target.Id}/successor",
            new SetApplicationSuccessorRequest(successor.Id));

        Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
    }

    // ADR-0103: register requires a valid owning team in the tenant. All callers
    // register as OrgA, so seed the team in OrgA's tenant (BYPASSRLS, idempotent).
    private async Task<ApplicationResponse> RegisterAsync(HttpClient client, string displayName, string description)
    {
        var teamId = await Fx.SeedTeamInOrganizationAsync(
            Fx.TenantIdForEmail(OrgAUser), "Lifecycle Team");
        var resp = await client.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest(displayName, description, teamId));
        Assert.IsTrue(resp.IsSuccessStatusCode);
        return (await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson))!;
    }

    // Registers an application in OrgB's tenant (its own team, seeded BYPASSRLS) so
    // OrgA can reference it as a would-be cross-tenant successor. The row is real but
    // invisible to OrgA under RLS.
    private async Task<ApplicationResponse> RegisterInOrgBAsync(string displayName)
    {
        var orgB = await Fx.CreateAuthenticatedClientAsync(OrgBUser);
        var teamId = await Fx.SeedTeamInOrganizationAsync(
            Fx.TenantIdForEmail(OrgBUser), "OrgB Lifecycle Team");
        var resp = await orgB.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest(displayName, "Desc.", teamId));
        Assert.IsTrue(resp.IsSuccessStatusCode);
        return (await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson))!;
    }

    // Helper for parsing ProblemDetails responses — mirrors DeprecateApplicationTests'
    // identical nested class (itself mirroring EditApplicationTests). Acceptable
    // duplication per that file's existing comment; a shared helper could be
    // extracted later if desired.
    private sealed class ProblemPayload
    {
        public string Type { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public int Status { get; set; }
        public string? Detail { get; set; }
        public Dictionary<string, string[]> Errors { get; set; } = new();
        public string? CurrentVersion { get; set; }
        public string? CurrentLifecycle { get; set; }
        public string? AttemptedTransition { get; set; }
    }
}

using System.Net;
using System.Net.Http.Json;
using Kartova.Catalog.Contracts;
using Kartova.Catalog.Domain;
using Kartova.SharedKernel.AspNetCore;
using Kartova.SharedKernel.Multitenancy;
using Kartova.Testing.Auth;

namespace Kartova.Catalog.IntegrationTests;

[TestClass]
public sealed class UnDecommissionApplicationTests : CatalogIntegrationTestBase
{
    private const string OrgAdminEmail = "admin@orga.kartova.local";
    private const string MemberEmail   = "member@orga.kartova.local";

    [TestMethod]
    public async Task POST_un_decommission_from_Decommissioned_returns_200_with_Deprecated_state_and_new_sunsetDate()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var registered = await RegisterAsync(client, "UnDecommission App 1", "Desc.");

        // Active → Deprecated (with near-future sunset) → Decommissioned (wait past sunset).
        var sunset = DateTimeOffset.UtcNow.AddSeconds(1);
        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/deprecate",
            new DeprecateApplicationRequest(sunset));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        await Task.Delay(2000);

        var decommissionResp = await client.PostAsync(
            $"/api/v1/catalog/applications/{registered.Id}/decommission",
            content: null);
        Assert.IsTrue(decommissionResp.IsSuccessStatusCode);

        // Now un-decommission with a new future sunsetDate.
        var newSunset = DateTimeOffset.UtcNow.AddDays(30);
        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/un-decommission",
            new { sunsetDate = newSunset });

        Assert.AreEqual(HttpStatusCode.OK, resp.StatusCode);
        var body = await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);
        Assert.AreEqual(Lifecycle.Deprecated, body!.Lifecycle);
        Assert.IsNotNull(body.SunsetDate);
        var diff = (body.SunsetDate!.Value - newSunset).Duration();
        Assert.IsTrue(diff <= TimeSpan.FromSeconds(1));

        // Follow-up GET — confirms the lifecycle change persisted across the request boundary
        // (kills the SaveChangesAsync-removed mutation: without persistence the in-memory state
        // would be lost on a second request).
        var followUp = await client.GetAsync($"/api/v1/catalog/applications/{registered.Id}");
        Assert.AreEqual(HttpStatusCode.OK, followUp.StatusCode);
        var persisted = await followUp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson);
        Assert.AreEqual(Lifecycle.Deprecated, persisted!.Lifecycle);
        Assert.IsNotNull(persisted.SunsetDate);
        var persistedDiff = (persisted.SunsetDate!.Value - newSunset).Duration();
        Assert.IsTrue(persistedDiff <= TimeSpan.FromSeconds(1));
    }

    [TestMethod]
    public async Task POST_un_decommission_from_Deprecated_returns_409_lifecycle_conflict()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var registered = await RegisterAsync(client, "UnDecommission App 2", "Desc.");

        // Deprecate (Active → Deprecated), then immediately try un-decommission.
        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/deprecate",
            new DeprecateApplicationRequest(DateTimeOffset.UtcNow.AddDays(30)));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/un-decommission",
            new { sunsetDate = DateTimeOffset.UtcNow.AddDays(60) });

        Assert.AreEqual(HttpStatusCode.Conflict, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.LifecycleConflict, problem!.Type);
    }

    [TestMethod]
    public async Task POST_un_decommission_from_Active_returns_409_lifecycle_conflict()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var registered = await RegisterAsync(client, "UnDecommission App 3", "Desc.");

        // Freshly-registered app is Active — wrong source state.
        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/un-decommission",
            new { sunsetDate = DateTimeOffset.UtcNow.AddDays(30) });

        Assert.AreEqual(HttpStatusCode.Conflict, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.LifecycleConflict, problem!.Type);
    }

    [TestMethod]
    public async Task POST_un_decommission_with_past_sunsetDate_returns_400_validation_failed()
    {
        var client = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var registered = await RegisterAsync(client, "UnDecommission App 4", "Desc.");

        // Drive to Decommissioned state first.
        var sunset = DateTimeOffset.UtcNow.AddSeconds(1);
        var deprecateResp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/deprecate",
            new DeprecateApplicationRequest(sunset));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode);

        await Task.Delay(2000);

        var decommissionResp = await client.PostAsync(
            $"/api/v1/catalog/applications/{registered.Id}/decommission",
            content: null);
        Assert.IsTrue(decommissionResp.IsSuccessStatusCode);

        // Send a past sunsetDate — the domain's ArgumentException maps to 400.
        var pastDate = DateTimeOffset.UtcNow.AddDays(-1);
        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/un-decommission",
            new { sunsetDate = pastDate });

        Assert.AreEqual(HttpStatusCode.BadRequest, resp.StatusCode);
        var problem = await resp.Content.ReadFromJsonAsync<ProblemPayload>();
        Assert.AreEqual(ProblemTypes.ValidationFailed, problem!.Type);
        Assert.IsTrue(problem.Errors.ContainsKey("newSunsetDate"));
    }

    [TestMethod]
    public async Task POST_un_decommission_as_Member_returns_403()
    {
        var orgAdminClient = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var registered = await RegisterAsync(orgAdminClient, "UnDecommission App 5", "Desc.");

        // Drive to Decommissioned.
        var sunset = DateTimeOffset.UtcNow.AddSeconds(1);
        await orgAdminClient.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/deprecate",
            new DeprecateApplicationRequest(sunset));
        await Task.Delay(2000);
        await orgAdminClient.PostAsync(
            $"/api/v1/catalog/applications/{registered.Id}/decommission",
            content: null);

        var memberClient = await Fx.CreateAuthenticatedClientAsync(MemberEmail, new[] { KartovaRoles.Member });
        var resp = await memberClient.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{registered.Id}/un-decommission",
            new { sunsetDate = DateTimeOffset.UtcNow.AddDays(30) });

        Assert.AreEqual(HttpStatusCode.Forbidden, resp.StatusCode);
    }

    [TestMethod]
    public async Task POST_un_decommission_unauthenticated_returns_401()
    {
        var client = Fx.CreateAnonymousClient();
        var resp = await client.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{Guid.NewGuid()}/un-decommission",
            new { sunsetDate = DateTimeOffset.UtcNow.AddDays(30) });

        Assert.AreEqual(HttpStatusCode.Unauthorized, resp.StatusCode);
    }

    [TestMethod]
    public async Task POST_un_decommission_for_other_tenants_id_returns_404()
    {
        // Register, deprecate, and decommission as OrgB so the app is in an un-decommissionable state.
        var orgBClient = await Fx.CreateAuthenticatedClientAsync("admin@orgb.kartova.local", new[] { KartovaRoles.OrgAdmin });
        var otherTenantApp = await RegisterAsync(orgBClient, "Cross Tenant UnDecommission", "Desc.",
            email: "admin@orgb.kartova.local");

        var sunset = DateTimeOffset.UtcNow.AddSeconds(1);
        var deprecateResp = await orgBClient.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{otherTenantApp.Id}/deprecate",
            new DeprecateApplicationRequest(sunset));
        Assert.IsTrue(deprecateResp.IsSuccessStatusCode, $"OrgB deprecate must succeed (was {deprecateResp.StatusCode}).");

        await Task.Delay(2000);

        var decommissionResp = await orgBClient.PostAsync(
            $"/api/v1/catalog/applications/{otherTenantApp.Id}/decommission",
            content: null);
        Assert.IsTrue(decommissionResp.IsSuccessStatusCode, $"OrgB decommission must succeed (was {decommissionResp.StatusCode}).");

        // Attempt to un-decommission OrgB's app as OrgA — RLS filters the cross-tenant row → 404.
        var orgAClient = await Fx.CreateAuthenticatedClientAsync(OrgAdminEmail, new[] { KartovaRoles.OrgAdmin });
        var resp = await orgAClient.PostAsJsonAsync(
            $"/api/v1/catalog/applications/{otherTenantApp.Id}/un-decommission",
            new { sunsetDate = DateTimeOffset.UtcNow.AddDays(30) });

        Assert.AreEqual(HttpStatusCode.NotFound, resp.StatusCode);
    }

    // ADR-0103: register requires a valid owning team in the registering tenant.
    // Seed the team in that tenant (default OrgA; the cross-tenant test registers as
    // OrgB and passes its email). BYPASSRLS, idempotent.
    private async Task<ApplicationResponse> RegisterAsync(
        HttpClient client, string displayName, string description,
        string email = "admin@orga.kartova.local")
    {
        var teamId = await Fx.SeedTeamInOrganizationAsync(
            Fx.TenantIdForEmail(email), "Lifecycle Team");
        var resp = await client.PostAsJsonAsync(
            "/api/v1/catalog/applications",
            new RegisterApplicationRequest(displayName, description, teamId));
        Assert.IsTrue(resp.IsSuccessStatusCode);
        return (await resp.Content.ReadFromJsonAsync<ApplicationResponse>(KartovaApiFixtureBase.WireJson))!;
    }

    // Mirrors ProblemPayload from DeprecateApplicationTests / DecommissionApplicationTests.
    // Includes the Errors dictionary for the 400 ValidationFailed assertion and the
    // Type/CurrentLifecycle fields for the 409 LifecycleConflict assertions.
    private sealed class ProblemPayload
    {
        public string Type { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public int Status { get; set; }
        public string? Detail { get; set; }

        public Dictionary<string, string[]> Errors { get; set; } = new();

        public string? CurrentLifecycle { get; set; }
        public string? AttemptedTransition { get; set; }
        public string? Reason { get; set; }
        public DateTimeOffset? SunsetDate { get; set; }
    }
}

using Kartova.Organization.Application;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Kartova.Organization.Tests;

/// <summary>
/// Shape tests for the result records produced by Organization command handlers.
/// Mutation testing flips the boolean literals (false ↔ true) inside the handler
/// branches' <c>new(...)</c> constructions, and removes the positional-constructor
/// assignments on the record itself. Asserting every field for every terminal
/// branch — one test per branch — gives each literal flip a guaranteed failing
/// observer.
/// </summary>
[TestClass]
public sealed class HandlerResultTests
{
    // ---------------------------------------------------------------------
    // DeleteTeamResult
    // ---------------------------------------------------------------------

    [TestMethod]
    public void DeleteTeamResult_NotFound_shape()
    {
        var r = new DeleteTeamResult(Deleted: false, NotFound: true, ApplicationsAssigned: null);

        Assert.IsFalse(r.Deleted);
        Assert.IsTrue(r.NotFound);
        Assert.IsNull(r.ApplicationsAssigned);
    }

    [TestMethod]
    public void DeleteTeamResult_HasApplicationsAssigned_shape()
    {
        var r = new DeleteTeamResult(Deleted: false, NotFound: false, ApplicationsAssigned: 3);

        Assert.IsFalse(r.Deleted);
        Assert.IsFalse(r.NotFound);
        Assert.AreEqual(3, r.ApplicationsAssigned);
    }

    [TestMethod]
    public void DeleteTeamResult_Success_shape()
    {
        var r = new DeleteTeamResult(Deleted: true, NotFound: false, ApplicationsAssigned: null);

        Assert.IsTrue(r.Deleted);
        Assert.IsFalse(r.NotFound);
        Assert.IsNull(r.ApplicationsAssigned);
    }

    // ---------------------------------------------------------------------
    // AddTeamMemberResult
    // ---------------------------------------------------------------------

    [TestMethod]
    public void AddTeamMemberResult_TeamNotFound_shape()
    {
        var r = new AddTeamMemberResult(Added: false, TeamNotFound: true, AlreadyMember: false, AddedAt: null);

        Assert.IsFalse(r.Added);
        Assert.IsTrue(r.TeamNotFound);
        Assert.IsFalse(r.AlreadyMember);
        Assert.IsNull(r.AddedAt);
    }

    [TestMethod]
    public void AddTeamMemberResult_AlreadyMember_shape()
    {
        var r = new AddTeamMemberResult(Added: false, TeamNotFound: false, AlreadyMember: true, AddedAt: null);

        Assert.IsFalse(r.Added);
        Assert.IsFalse(r.TeamNotFound);
        Assert.IsTrue(r.AlreadyMember);
        Assert.IsNull(r.AddedAt);
    }

    [TestMethod]
    public void AddTeamMemberResult_Success_shape()
    {
        var when = new DateTimeOffset(2026, 5, 26, 12, 0, 0, TimeSpan.Zero);

        var r = new AddTeamMemberResult(Added: true, TeamNotFound: false, AlreadyMember: false, AddedAt: when);

        Assert.IsTrue(r.Added);
        Assert.IsFalse(r.TeamNotFound);
        Assert.IsFalse(r.AlreadyMember);
        Assert.AreEqual(when, r.AddedAt);
    }

    // RemoveTeamMemberResult / UpdateTeamMemberResult shape tests removed: those results
    // are now enums (RemoveTeamMemberOutcome / UpdateTeamMemberOutcome) per ADR-0104, so
    // there is no boolean-flag construction left to assert. Branch behavior is covered by
    // the integration tests (RemoveTeamMemberTests / UpdateTeamMemberTests → HTTP status).
}

using Kartova.Organization.Domain;
