    [TestMethod]
    public void Revoke_throws_when_already_terminal()
    {
        var clock = new FakeTimeProvider();
        var inv = Invitation.Create("a@b.c", KartovaRoles.Member, InvitedBy, KcUser, Tenant, clock, tokenHash: "HASH");
        inv.MarkAccepted(clock);
        Assert.ThrowsExactly<InvalidOperationException>(() => inv.Revoke(clock));
    }

    [TestMethod]
    public void MarkExpired_flips_status()
    {
        var clock = new FakeTimeProvider();
        var inv = Invitation.Create("a@b.c", KartovaRoles.Member, InvitedBy, KcUser, Tenant, clock, tokenHash: "HASH");
        inv.MarkExpired(clock);
        Assert.AreEqual(InvitationStatus.Expired, inv.Status);
    }

    [TestMethod]
    public void MarkExpired_throws_when_not_pending()
    {
        var clock = new FakeTimeProvider();
        var inv = Invitation.Create("a@b.c", KartovaRoles.Member, InvitedBy, KcUser, Tenant, clock, tokenHash: "HASH");
        inv.Revoke(clock);
        Assert.ThrowsExactly<InvalidOperationException>(() => inv.MarkExpired(clock));
    }

    [TestMethod]
    public void Create_stores_token_hash_and_leaves_credential_unset()
    {
        var clock = new FakeTimeProvider();
        var inv = Invitation.Create("a@b.com", KartovaRoles.Member, Guid.NewGuid(),
            Guid.NewGuid(), new TenantId(Guid.NewGuid()), clock, tokenHash: "HASH");
        Assert.AreEqual("HASH", inv.TokenHash);
        Assert.IsNull(inv.CredentialSetAt);
    }

    [TestMethod]
    public void MarkCredentialSet_burns_token_and_stamps_time()
    {
        var clock = new FakeTimeProvider(DateTimeOffset.Parse("2026-05-27T10:00:00Z"));
        var inv = Invitation.Create("a@b.com", KartovaRoles.Member, Guid.NewGuid(),
            Guid.NewGuid(), new TenantId(Guid.NewGuid()), clock, tokenHash: "HASH");
        clock.Advance(TimeSpan.FromMinutes(10));
        inv.MarkCredentialSet(clock);
        Assert.IsNull(inv.TokenHash);
        Assert.IsNotNull(inv.CredentialSetAt);
        Assert.AreEqual(InvitationStatus.Pending, inv.Status);
    }

    [TestMethod]
    public void MarkCredentialSet_throws_when_not_pending()
    {
        // Arrange: move invitation to a non-Pending state.
        var clock = new FakeTimeProvider(DateTimeOffset.Parse("2026-05-27T10:00:00Z"));
        var inv = Invitation.Create("a@b.com", KartovaRoles.Member, Guid.NewGuid(),
            Guid.NewGuid(), new TenantId(Guid.NewGuid()), clock, tokenHash: "HASH");
        inv.MarkAccepted(clock);

        // Act + Assert: guard must fire.
        Assert.ThrowsExactly<InvalidOperationException>(() => inv.MarkCredentialSet(clock));
    }

    [TestMethod]
    public void MarkCredentialSet_throws_on_second_call_even_when_still_pending()
    {
        // Arrange: Pending invitation with first call succeeding.
        var clock = new FakeTimeProvider(DateTimeOffset.Parse("2026-05-27T10:00:00Z"));
        var inv = Invitation.Create("a@b.com", KartovaRoles.Member, Guid.NewGuid(),
            Guid.NewGuid(), new TenantId(Guid.NewGuid()), clock, tokenHash: "HASH");

        // First call must succeed.
        inv.MarkCredentialSet(clock);
        Assert.IsNotNull(inv.CredentialSetAt);

        // Second call must throw — credential already set.
        Assert.ThrowsExactly<InvalidOperationException>(() => inv.MarkCredentialSet(clock));
    }
}

using Kartova.Organization.Domain;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Kartova.Organization.Tests;

[TestClass]
public sealed class InvitationTokenTests
{
    [TestMethod]
    public void Hash_is_deterministic_for_same_input()
    {
        Assert.AreEqual(InvitationToken.Hash("abc"), InvitationToken.Hash("abc"));
    }

    [TestMethod]
    public void Hash_differs_for_different_input()
    {
        Assert.AreNotEqual(InvitationToken.Hash("abc"), InvitationToken.Hash("abd"));
    }

    [TestMethod]
    public void Hash_is_base64url_of_sha256_43_chars()
    {
        // SHA-256 = 32 bytes -> base64url without padding = 43 chars.
        Assert.AreEqual(43, InvitationToken.Hash("anything").Length);
        Assert.IsFalse(InvitationToken.Hash("anything").Contains('+'));
        Assert.IsFalse(InvitationToken.Hash("anything").Contains('/'));
        Assert.IsFalse(InvitationToken.Hash("anything").Contains('='));
    }

    [TestMethod]
    public void Issue_returns_distinct_high_entropy_plaintext_and_matching_hash()
    {
        var (p1, h1) = InvitationToken.Issue();
        var (p2, _) = InvitationToken.Issue();
        Assert.AreNotEqual(p1, p2);
        Assert.AreEqual(43, p1.Length);
        Assert.AreEqual(InvitationToken.Hash(p1), h1);
    }
}

using System.Text;
using Kartova.Organization.Application;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Kartova.Organization.Tests;

/// <summary>
/// Tests for <see cref="LogoValidation"/> magic-byte detection and SVG sanitization.
/// Magic-byte tests include exact-boundary length cases so mutation operators that
/// flip <c>&gt;=</c> to <c>&gt;</c> (or vice-versa) on the length guards have a
/// failing observer. The unsupported-mime-type test kills the <c>_ =&gt; false</c>
/// arm-removal mutator on the switch expression.
/// </summary>
[TestClass]
public sealed class LogoValidationTests
{
    [TestMethod]
    public void MagicBytesMatch_png_with_correct_header_returns_true()
    {
        var bytes = new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A, 0x00 };
        Assert.IsTrue(LogoValidation.MagicBytesMatch(bytes, "image/png"));
    }

    [TestMethod]
    public void MagicBytesMatch_png_with_wrong_header_returns_false()
    {
        var bytes = new byte[] { 0xFF, 0xD8, 0xFF, 0x00 };
        Assert.IsFalse(LogoValidation.MagicBytesMatch(bytes, "image/png"));
    }

    [TestMethod]
    public void MagicBytesMatch_png_with_exactly_8_bytes_returns_true()
    {
        var bytes = new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A };
        Assert.IsTrue(LogoValidation.MagicBytesMatch(bytes, "image/png"));
    }

    [TestMethod]
    public void MagicBytesMatch_png_with_7_bytes_returns_false()
    {
        var bytes = new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A };
        Assert.IsFalse(LogoValidation.MagicBytesMatch(bytes, "image/png"));
    }

    [TestMethod]
    public void MagicBytesMatch_jpeg_with_correct_header_returns_true()
    {
        var bytes = new byte[] { 0xFF, 0xD8, 0xFF, 0xE0 };
        Assert.IsTrue(LogoValidation.MagicBytesMatch(bytes, "image/jpeg"));
    }

    [TestMethod]
    public void MagicBytesMatch_svg_with_xml_prelude_returns_true()
    {
        var bytes = Encoding.UTF8.GetBytes("<?xml version=\"1.0\"?><svg></svg>");
        Assert.IsTrue(LogoValidation.MagicBytesMatch(bytes, "image/svg+xml"));
    }

    [TestMethod]
    public void MagicBytesMatch_svg_with_root_element_returns_true()
    {
        var bytes = Encoding.UTF8.GetBytes("  <svg xmlns=\"...\"/>");
        Assert.IsTrue(LogoValidation.MagicBytesMatch(bytes, "image/svg+xml"));
    }

    [TestMethod]
    public void MagicBytesMatch_returns_false_for_unsupported_mime_type()
    {
        // Valid PNG header bytes, but the mime type is unsupported — the
        // switch expression's `_ => false` arm must return false.
        var bytes = new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A };
        Assert.IsFalse(LogoValidation.MagicBytesMatch(bytes, "image/gif"));
    }

    [TestMethod]
    public void SanitizeSvg_strips_script_element()
    {
        var input = "<svg><script>alert(1)</script><circle r=\"5\"/></svg>";
        var (sanitized, materiallyChanged) = LogoValidation.SanitizeSvg(input);
        Assert.IsFalse(sanitized.Contains("<script", StringComparison.OrdinalIgnoreCase),
            "Sanitized output should not contain a <script tag opener.");
        Assert.IsTrue(materiallyChanged);
    }

    [TestMethod]
    public void SanitizeSvg_passes_clean_svg_unchanged()
    {
        var input = "<svg xmlns=\"http://www.w3.org/2000/svg\"><circle r=\"5\" fill=\"red\"/></svg>";
        var (sanitized, materiallyChanged) = LogoValidation.SanitizeSvg(input);
        Assert.IsFalse(materiallyChanged);
        Assert.IsTrue(sanitized.Contains("circle"));
    }
}

